INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Abacateiro', E'', '', E'PERSEA CIRATISSIRNA GAERTN., AGUACATE E AGNATA.DIURÉTICO, CARMINATIVO, ESTOMÁQUICO, COLAGOGO, COLERÉTICO E EMENAGOGO. EXTERNAMENTE ÉAbacateiro', '', E'Nome científico: Persea ciratissirna Gaertn. Família: Lauraceae.  Origem: América Central.  Sinonímia: aguacate e agnata.  Descrição: árvore que atinge até 20 m de altura, com casca pardacenta; folhas coriáceas, alternas e simples; inflorescéncias em panículas; fruto tipo baga piriforme, de polpa gordurosa.  Constituintes químicos principais: tanino, metil-eugenol, abacatina, dopamina, quercitina e perseitol. Abscisina nas sementes.  Indicações: diurético, carminativo, estomáquico, colagogo, col', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Abóbora', E'', '', E'CEICURBITA SP.VERMÍFUGOABÓBORA', '', E'(Ceicurbita SP.) Planta anual, rasteira, da família Cucurbitaceae. Contém açúcares, pigmentos e cucurbitacinas.  As sementes expulsam lombriga e solitária. Assementes devem ser secas ao sol, descascadas e ligeiramentetorradas em urna panela. Para expulsar a solitária, utilizar 50 sementes e, para lombrigas, 25. Amassá-las num pilão, juntamente cora 1 colher (sopa) de açúcar, e um pouco de leite, para que forme urna pasta. Tornar pela manhã antes do sol nascer, em jejum. Após 2 horas, ingerir 2 c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Abrotanum', E'', '', E'ARTEMISIA ABROTANUMDIURÉTICA.ASCITE.TUBERCULOSSE DO PERITÔNIO E DO MESENTÉRIO;DISPNÉIA, ASMA,FRIEIRAS.Artemisia abrotanum', '', E'O Abrotanum, que é a mais aromática das espécies de Artemisia, é originária da Europa meridional e da Ásia maior, mas podemos encontrá-la na Europa central em solos quentes, nutritivos, fofos e arenosos. Os lobos das folhas muito recortadas formam um feixe filamentoso. Desse bouquet plumoso emana um odor forte, refrescante, salino, aromático, com um gosto de fundo semelhante ao do limão, muito ácido. Ele produz suas panículas muito frouxas de inflorescências, com minúsculos capítulos compactos,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Abutua', E'', '', E'CISSAMPELOS PAREIRA L., PARREIRA BRAVAMIORRELAXANTE, AFECÇÕES DIGESTIVAS, COMO DIURÉTICA E FEBRÍFUGAAbutua', '', E'(Cissampelos pareira L.) Espécie nativa, trepadeira, da família Menispermaceae. Contém um alcalóide, cissampelina com atividade miorrelaxante. A planta toda é utilizada nos preparados fitoterápicos, sendo a infusão indicada para uso interno, e a decocção, para uso externo. As folhas são utilizadas contra afecções digestivas, como diurética e febrífuga. As raízes são tõnicas e afrodisíacas. Também é conhecida como parreirabrava. Multiplica-se através de sementes. û7', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Açafrão', E'', '', E'CROCUS SATIVUS L.LOÇÕES OCULARES E COLÍRIOS,ABORTIVOAÇAFRÃO', '', E'CROCUS SATIVUS L. LOÇÕES OCULARES E COLÍRIOS,ABORTIVO Crocus sativus L. Iridaceae Planta herbácea perene dotada de um bulbo escamoso subterrâneo e de folhas lineares consolidadas por uma nervura de cor clara. A haste floral curta e terminada por uma flor afunilada violeta-clara dividida em seis lóbulos. O estilete amarelo divide-se em três, sendo cada uma das partes terminada por um estigma alaranjado. Estes estigmas erguem-se acima da flor. O açafrão multiplica-se através de bulbos-filhos que a', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Açafrão Do Prado', E'', '', E'COLCHICUM AUTUMNALE L.ALIVIA DOR E REDUZ INFLAMAÇÃO.GOTA.AÇAFRÃO DO PRADO', '', E'COLCHICUM AUTUMNALE L. ALIVIA DOR E REDUZ INFLAMAÇÃO.GOTA. Colchicum autumnale L. Liliaceae (Colchicaceae) O género Colchicum, distribuído ao longo da Europa, África do norte, Ásia ocidental e China ocidental, é constituído de cerca de 45 espécies perenais bulhares. Apesar de sua toxidade. colchicuns são populares plantas de jardins devido sua grande inflorescência colorida que aparece desde o início do verão até o início do outono. Eles crescem nas margens de caminhos, debaixo de árvores e em p', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Acariçoba', E'', '', E'HYDROCOTYLLE UMBELLATA L.DIURÉTICA, ANTI-REURNÃTICA, EMÉTICA, PURGATIVA, DESOBSTRUENTE DO FÍGADO E DOS RINS. EM USO EXTERNO FAZ DESAPARECER SARDAS E OUTRAS MANCHAS DA PELE, CALMANTE E TÔNICO CEREBRAL Acariçoba', '', E'Nome científico: Hydrocotylle umbellata L. Planta herbácea, perene, nativa do Brasil, da família Umbelliferae. As raízes apresentara ação diurética, anti-reurnãtica, emética, purgativa, desobstruente do fígado e dos rins. Em uso externo (suco), faz desaparecer sardas e outras manchas da pele. As folhas são empregadas como calmante e tônico cerebral (bater 5 folhas em 1 xícara de leite, tornar à noite). Não deve ser utilizada por gestantes. Multiplica-se por sementes e divisão de rizomas, desenvo', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aconito', E'', '', E'ACONITUM NAPELUS L.ANALGÉSICAS (REUMATISMOS, GOTA, CIÁTICA, DORES DE DENTES).DORES E AS AFECÇÕES DEVIDAS A RESFRIAMENTOS.Aconitum napelus L. Ranunculaceae', '', E'Planta perene com raizes tuberosas, caule ereto e folhas alternas paimatipartidas. Na parte superior do caule forma-se um cacho floral ramificado, composto de flores azuis com a forma característica de elmo. O fruto é uma vesícula. A espécie européia, espalhada em toda a zona temperada até a Suécia, cresce espontaneamente nos bosques sombrios e nas florestas frondosas. É uma planta protegida em numerosos países. É cultivada em grande escala para fins farmacêuticos. São colhidos os tubérculos, ma', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Adonis', E'', '', E'ADONIS VERNALISHIDROPSIA.CORAÇÃO ESTÁ MUITO DILATADO E GORDUROSO.Adonis', '', E'Adonis vernalis Ranunculaceae Assim como o útero, que pode ser entendido como um coração metamorfoseado na região inferior, a Pulsatilla pode ser vista como um Adonis do pólo metabolico - reprodutor e o Adonis como a Pulsatilla do sistema rítimico.  Esta planta também pertence ã Primavera, procurando por um lado o equilibrio entre o sólido e o liquido, e por outro lado entre o aéreo e o calórico. Ela cresce de preferência nos solos secos das colinas calcáreis que se aquecem com facilidade. Seu r', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Agrião', E'', '', E'NASTURTIUM OFFICINALE R. BR.DIURÉTICA, TÕNICA, DEPURATIVA, ANTIINFLAMATÕRIA, EXPECTORANTE E ANTÍDOTO CONTRA A NICOTINA. AS FOLHAS SÃO UTILIZADAS EM SALADAS, SUCOS EAgrião', '', E'Nome científico: Nasturtium officinale R. Br. Planta herbácea anual, da família Cruciferae, que se desenvolve bera em locais úmidos. Originária do Chile. Tem ação diurética, tõnica, depurativa, antiinflamatõria, expectorante e antídoto contra a nicotina. As folhas são utilizadas em saladas, sucos e maceração a frio, além do uso em xaropes. Xarope de agrião e mel: 1 xícara de agrião picado, 1 xícara (chá) de água fervente, deixar por 10 minutos abafado, coar, adicionar 1 xícara (chá) de açúcar, l', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Agrimônia', E'', '', E'AGRIMÔNIA EUPATORIA L.CATARROS, HEMORRAGIAS, AFECÇÕES DA PELE E A TUBERCULOSE.ADSTRINGENTE,CATARROS GÁSTRICOS OU INTESTINAIS E DIARRÉIAS DIVERSAS.CÁLCULOS RENAIS.ERUPÇÕES DÉRMICASAgrimônia', '', E'Agrimônia eupatoria L. Rosaceae  A agrimônia é uma planta herbácea vivaz dotada de um curto rizoma subterrâneo, possuindo uma roseta terrestre de folhas penáceas e um caule direito com folhas alternas e sésseis. 0 caule termina numa inflorescência de flores amarelas em espiga pouco densa. 0 fruto é um aquênio (desenho) envolvido por uma silícula munida de excrescências em forma de gancho. A agrimónia é vulgar num vasto território europeu, onde cresce sobretudo nos prados secos, nas pastagens e n', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Água Da Rainha', E'', '', E'OCIMUM SP.CONTRA A GRIPEÁgua-da-rainha', '', E'Nome científico: Ocimum Sp. Espécie herbácea, perene, da família Labiatae, semelhante às alfavacas. As folhas e flores são utilizadas, na forma de infusão, contra a gripe. O gênero Ocimum destaca-se dentre as plantas cultivadas; no entanto, a ocorrência de polinizações cruzadas entre espécies ou variedades, provocadas principalmente pela ação das abelhas dificulta a identificação das espécies, já que as descendências apresentam formas diferentes ou linhagens instáveis. Deve-se cultivar apenas um', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Água De Colônia', E'', '', E'AEOLANTHUS SUAVEOLENS G. DON.ANTICONVULSIVANTE (SUMO DAS FOLHAS). AS FOLHAS, NA FORMA DE INFUSÃO, SÃO UTILIZADAS COMO CALMANTE E PARA DORES NOÁgua-de-colônia', '', E'Nome científico: Aeolanthus suaveolens G. Don. Herbácea anual, da família Labiatae, originária da África. É também denominada catinga-de-mulata, embora não tenha muita semelhança com a planta do gênero Tanaceturn já descrita. Contém lactonas rio óleo essencial. Tradicionalmente, é empregada como anticonvulsivante (sumo das folhas). As folhas, na forma de infusão, são utilizadas como calmante e para dores no coração. Na cultura popular, é utilizada para fazer com que as crianças "caladas" comecem', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aipo', E'', '', E'APIUM GRAVEOLENS L., SALSÃO, AIPO-CULTIVADO, AIPO D''ÁGUA, AIPO-DOCE E CELERIDIURÉTICO, COMBATE A GOTA E PEDRAS, NA VESÍCULA BILIAR DEPURATIVO, ESTOMAQUICO, EXPECTORANTE, FEBRÍFUGO, ANTÜNFLARNATÓRIO Nome científico: Apium graveolens L. Família: Umbelliferae. Origem: Europa', '', E'Sinonímia: salsão, aipo-cultivado, aipo d''água, aipo-doce e celeri.  Descrição: planta herbácea, bianual, de pequeno porte; talo ramificado, fistuloso e acanalado; folhas oblongas a ovadas, pinadas, com três a sete folíolos primários, ovais e subcordados; inflorescência em umbela; fruto esquizocarpo.  Constituintes químicos principais: contém óleo essencial rico em apiósido, limoneno, selineno, eudesmol, sedanólido, anidrido sedanõnico, apresentando ainda açúcares,manitol, pentosanas, ácidos gli', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alcachofra', E'', '', E'CVNARA SCOLYMUS L., CACHOFRA E ALCACHOFRA HORTENSEDISTÚRBIOS DIGESTIVOS, E HEPÁTICO, COLAGOGO, COLERÉTICO  DIURÉTICO E ELIMINADOR DO ÁCIDO ÚRICO; AUXILIA NO TRATAMENTO DE OBESIDADE; AUMENTA A AÇÃO ANTITÓXICA DO ORGANISMO; PARA HIPERCOLESTEROMIA E HIPERTRIGLICERIDOMIA, DEPURATIVO, E ANTIOFÍDICO.ALCACHOFRA', '', E'Nome científico: Cvnara scolymus L. Família: Compositae. Origem: Norte da África (Mediterrâneo).  Sinonímia: cachofra e alcachofra hortense.  Descrição: planta herbácea, perene; folhas inferiores em roseta, segmentadas; caule roliço; receptáculo floral desenvolvido e carnoso; flores azuis ou violáceas, tubulares; sabor amargo.  Constituintes químicos principais: cinarina, inulina, flavonóides, esteróides e sesquiterpenos, cinarisídio, cinaropicrina e ácido caféico.  Indicações: distúrbios digest', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alcaçuz', E'', '', E'GLYCYRRHIZA GLABRA L.EXPECTORANTE, LIGEIRAMENTE LAXANTE E ESPASMOLÍTICO.ÚLCERAS GASTRODUODENAIS.Alcaçuz', '', E'Glycyrrhiza glabra L. Leguminosas (Fabaceae) Planta herbácea perene com nzoma lenhoso e rastejante. apresentando um caule ereto, ramificado, com folhas alternas imparifolioladas. As flores azul-violeta formam espigas sustentadas por pedúnculos que nascem na axila das folhas. Os frutos são vagens. A espécie, originária da Europa meridional e do Oriente, é cultivada nos campos e naturaliza-se facilmente. A indústria farmacêutica e alimentar utiliza a raiz e os rebentos subterrâneos da planta. São', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alecrim', E'', '', E'ROSMARINUS OFFICINALIS L., ALECRIM-DE-JARDIM, ALECRIM ROSMARINO, LIBANOTIS E ROSMARINO.ESTIMULANTE DIGESTIVO E PARA FALTA DE APETITE (INAPETÊNCIA); AZIA, PROBLEMAS RESPIRÁTÓRIOS, DEBILIDADE CARDÍACA (CARDIOTÔNICO), FRAGI1IDADE DOS VASÓS CÁPILARES, CANSAÇO FISICO E MENTAL, HEMORRÓIDAS, ANTIESPASMÓDICO E CICATRIZANTE.ALECRIM', '', E'Nome científico: Rosmarinus officinalis L. Família: Labiatae. Origem: Sul da Europa e Norte da África.  Sinonímia: alecrim-de-jardim, alecrim rosmarino, libanotis e rosmarino.  Descrição: subarbusto ramificado com até 2 m de altura; folhas sésseís, opostas e lineares, de sabor picante; flores diminutas, azuladas ou brancas, bilabiadas em cimeiras. Toda a planta exala forte aroma.  Constituintes químicos principais: o óleo essencial contém pineno, canfeno, borneol, cineol; apresenta ainda taninos', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alecrim Do Campo', E'', '', E'BACCHARIS DRACUNCULIFOLIA D.C. CATARRO PULMONAR. OS BANHOS SÃO ECOMENDADOS NO TRATAMENTO DE REUMATISMO E COMO ESTIMULANTES. NA FORMA DE COMPRESSA (QUENTE) VITALIZA O SISTEMA DIGESTIVO NA ÁREA INTESTINALAlecrim-do-campo', '', E'Nome científico: Baccharis dracunculifolia D.C.  Trata-se de urna arbusto nativo, da família Cornpositae, que cresce, normalmente, em terras cansadas ou degradadas. O nome alecrim-do-campo é comum a diversas , plantas das famílias Compositae,Labiatae e Verbenaceae. A infusão de folhas e flores é indicada para combater catarro pulmonar. Os banhos são ecomendados no tratamento de reumatismo e como estimulantes. Na forma de compressa (quente) vitaliza o sistema digestivo na área intestinal, 1 vez a', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alecrim Pimenta', E'', '', E'LIPPIA SIDOIDES CHAM., ALECRIM-DO-NORDESTE E ESTREPA-CAVALO.PARA IMPIGENS, ACNE, PANO BRANCO, AFTAS, ESCABIOSE, CASPA, MAUS ODORES NOS PÉS E AXILAS, SARNA INFECCIOSA E PÉ DE ATLETA. EMPREGADO, AINDA PARA INFLAMAÇÕES NA BOCA E GARGANTA. É ANTIESPASMÓDICO E ESTOMÁQUICO. SEUS CONSTITUINTES QUÍMICOS LHE CONFEREM FORTEALECRIM PIMENTA', '', E'Nome científico: Lippia sidoides Cham. Família: Verbenaceae. Origem: Nordeste do Brasil. Sinonímia: alecrim-do-nordeste e estrepa-cavalo.  Descrição: arbusto silvestre, com até 3 m de altura; folhas simples, compostas, com margens crenadas, pêlos esbranquiçados na face inferior, aromáticas e de sabor picante, daí a denominação alecrim pimenta; flores brancas, em racimos; cálice curto e membranáceo; caule quebradiço.  Constituintes químicos principais: óleo essencial contendo, principalmente, tim', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alface', E'', '', E'LACTUCA SATIVA L.LAXANTES, DIURÉTICO E ANTIÁCIDAS, SONÍFEROS, CALMANTES DO ESTÕMAGO, DO SISTEMA NERVOSO, BÉQUICO E PARA ICTERÍCIA CONTUSÕES, INCHAÇOS E IRRITAÇÕES NA PELE. ALFACE', '', E'Nome científico: Lactuca sativa L. Espécie da família Cornpositae, originária da Ásia e cultivada desde a antigüidade. Contém um princípio amargo denominado lactucina. As folhas são usadas em saladas. Apresentam propriedades laxantes, diurético e antiácidas. o sumo e o chã das folhas, dos talos, e das raízes são soníferos, calmantes do estõmago, do sistema nervoso, béquico e para icterícia. Para contusões, inchaços e irritações na pele, suas folhas, fervidas por 5 minutos e depois untadas com az', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alface Selvagem', E'', '', E'LACTUCA VIROSA L.NARCÓTICO.ATAQUES DE TOSSE E A TOSSE CONVULSIVA.ALFACE SELVAGEM', '', E'Lactuca virosa L. Asteraceae (Compositae) Planta anual a bienal, possuindo um caule ereto, ramificado ma parte superior, apresentando folhas sesseis. As folhas da roseta são pecioladas, ovaladas, dentadas. O caule, com os seus capitules de flores amarelas, forma uma panicula ramificada. O fruto è um aquênio com coroa. toda a planta é percorrida por uma rede de laticiferos que contém um látex branco, que endurece, tornase colante e muda de cor em contacto cone o ar. Originária da Europa meridiona', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alfavacão', E'', '', E'OCINUM GRATISSIMUM L.CONTRA FRIEIRAS, PROBLEMAS RESPIRATÓRIOS, TÔNICA, ANTI-SÉPTICA E CARMINATIVA  Alfavacão', '', E'Nome científico: Ocinum gratissimum L.  Arbusto perene, da família Labiatae, seu cheiro lembra o do cravo-da-índia. o sumo das folhas é útil contra frieiras. As folhas em xarope ou infusão são muito indicadas para problemas respiratórios. Apresenta ainda as seguintes propriedades: tônica, anti-séptica e carminativa. Contém substãncias muito voláteis como o eugenol, que se podem perder com a fervura. Multiplica-se por sementes e estacas. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alfazema', E'', '', E'LAVANDULA SP., LAVANDAANÚRIA, AMENGRRÉIA, PEITORAL (BRÔNGUITE E GRIPE), CARMINATIVO, ANTIESPASMÓDICO, ANTI_SÉPTICO, ESTIMULANTE, CICATRIZANTE E DIGESTIVO,. TAMBÉM PARA DORES DE CABEÇA EAlfazema', '', E'Nome científico: Lavandula sp. Família: Labiatae.  Origem: Europa (regiões montanhosas dos países mediterrâneos).  Sinonímia: lavanda.  Descrição: erva com caule estirado (comprido e esgalhado); folhas sésseis, em forma de espada (ensiformes); inflorescência em espiga interrompida, de coloração azulada.  Constituintes químicos principais: óleo essencial contendo geraniol, furfurol, linalol, cariofileno, acetato de linalino e cumarinas.  Indicações: anúria, amengrréia, peitoral (brônguite e gripe', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alho', E'', '', E'ALLIUM SATIVUM L., ALHO-MANSO E ALHO-COMUMHIPERTENSAO ,PICADA DE INSETOS, DIURÉTICO, EXPECTORANTE,Nome científico: Allium sativum L. Família: Liliaceae', '', E'àigem: Ásia Central. Sinonímia: alho-manso e alho-comum. Descrição: planta herbácea anual, com 0,50 a 0,70 m de altura; bulbo composto; folhas verdes, longas, delgadas e pontiagudas; inflorescência em umbela (flores brancas ou avermelhadas).  Constituintes químicos principais: alucina (formada a partir da aluna, pela ação da enzuna alünase), ajoeno, ácidos fosfórico e sulfúrico, vitaminas A, B e C, proteínas, sais minerais, óleos essenciais, glicosídios, galicina, resinas, enzimas e sulfuretos.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Almeirão Roxo', E'', '', E'LACTUCA SP.CALMANTE Almeirão roxo', '', E'Nome científico: Lactuca sp.  Espécie herbácea, anual, da família Compositae. As folhas apresentam nervura de cor roxa, conferindo-lhe características ornamentais. Planta comestível com atividade calmante. Utilizam-se as folhas em infusão, colocando-se 1 colher (chá) de folhas frescas picadas em 1 xícara (chá) de água. Tomar 2 a 3 xícaras por dia. Multiplica-se por sementes. Ocorre em solos preferencialmente ricos em matéria orgânica. /', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Almeirão Selvagem', E'', '', E'CICHORIUM INTYBUS L.,RADICE SELVAGEM (RS)ESTÔMAGO E O INTESTINO.BLOQUEIOS DO FÍGADO, PROBLEMAS BILIARES.ESTAGNAÇÃO DO FLUXO BILIAR, CÁLCULOS.Almeirão selvagem', '', E'Radice selvagem (RS) Cichorium intybus L. Asteraceae (Compositae), Sob ponto de vista antroposófico A forte e longa raiz se enterra no solo e porta uma vigorosa roseta foliar que lembra a do taraxacum, mas suas folhas são menos exuberantes e mais retraídas. A inflorescéncia se ramifica muito, quase que com ângulos retos, trazendo pequenas folhas séssels, atrofiadas, como que engolidas pelo caule, e os ramos separados trazem os capítulos. É um contaste marcante em relação ao Taraxacum. Embaixo, a', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Alquemila', E'', '', E'ALCHEMILLA VULGARISHEMORRAGIAS UTERINA.Alquemila', '', E'Alchemilla vulgaris Rosaceae Sob ponto de vista antroposófico Como todas as Rosáceas, esta pequena planta dos prados realiza uma bela harmonia entre as forças de dilatação e as forças de formação. As primeiras, favorecidas por um substrato úmido e as outras, pelo ar livre. É uma erva graciosa que só de olhar alegra o coração. Apesar disso, é uma variante unilateral, apesar de ser muito graciosa, do tipo Rosácea.  O principal órgão nesta planta é a folha. Nesta planta, a folha penada, típica das', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Altéia', E'', '', E'ALTHAEA OFFICINALIS L.,MALVA-DO-PÂNTANOINFLAMAÇÕES DAS VIAS RESPIRATÓRIAS SUPERIORES,ANTITÚSSICO E EXPECTORANLEAltéia', '', E'Malva-do-pântano Althaea officinalis L. Malvaceae O género Althaea consta de cerca de 12 espécies de plantas anuais e perenes, bastante semelhante ao gênero Malva, ocorrendo ao longo da Europa ocidental, Asia Central e norte da Africa. Este gênero incluia antigamente Alcea rosea chamada então Althaea rosea. O nome Althaea vem do grego altha, curar, e refere-se às propriedades curativas destas plantas. Althaea oficinalis , Altéia ou Malva-do-pãntano, é uma planta herbácea perene com raiz ramifica', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Amendoeira', E'', '', E'PRUNUS DULCIS MILL., AMYGDALUS COMMUNIS L.TOSSE, NÁUSEAS, VÔMITOS , FALTA DE AR.Amendoeira', '', E'Prunus dulcis Mill. D.AMebb. Syn.: Amygdalus communis L. Rosaceae Ávore ou arbusto com ramos avermelhados, folhas alternas, estreitas e brilhantes. As flores cor-de-rosa desabrocham no princípio da Primavera, antes do aparecimento das folhas. Os frutos são drupas alongadas e aveludadas. É uma espécie originária do Cáucaso, cultivada na Europa e no resto do mundo para a produçáo de amêndoas amargas (var. amara) ou doces (var. dulcis). 0 óleo de amêndoas entrava na composição da maior parte dos an', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Amieiro Negro', E'', '', E'RHAMNUS FRANGULA L.,FRANGULA ALNUS MILL.LAXANTE.FÍGADO, VESÍCULA ,  BAÇO. OBESIDADE.PARASITAS INTESTINAIS.Amieiro negro', '', E'Rhamnus frangula L. Syn.: Frangula alnus Mill. Rhamnaceae Arbusto com ramos finos, cmzentoescuros, com folhas alternas, ovaladas e inteiras. Na axila das folhas, aparecem diminutas flores esverdeadas que se transformam progressivamente em drupas, primeiro verdes, depois vermelhas e por fim negras. É um espécie vulgar na Europa. Ásia e África do Norte, em meios úmidos, ao longo dos riachos, junto aos tanques, perto das turfeiras, onde forma matagais. Para fins medicinais, colhe-se a casca, de pre', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Amor Perfeito', E'', '', E'VIOLA TRICOLOR L.DIURÉTICO, LAXATIVO, ANTIINFLAMATÓRIO, ANTIREUMÁTICO, PEITORAL, ANTIESPASMÓDICO, FEBRÍFUGO E DEPURATIVO, PROBLEMAS DE PELEAmor-perfeito', '', E'Nome científico: Viola tricolor L.  Espécie herbácea, anual, da família Violaceae, de origem européia. As flores possuem coloração bastante variada, amarela, violeta, rósea, etc. Apresenta em sua constituição ácido salicílico, tanino, saponinas, heterosídeos flavônicos e mucilagem. São empregadas as folhas e flores, na forma de infusão, como diurético, laxativo, antiinflamatório, antireumático, peitoral, antiespasmódico, febrífugo e depurativo. Ern compressas, têm boa ação contra problemas de pe', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aneto', E'', '', E'ANETHUM GRAVEOLENS LCARMINATIVO, APERIENTE, DIGESTIVO E COMBATE A INSÕNIA. ANTIBACTERIANA CONTRA ESCHERICHIA COLI, SHIGELLA, DYSENTERIAE ETC.Aneto', '', E'Nome científico> Anethum graveolens L  Planta herbácea, bianual, da família Umbelliferae. originária do sul da Europa e das regiões de clima temperado da África e Ásia. As partes aéreas e as sementes contém flavonóides. A infusão dos frutos secos (1-4 g para 1 litro de água fervendo) tem efeito carminativo, aperiente, digestivo e combate a insõnia. Possui cheiro forte semelhante ao funcho. As partes aéreas revelam propriedades antibacterianas contra Escherichia coli, Shigella dysenteriae etc. Se', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Angélica', E'', '', E'ANGELICA ARCHANGELICA L.,ARCHANGELICA OFFICINALIS (MOENCH)CALMANTES DO SISTEMA NERVOSO,REDUZEM O APARECIMENTO DE DORES DE CABEÇA E DE PERTURBAÇÕES NERVOSAS, ALIVIAM AS CÃIBRAS.Angélica', '', E'Angelica archangelica L. Syn. Archangelica officinalis (Moench) Hoffm. Umbelliferae (Apiaceae) Planta bienal de porte robusto, munida de tini rizoma cônico de cor escura e de poderosas raizes. No primeiro ano, aparece uma roseta de folhas terrestres, no segundo ano um enorme caule em forma de cana. muito ramificado, coberto de folhas alternas dotadas de bainha membranosa. A parte terminal do caule apresenta umbelas compostas, formadas de flores esverdeadas. O fruto é um diaquénio. Toda a planta', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Anil', E'', '', E'INDIGOFERA SUFFRUTICOSA MILL.ANTIESPASMÓCO, EMENAGOGO, SEDATIVO E ESTOMÁQUICO, CONTRA SARNA, ICTERÍCIAAnil', '', E'Nome científico: Indigofera suffruticosa Mill.  Espécie perene, da família Leguminosas, sublenhosa, bem ramificada, com flores róseas miúdas, originária das Antilhas e da América Central. A infusão das folhas (5 g de folha em 1 litro d''água, tomar 1 ou 2 xícaras (chá) ao dia) apresenta efeitos antiespasmóco, emenagogo, sedativo e estomáquico. O cataplasma das folhas é aplicado contra sarna. A decocçáo da raiz é útil na cura de icterícia. É considerada antídoto do mercúrio e do arsênico. Multípli', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Anis', E'', '', E'ANTENNARIA DIOICA (L.),ANTENÁRIA, PÉ-DE-GATOADSTRINGENTE. EMOLIENTE, COLAGOGA E ESTIMULA O FÍGADO.TRATAMENTO DAS VIAS RESPIRATÓRIAS SUPERIORES, DO CATARRO GASTRINTESTINAL E DA VESÍCULA BILIAR.Antenária, Pé-de-gato', '', E'Antennaria dioica (L.) GAERTN. Asteraceae (Compositae) Aproximadamente 45 espécies de pequenas plantas lanosas, perenes ou semi-perenes, compõem o gênero Antennaria que é distribuído ao longo de regiões temperadas e mornas, excluindo a África. O nome Antennaria deriva dos apêndices lanosos nas sementes que se assemelham a antenas de insetos. Antennaria dióica, pé-de-gato ou antenária, é uma planta herbácea perene que forma tapetes sobre o solo, espalhando-se através de rebentos radiculares. As f', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aristolóquia', E'', '', E'ARISTOLOCHIA CLEMATITIS L.,ERVA-DE-PARTO,RAIZ-DE-COBRACÂBRAS,CALMANTE SOBRE AS DORES CARDÍACAS, GÁSTRICAS, INTESTINAIS OU RESPIRATÓRIAS.DOENÇAS DO SISTEMA VASCULAR E A TROMBOSE.ULCERAS,ECZEMAS,FRIEIRAS,FERIDAS,ERUPÇÕES CUTÂNEAS.Aristo1óquia clematite', '', E'Aristolochia clematitis L. Arístolochiaceae O gênero Aristolochia consiste de cerca de 300 espécies venenosas de cipós, trepadeiras, arbustos e herbáceos perenes que ocorrem principalmente nas partes mornas e tropicais das Américas. Muitas espécies trepadeiras são cultivadas pela sua atraente folhagem e intrigante cheiro de suas flores. o nome Aristolochia é derivado do grego "cristos", melhor, e "lokhia'', parto, e se refere aos principais usos medicinais.  Aristolochia clematitis é uma planta h', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Arnica', E'', '', E'SOLIDAGO MICROGLOSSA D.C., ARNICA-BRASILEIRA, ARNICA SILVESTRE, ESPIGA DE OURO, ERVA LANCETA, MACELA MIÚDACONTUSÕES, TRAUMATISMOS E REUMATISMOS, ATUA NA FRAGILIDADE DOS VASOS CAPILARES , ANTI-INFLAMATÓRIASArnica', '', E'Nome científico: Solidago microglossa D.C.  Planta herbácea, perene, da família Compositae, com flores amarelas. Originária da América do Sul. Contém guercitina, glicosídeo, que atua na fragilidade dos vasos capilares. As folhas sáo usadas em contusões, traumatismos e reumatismos, na forma de compressa, cataplasma e banhos. Substitui a arnica verdadeira (Arnica montana). Multiplica-se por sementes ou estacas.  Nomes populares: Arnica-brasileira, arnica silvestre, espiga de ouro, erva lanceta, ma', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Arruda', E'', '', E'RUTA GRAVEOLENS L., ARRUDA-FEDORENTA, RUTA-DE-CHEIRO-FORTE, ARRUDA-DOMÉSTICA E ARRUDA-DOS-JARDINSPLANTA ESTIMULANTE. VERMÍFUGA, ANTIESPESMÓDICA, PARA DORES DE OUVIDO, ALÉM DE CARMINATIVO. USADA NO TRATAMENTO DE VARIZES E FLEBITE. É ANTIHELMÍNTICO E EMENAGOGA. UTILIZADA AINDA PARA PROBLEMAS OFTÁLMICOS, POR EXEMPLO CONJUNTIVITES (USO EXTERNO).ARRUDA', '', E'Nome científico: Ruta graveolens L. Família: Rutaceae. Origem: Sul da Europa. Sinonímia: arruda-fedorenta, ruta-de-cheiro-forte, arruda-doméstica e arruda-dos-jardins.  Descrição: subarbusto de até 1 m de altura, aromático; folhas alternas, pecioladas, carnudas, verde-acinzentadas e compostas; flores pequenas, verdearnareladas; haste lenhosa e ramificada desde a base.  Constituintes químicos principais: flavonóides (rutina e hesperidina), cumarinas (chalepeusina, graveliferona e bergapteno), alc', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Artemisia', E'', '', E'CHRYSANTHEMUM PARTHENIUM (L.) BERN.,MONSENHOR-AMARELO, PIRETRODO-CÁUCASO, MARGARIDINHA, MATRICÁRIA, ARTEMIJO, MACELA-DO-REINO, CAMOMILA PEQUENA, MACELA-DA-SERRA E ARTEMIGEM-DOS-JARDINS.ANTILEUCORREICO, EMENAGOGA, ANTIESPASMÓDICA,ESTOMÁQUICA, FEBRÍFUGA, PARA DORES DE CABEÇA, ENXAQUECA, ARTRITES, DIARRÉIAS, PERTURBAÇÕES GÁSTRICAS E INSÕNIA.ARTEMÍSIA', '', E'Nome científico: Chrysanthemum parthenium (L.) Bern.  Família: Compositae. Origem: Ásia (Cáucaso). Sinonímia: monsenhor-amarelo, piretrodo-cáucaso, margaridinha, matricária, artemijo, macela-do-reino, camomila pequena, macela-da-serra e artemigem-dos-jardins.  Descrição: planta anual, 0,50 a 1 m de altura, muito ramificada nas formas mais altas; flores centrais amarelas e periféricas brancas em capítulos terminais. Apresenta cheiro forte, desagradável e sabor amargo.  Constituintes químicos prin', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Artemísia Chinesa', E'', '', E'ARTEMÍSIA ANNUA L.COMBATE A MALÁRIAArtemísia chinesa', '', E'Nome científico: Artemísia annua L.  Planta herbácea, anual, da família Compositae, originária da Ásia. Contém um princípio ativo, a artemisinina (sesquiterpeno), que combate a malária. Multiplica-se por sementes, sendo indicada a semeadura em tubetes plásticos (150 x 37 mm) com posterior desbaste (25 dias). Esta espécie foi submetida a um melhoramento genético para altos rendimentos do princípio ativo e, dada sua iniportãncia social e econõmica, está sendo investigada a produção de artemisinina', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aspérula Odorífera', E'', '', E'GALIUM ODORATUM (L.),ASPERULA ODORATA L.ADSTRINGENTE,TÔNICO, DIURÉTICO E SEDATIVO.MELHORA FUNÇÃO HEPÁTICA, RELAXA ESPASMOS, FORTALECE VASOS CAPILARES E REDUZ COAGULAMENTO DO SANGUE.CALMANTE,ESPASMOLÍLICO, CONTRA AS PALPITAÇÕES E PARA REGULARIZAR A PULSAÇÃO, CONTRA AS INSÔNIAS INFANTIS,FERIDAS PAspérula-odorífera', '', E'Galium odoratum (L.) SCOP. syn.: Asperula odorata L. Rubiaceae O gênero Galium é cosmopolita e inclui aproximadamente 400 espécies anuais e perenais. Galium aparine é uma erva daninha comum ao longo da Europa e da Ásia do Norte e Ocidental. Galium odoratum, além destes locais, também é encontrado na Sibéria e África do norte, e é a espécie ornamental melhor conhecida e mais difundida. Ela proporciona uma boa cobertura deciduas em solo de áreas sombrias. Galium verum está difundido nos prados da', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Assa Fétida', E'', '', E'FÉRULA, FUNCHO GIGANTEHISTERIA.SISTEMA DIGESTIVO,ALIVIA A DOR E ESPASMOS,ESTIMULA A TOSSE PRODUTIVA,HIPOTENSIVO E ANTI-COAGULANTE.INDIGESTÃO, FLATULÊNCIA, CÓLICA, CONSTIPAÇÃO, LOMBRIGAS INTESTINAIS,DISENTERIA, TOSSE FORTE, BRONQUITE E ENFERMIDADES CONVULSIVAS.ARTICULAÇÕES DOLOAssa fétida, Férula, Funcho gigante', '', E'Umbelliferae (Apiaceae)  Este gênero consiste em 172 espécies perenes robustas, encontradas desde o mediterrâneo até a Ásia Central. Ferula assafoetida é nativa de regiões litorâneas e áreas rochosas do Irã. Embora conhecidas como funchos gigantes, por causa de sua similaridade com a espécie Foeniculum, muitas têm um cheiro desagradável. Ferula assafoetida e Ferula gummosa foram importantes durante muito tempo devido sua resina de látex: a primeira foi taxada por um imposto na Alexandria durante', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Assa Peixe', E'', '', E'VERNONIA POLYANTHES LESSTOSSE, BRONQUITE E COMO EXPECTORANTE, HERNOSTÁTICAS (ESTANCA O SANGUE)Assa-peixe', '', E'Nome científico: Vernonia polyanthes Less.  Planta arbustiva, perene, da família compositae. originária da África. As folhas são utilizadas para tosse, bronquite e como expectorante. Xarope: 2 folhas picadas, 1 xícara (café) de água, ferver por 5 minutos, coar, acrescentar 2 xícaras (café) de açúcar e levar ao fogo novamente, para dissolver o açúcar; os adultos devem tomar 1 colher (sopa) 2 a 3 vezes ao dia. Em compressas, age como hernostáticas (estanca o sangue). As folhas também são utilizada', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Atanásia', E'', '', E'TANACETUM VULGARE L.,CHRYSANTHEMUM VULGARE BERNH.,ERVA-DE-SÃO-MARCOSVERMÍFUGA,EMENAGOGA,ANTI-HELMÍNTICOAtanásia', '', E'Tanacetum vulgare L. syn.: Chrysanthemum vulgare BERNH. Asteraceae (Compositae) Planta herbácea perene com caules eretos, angulosos, suportando folhas divididas, alternas, verde-escuras. Os caules tem capitules terminais de flores amarelas agrupadas em corimbos. Os frutos são aquénios. Toda a planta liberta um odor a cânfora, sobretudo depois de estar seca. A atanasia, também chamada erva-de-são-marcos, cresce na Europa e na Ásia, nos grandes vales fluviais, de clima tépido e úmido, na berra dos', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aveia', E'', '', E'AVENA SATIVA L.ESTIMULA O APETITE E ATENUA AS DORES DE GARGANTA E DO TÓRAX.FADIGA NERVOSA, NERVOSISMO, INSÓNIA.DIABETES, ESCIEROSE, HIPERTENSÃO.REDUZ NIVEIS DE COLESTEROL.ACALMAM AS DORES REUMATISMAIS, A CIÁTICA E AS PERTURBAÇÕES HEPÁTICAS.ECZEMA, AS FRIEIRAS E AS IMPIGAveia', '', E'Avena sativa L. Gramineae (Poaceae) Avena é um gênero de aproximadamente 15 espécies de gramas anuais, encontradas de forma selvagem na Eurásia e África do norte. As mais importantes são Avena tatua (aveia selvagem), uma espécie européia meridional que alcançou partes do hemisfério norte durante a Idade do Ferro e se tornou a principal colheita de subsistência da Escócia; e Avena sativa (aveia cultivada) que foi desenvolvida de avenas selvagens. Avena sativa cresce extensamente em regiões temper', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Aveloz', E'', '', E'EUPHORBIA TIRUCALLI L., AVELOZ, ÁRVORE-DO-CORAL-DE-SÃO-SEBASTIÃO, CEGA-OLHO, CORAL-VERDE, DENTE-DE-CÃO, DEDO-DO-DIABO, GRAVETO-DE-DIABO, LABIRINTO, CASSONEIRA, COROA-DE-CRISTO, ALMEIDINHA E MATA-VERRUGAS.RESOLUTIVO, EM CARCINOMAS E EPITELIOMAS BENIGNOS; PURGÁTIVO; CONTRA PICADA DE ESCORPIÃO E COBRAS (USO INTERNO). USADO PARA CURAR VERRUGAS E, AINDA, COMO RUBEFACIENTE E ANTI-REUMÁTICO, (USO EXTER', '', E'Nome científico: Euphorbia tirucalli L. Família: Euphorbiaceae. Origem: África. Sinonímia: aveloz, árvore-do-coral-de-são-sebastião, cega-olho, coral-verde, dente-de-cão, dedo-do-diabo, graveto-de-diabo, labirinto, cassoneira, coroa-de-cristo, almeidinha e mata-verrugas.  Descrição: planta lactescente arbustiva, pubesceste e sublenhosa; ramos verticilados, filiformes de coloração verde; as flores femininas são terminais e axilares, com coloração amarelada ou esverdeada, enquanto as masculinas fi', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Avenca', E'', '', E'ADIANTUM SPP., AVENCA-CABELO-DE-VÊNUS.EXPECTORANTE E BÉQUICA, AFECÇÕES DAS VIAS RESPIRÁTÓRIAS DE MODO GERAL. USADA POPULARMENTE COMO EMENAGOGAAvenca', '', E'Nome científico: Adiantum spp. Família: Pteridaceae. Origem: Europa e América Tropical. Sinonímia: avenca-cabelo-de-vênus.  Descrição: planta que cresce em touceiras; hastes e ramos marrom escuros, duros e muito finos; folhas pecioladas, alternas, muito finas, polimorfas. Apresenta rizomas não muito longos.  Constituintes químicos principais: compostos fenólicos e carboidratos, ácidos gálico e tânico.  Indicações: expectorante e béquica, afecções das vias respirátórias de modo geral. Usada popul', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Azeda Do Brejo', E'', '', E'BEGONIA SP. , ERVA-DE-SAPOCOMBATER A FEBRE, MELHORA OS OLHOS INFLAMADOS, INDICADO PARA SAPINHOSAzeda-do-brejo', '', E'Nome científico: Begonia sp.  Planta herbácea, perene, da família Begoniaceae, também conhecida corno erva-de-sapo. Folhas arredondadas, espessas, verde brilhantes. As folhas e flores são utilizadas, na forma de infusão, para combater a febre e banhar os olhos inflamados. Seu suco, que é ácido, é indicado contra diarréia, na dose de 30 a 60 g, internamente. Externamente, é indicado para sapinhos. Tem bom desenvolvimento em locais úmidos e parcialmente sombreados. Multiplica-se por sementes e est', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Azedinha', E'', '', E'OXALIS ACETOSELLA L.,OXÁLIDA-AZEDADIURÉTICO.ANTISCORBÚTICAS.Oxálida-azeda', '', E'Oxalis acetosella L. Oxalidaceae Planta perene com fino rizoma rastejante e caule atrofiado que apresenta folhas longamente pecioladas. Estas folhas são bifoliadas. tendo os folíolos a forma de coração invertido; as folhas fecham à noite ou quando faz mau tempo, dobrando-se segundo o eixo da nervura central. As flores brancas aparecem isoladamente; as pétalas têm veios violeta e os pedúnculos são longos. Neste tipo de flores a polinização é assegurada por insetos. Outras flores são autogàmicas;', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Babado De Viúva', E'', '', E'DATURA STRAMONIUM VAR. TATULA DUN., TROMBETA-ROXA, ESTRAMÔNIOASMA, ANTIESPASMÓDICA, SEDATIVA, ANTIASMÁTICA E ALUCINÓGENABabado-de-viúva', '', E'Nome científico: Datura stramonium var. tatula Dun.  Planta arbustiva tropical, bianual, da família Solanaceae, conhecida também corno trombeta-roxa. As folhas são transformadas em cigarro e fumadas para combater a asma. Dada a presença de alcalóides (daturina, hiosciamina, escopolamina) que lhe conferem toxicidade, as espécies do género Datura devem ser utilizadas sob a orientação de um profissional da área. As folhas e sementes possuem atividade antiespasmódica, sedativa, antiasmática e alucin', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Babosa', E'', '', E'ALOE VERA L., ERVA-BABOSA E CARAGUATÁ.INFLAMAÇÕES, QUEIMADURAS,ECZEMAS, ERISIPELA, QUEDA DE CABELO,ANTIOFTALMICA, VULNERÁRIA E VERMÍFUGA,ANTI-HEIMÍNTICO Babosa', '', E'Nome científico: Aloe vera L. Família: Liliaceae.  Origem: Sul da África. Sinonímia: erva-babosa e caraguatá. Descrição: folhas carnosas, grossas e suculentas, quase triangulares, orladas de espinhos, são ricas em suco mucilaginoso translúcido no centro e amarelado próximo à epiderme; caule muito curto; flores tubulosas e amarelas, em cacho.  Constituintes químicos principais: barbalodina, aloína (purgativo), aloquilodina, aloetina, aloeferon (cicatrizante), ácido pícrico, resinas, mucilagens e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bálsamo', E'', '', E'SEDUM DENDROIDEUM MOC. & SESSÉEMOLIENTE, USADO EM INFLAMAÇÕES GASTRINTESTINAIS E DA PELE, ÚLCERAS E CICATRIZANTE.BÁLSAMO', '', E'Nome científico: Sedum dendroideum Moc. & Sessé Família: Crassulaceae. Origem: África do Sul e Ásia . Sinonímia: sem referências.  Descrição: planta herbácea; folhas suculentas; flores amarelas, atinge 0,30 a 0,50 m de altura. Sabor levemente ácido. Constituintes químicos principais: mucilagens.  Indicações: emoliente, usado em inflamações gastrintestinais e da pele, úlceras e cicatrizante.  Parte usada: folhas frescas.  Preparo e dosagem: - uso ao natural, sob a forma de saladas, sem tempero (i', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Barbasco', E'', '', E'BUDDLEJA BRASILIENSIS JACK., VERBASCODEPURATIVA, ADSTRINGENTE, DIURÉTICA, EXPECTORANTE, EMOLIENTE E SEDATIVA, INDICADA PARA TOSSE, BRONQUITE E ASMA , HIPERTENSÃOBARBASCO', '', E'Nome científico: Buddleja brasiliensis Jack.  Espécie nativa do Brasil, bianual ou perene, da família Buddlejaceae, também conhecida corno verbasco. As folhas e flores possuem propriedades: depurativa, adstringente, diurética, expectorante, emoliente e sedativa, indicada para tosse, bronquite e asma. Pode-se usar na forma de infusão ou tintura (10%). Em casos de doenças cardíacas, quadros de hipertensão, utiliza-se a compressa de barbasco no coração (1 a 2 vezes ao dia), podendo-se tornar o chá', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Barbatimão', E'', '', E'STRYPHNODENDRON BARBATIMAN M.INFECCÕES DO ÚTERO, LAVAGENS VAGINAIS E LEUCORRÉIA, NA FORMA DE BANHOS. ÚLCERAS. ADSTRINGENTE, DEPURATIVA, HIPOGLICEMIANTE E TÔNICABarbatimão', '', E'Nome científico: Stryphnodendron barbatiman M.  Árvore da família Leguminosas, nativa do Brasil, de pequeno porte (5 a 7 m). As cascas são muito ricas em taninos. O decocto, que se prepara com 30 g de casca e 500 g de água, é utilizado em infeccões do útero, lavagens vaginais e leucorréia, na forma de banhos. Externamente, reduzida a pó, a casca é empregada no tratamento de úlceras. As folhas são tônicas, e as sementes consideradas venenosas (alcalóides). Tem ação adstringente, depurativa, hipog', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bardana', E'', '', E'ARCTIUM LAPPA L., BARDANA-MAIORHIPOGLICEMIANTE, DEPURATIVA, COLERÉTICO, DIURÉTICA E DIAFORÉTICA. USADA COMO CICATRIZANTE, PARA TRATAMENTO DE FURUNCULOS, ABSCESSOS, ACNE E TERÇOL. AJUDA NO TRATAMENTO DE QUEDA DE_CABELO E ENFERMIDADES DA PELE, POR EXEMPLO, MICOSE DE UNHAS E FRIEIRAS (USOBARDANA', '', E'Nome científico: Arctium lappa L. F mília: Compositae.  Origem: Japão. Sinonímia: bardana-maior. Descrição: planta bianual herbácea, com 1 a 1,5 rn de altura, pilosa; folhas alternas, cordiforrnes e ovais; flores azuladas ou arroxeadas, dispostas em capítulos e, estes, ern corimbos.  Constituintes químicos principais: óleo essencial contendo inulinas e, ainda, açúcares, polifenóis, fuquinona, beta eudesmol, taraxasterol, acetato e palmitato de diidrofuquinona.  Indicações: é uma planta hipoglice', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Batata De Bugre', E'', '', E'PIPTOSTEGIA PISONIS MART., FOLHA-DO-FOGO , UNHA-DO-GATOPURGATIVOBatata-de-bugre', '', E'Nome científico: Piptostegia pisonis Mart.  Planta nativa do Brasil, perene, da família Convolvulaceae, também conhecida como folha-do-fogo e unha-do-gato. Planta silvestre, trepadeira herbácea cora gavinhas; raiz tuberosa; folhas pequenas acuminadas; flores brancas em cachos. Utiliza-se o tubérculo como purgativo, menos energético do que o da batata-de-purga (2 a 4 g em pó da raiz). Tem bom desenvolvimento quando cultivada. Multiplica-se por tubérculos.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Batata De Purga', E'', '', E'OPERCULINA MACROCARPA URB., JALAPA E RUIBARBO BRANCOLAXATIVO E PURGATIVO. DEPURATIVO, CONTRA MOLÉSTIAS DA PELEBatata-de-purga', '', E'Nome científico: Operculina macrocarpa Urb.  Planta nativa do Brasil, anual ou bianual, da família Convolvulaceae, apresenta também outros nomes: jalapa e ruibarbo branco, É uma trepadeira herbácea sem gavinhas; folhas grandes e ovais; raiz tuberosa; flores brancas e solitárias; frutos com sementes negras e duras. Utiliza-se a decocção do tubérculo seco (pó) como laxativo e purgativo; é também um depurativo, contra moléstias da pele. Pode ser tóxica. Usar sob a orientação de profissional da área', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Baunilha', E'', '', E'VANILLA SP.AFECÇÕES NERVOSAS, AROMATIZANTE DE DOCES, BEBIDAS, PERFUMESBaunilha', '', E'Nome científico: Vanilla sp.  Espécie trepadeira, perene, da família Orchidaceae, originária do México e América Central. Possui folhas brancas efêmeras que dão pequenas vagens verdes. As vagens são colhidas e secas ao sol. os frutos, em infusáo ou tintura, são utilizados contra afecções nervosas. É também utilizada como aromatizante de doces, bebidas, perfumes entre outros. Multiplica-se por estacas (40-80 cm) em lugar sombreado.  G', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Beladona', E'', '', E'ATROPA BELLADONA L.ESPASMOLITICO,DORES DAS CÓLICAS URINÁRIAS E DA VESÍCULA BILIAR, ALIVIAM AS CRISES DE ASMABELADONA', '', E'Atropa belladona L. Solanaceae Planta vivaz com caule ramificado, formando um vasto tufo suportado por uma gigantesca raiz cônica. O caule tem folhas alternas, ovais e moles. Na axila das folhas aparecem flores campanuladas, pedunculadas, castanhoavermelhadas, que depois se transformam em bagas negras. A beladona cresce na Europa á beira das florestas, nos escombros e lugares abandonados. Toda a planta é extremamente venenosa e são conhecidos casos de envenenamentos mortais em crianças que confu', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Beldroega', E'', '', E'PORTULACA OFERACEA L.CICATRIZASTE, VERMÍFUGO E LAXANTE, DOENÇAS URINÁRIAS E INFLAMAÇÕES DOS OLHOSBeldroega', '', E'Nome científico: Portulaca oferacea L.  É uma espécie herbácea, anual, da família Portulacaceae, suculenta, prostrada e ramificada. Originária da Grécia e China. Apresenta, às vezes, folhas e caules avermelhados, pela presença da antocianina. As folhas (sumo) têm efeito cicatrizaste, vermífugo e laxante, quando comidas em grande quantidade. Combate, ainda, doenças urinárias e inflamações dos olhos. É rica em mucilagens. A beldroega ainda é comestível, sendo rica em proteínas, vitaminas A, B e C,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bétula', E'', '', E'BETULA PENDULA ROTH.,BETULA VERRUCOSA EHRH.DOENÇAS DO SISTEMA URINÁRIO E REUMATISMOS.DIURÉTICO.CÁLCULOS RENAIS.REUMATISMOS.BÉTULA', '', E'Bétula Betula pendula Roth. Syn.: BetuLa verrucosa Ehrh. Betulaceae Grande árvore com ramos pendentes castanhos, casca branca e fendida na base do tronco. As folhas longamente pecioladas, no início viscosas, são alternas sobre os ramos. A bétula é uma árvore monóica: tem simultaneamente amentos de flores estaminadas e amentos de flores pistiladas. O fruto é um aquênio alado . A bétula é uma árvore vulgar na Europa e na Ásia, onde se encontra na sombra das florestas, nos bosques, nas ruas. As fol', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bistorta', E'', '', E'POLYGONUM BISTORTA L.,BISTORTA MAJOR S.F. GRAY.HEMOSTÁTICOS INTERNOS OU EXTERNOS,CATARROS GASTRINTESTINAIS E AS DIARRÉIAS FORTES,DISENTERIA.INFIAMAÇÕES DA CAVIDADE ORAL, AS AMIGDALITES, EM CASOS DE EXTRAÇÃO DENTÁRIA.Bistorta', '', E'Polygonum bistorta L. Syn.: Bistorta major S.F. Gray. Polygonaceae Planta perene com rizoma espesso, sinuoso, e uma roseta de folhas lanceoladas. O caule ereto termina numa espiga de flores cor-de-rosa. O fruto e um aquênio triquetro. É uma espécie vulgar em toda a Europa, nos prados encharcados, nas pastagens, nas valas, tanto a baixa como elevada altitude. Sobretudo os povos nórdicos empregavan-na antigamente contra a disenteria e a peste. As antigas receitas fazem dela componente de teriagas', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Boldo', E'', '', E'VERNONIA CONDENSATA BEKER.ANALGÉSICOS, APERIENTE, COLAGOGO, COLERÉTICO, DESINTOXICANTE DO. FÍGADO, DIURÉTICO E ANTIDIARRÉICO. USADO, POPULARMENTE, PARA A RESSACA ALCÓOLICA.Boldo', '', E'Nome científico: Vernonia condensata Beker.  Família: Compositae. Origem: África.  Sinonímia: alumã, árvore-de-pinguço, boldo-japonês, figatil, heparém, boldo-degoiás, etc.  Descrição: arbusto perene que cresce até 2 ou 3 m de altura, formando toureiras; folhas alternas. Sabor amargo.  Constituintes químicos principais: óleos essenciais, saponinas, taninos, flavonóides e lactonas sesquiterpênicas.   Indicações: analgésicos, aperiente, colagogo, colerético, desintoxicante do. fígado, diurético e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bolsa De Pastor', E'', '', E'CAPSELLA BURSA-PASTORÍS MOENCH.ADSTRINGENTE, ANTIEMÉTICA, ANTI-HERNORRÁGICA E EMENAGOGO, ALÍVIO DE INFLAMAÇÕES E DORESBolsa-de-pastor', '', E'Nome científico: Capsella bursa-pastorís Moench.  Planta herbácea, anual, da família Cruciferae, com até 60 cm de altura, originária da Europa.As flores são brancas, e os frutos (par) são triangulares. É adstringente, antiemética, anti-hernorrágica e emenagogo. Também é empregada no alívio de inflamações e dores. Utilizase as raízes, folhas e flores, na forma de infusao (30 a 60 g da erva em 1 litro de água, 3 vezes ao dia, entre as refeições), vinho medicinal (100 g da erva em 1 litro de vinho', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Borragem', E'', '', E'BORAGO OFFICINALIS L.CONSOLA O CORAÇÃO, AFASTA A MELANCOLIA E ACALMA O FRENÉTICO OU PESSOA LUNÁTICA. DEPRESSÃObORRAGEM', '', E'Borago officinalis L. Boraginaceae Três espécies anuais e perenes compõe este gênero que é nativo na região medaerrãnea e na Ásia ocidental. Duas espéces, Borago officinalis e Borago pygmaea, são populares pelas suas flores de coloração azul claro. O nome Borago pode ser derivado do termo latino ''burra", nome de um artigo de vestuário coberto de pelos, aludindo à folhagem cerdosa. Foi chamado de Euphrosinum por Plinio, por causa de seu efeito eufórico. Borago officinalis e uma planta anual com c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bredo', E'', '', E'AMARANTHUS VIRIDIS L.,CARURÚDIARRÉIA E MENSTRUAÇÃO EXCESSIVA.ADSTRINGENTE PARA ÚLCERAS BUCAIS E GARGANTA;CORRIMENTO VAGINAL, FERIMENTOS E HEMORRAGIA NASAL.DIURÉLICA.Bredo, Carurú', '', E'Amaranthus viridis L. Amarantaceae O gênero Amaranthus inclui 60 espécies espalhadas mundialmente em regiões temperadas e tropicais, das quais umas 20 são consideradas como plantas invasoras; A. Hypochondriacus ocorre no E.U.A. meridional, México, Índia e China. Muitas são comestíveis e são usadas como legumes e ervas de tempero, algumas são importantes como colheitas de grãos. Outras também tem usos medicinais. Algumas espécies têm folhagem colorida e são cultivadas para fins ornamentais. Amara', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Briônia Branca', E'', '', E'BRYONIA ALBA L.REUMATISMO,GOTA,CATÁRTICA, DIURÉTICA , EMÉTICA.Briônia-branca', '', E'Bryonia alba L. Cucurbitaceae O gênero Bryonia consta de cerca de 10 espécies de trepadeiras tuberosas perenes, nativas na Eurásia, África do norte e Ilhas Canárias. O nome Bryonia vem do grego "bryo", brotar, e se refere ao crescimento anual a partir do tubérculo.  Bryonia alba é uma planta perene com raiz cônica e ramficada, caule áspero, volúvel, atingindo até 5m de comprimento. O caule apresenta folhas palmadas alternas e gavinhas. Na axila das folhas aparecem cachos com pequenas flores verd', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Buchinha Do Norte', E'', '', E'LUFFA OPERCULATA COGN.,  CABACINHASINUSITEBuchinha-do-norte', '', E'Nome científico: Luffa operculata Cogn.  Planta trepadeira, anual, da família Cucurbitaceae, originária do Brasil, onde também conhecida como cabacinha. Empregada contra sinusite. Ferver 1/4 de fruto em 2 copos de água; dividir em 2 partes e fazer com uma parte inalação ainda quente; com a outra, depois de fria, pingar 2 gotas em cada narina de 4 em 4 horas. Não se deve assoar o nariz, deixe que escorra normalmente; fazer isto por breve período de tempo (3 a 5 dias). Esta planta pode ser muito p', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Bupleurum', E'', '', E'BUPLEURUM FALCATUMVULNERÁRIO, PARA DIMINUIR AS INCHAÇÕES DAS GLÂNDULAS E TAMBÉM NA GOTA.MALÁRIA, PROLAPSO UTERINO E RETAL, HERPES SIMPLES, HEMORRÓIDAS,FÍGADO PREGUIÇOSO.DESORDENS MENSTRUAIS E INCHAÇO ABDOMINAL.Bupleurum', '', E'Bupleurum falcatum Urnbelliferae (Apiaceae) Sob o ponto de vista antroposófico Este gênero de cerca de 100 espécies habita as regiões rochosas e os campos ralos em vegetação, comuns nas montanhas, e também cresce nas estepes salgadas. O Bupleurum é uma variante muito peculiar da família das Umbeliferas, algumas plantas silvestres se relacionam com o tipo Bupleurum que se afasta muito da imagem habitual das Umbeliferas. Encontramos folhas inteiras de bordo unido ou folhas semelhantes às das Gramí', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Buxo', E'', '', E'BUXUS SEMPERVIRENS L.ANTIPIRÉTICO, NFLAMAÇÃO DAS VIAS BILIARES E URINÁRIAS.Buxo', '', E'Buxus sempervirens L. Buxaceae Encontrado na Europa ocidental, Américas do Norte e central, Ásia oriental e Índias Ocidentais, o género Buxus contém aproximadamente 30 espécies de pequenas árvores e arbustos perenes. O lento crescimento e a longa vida do Buxus sempervirens, encontrado na Europa e América do Norte, motivou desde os tempos Clássicos seu uso para Copiaria, a arte de adornar os jardins, dando a certos grupos de plantas diferentes formas e configurações.  Buxus sempervirens é uma árv', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cacau', E'', '', E'THEOBROMA CACAOESTIMULANTE, DIURÉTICA, QUE ABAIXA A PRESSÃO SANGUÍNEA E DILATA AS ARTÉRIAS CORONÁRIAS.SUAVIZA E ACALMA  A PELE DANIFICADA.ANGINA E PRESSÃO ALTACacau', '', E'Theobroma cacao Sterculiaceae O género Theobroma consta de 20 espécies de árvores perenes tropicais americanas. Elas apresentam a caraclerislica incomum de produzirem as flores diretamente no tronco ou ramos. Theobroma cacao ocorre em baixadas e florestas tropicais da Amérca Central e do Sul. Embora as primeiras frutas de cacau foram levadas da América do Sul para a Espanha por Cristovão Colombo (1451-1506), o hábito pelo cacau não desenvolveu até o século 17. O cultivo de cacau na Áfnca começou', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cairuçu Asiático', E'', '', E'CENTELLA ASIATICA (L.), HYDROCOTYLE ASIATICA L.REDUZ O TEMPO DE CICATRIZAÇÃO, MELHORA PROBLEMAS CIRCULATÓRIOS NOS MEMBROS INFERIORES E ACELERA A CURA.LEPRA.REJUVENESCEDORA, DIURÉTICA,REDUZ INFLAMAÇÃO E A FEBRE, MELHORA A CURA E A IMUNIDADE.COMBATER FERIDAS E CONDIÇÕES CRÓNICAS DA PELE.DESORDENS NERVOSCairuçu asiático', '', E'Centella asiatica (L.) Urban Synonímia Hydrocotyle asiatica L. Umbelliferae (Apiaceae) O gênero Centella inclui aproximadamente 20 espécies de pequenas ervas perenes que medram na África meridional e na maioria das partes das regiões tropicais. A espécie mais conhecida é a Centella asiática que é uma erva medicinal importante. semelhante a uma sua parente Européia, a Hydrocotyle vulgares. A planta foi denominada inicialmente Hydrocotile asiática por Linnaeus e posteriormente passou para o gênero', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cajueiro', E'', '', E'ANACARDIUM OCCIDENTALE L.REDUZ A FEBRE (FOLHAS) E NIVEIS DE AÇÚCAR NO SANGUE,DIURÉTICA (FRUTAS),DIARRÉIA,HIPOGLICEMIA,GRIPE,MALARIA ,LEPRA, VERRUGAS E ENFERMIDADES DA PELE.DORES DE DENTE E GENGIVACajueiro', '', E'Anacardium occidentale L. Anacardiaceae Quinze espécies de árvores ou arbustos perenes, de porte pequeno até árvores muito altas, compõem o género Anacardium, nativo de partes tropicais da América do Sul e Central e da Índia ocidental.  Anacardium occidentale é encontrado em áreas secas, especialmente em regiões litorâneas no nordeste do Brasil e no Caribe, foi levado do Brasil para Índia e o Arquipélago malaio durante o século 16, mas não chegou á Europa antes de 1699. Suas folhas são ovaladas', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Calendula', E'', '', E'CALENDULA OFFICINALIS L., MALMEQUER E MARAVILHA DOS JARDINS.AÇÃO CICATRIZANTE E ANTISÉPTICA (USO EXTERNO); É SUDORÍFOGA, ANALGÉSICA, COLAGOGA, ANTIINFLAMATÓRIA, ANTIVIRAL, ANTIEMÉTICO. VASODILATADORA E TONIFICANTE DA PELE (CONTRA ACNE).CALÊNDULA', '', E'Nome científico: Calendula officinalis L. Família: Compositae. Origem: Europa. Sinonímia: malmequer e maravilha dos jardins.  Descrição: folhas geralmente ovais; flores grandes, largas e de coloração variando entre alaranjada e amarela; raiz fasciculada amarelo-clara; sementes em forma de pequenos barcos (curvas).  Constituintes químicos principais: caroteri ides, óleo essencial, saponinas (antiviral), flavonóides e cumarinas.  lndieações: tem ação cicatrizante e antiséptica (uso externo); é sud', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cambará', E'', '', E'LANTANA CAMARA L.ASMA, TOSSE E COQUELUCHE, REUMATISMOS E AFECÇÕES DO FÍGADOCambará', '', E'Nome científico: Lantana camara L.  Subarbusto perene, da família Verbenaceae, originária da América do Sul. As folhas e flores são usadas contra asma, tosse e coqueluche, na forma de infusão ou xarope: 3 a 5 folhas, 1 xícara de café de água fervente, 2 xícaras (café) de açúcar, levar novamente ao fogo para formar a calda; para adultos, dar 1 colher  (sopa) 2 a 3 vezes por dia; e crianças devera tornar 1 colher (chá) 2 a 3 vezes ao dia, quando tiverem peso acima de 14 kg e, abaixo disto, recomen', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Camomila Amarela', E'', '', E'MATRICARIA TINCTORIA L., CAMOMILA-ROMANA E ERVAMADRECALMANTE, ESTIMULANTE DIGESTIVO, CARMINATIVO, EM CASOS DE NÁUSEAS, INFLAMAÇÕES DAS VIAS URINÁRIAS, ALÉM DE COMBATER FEBRES E AFECÇÕES DA PELECamomila amarela', '', E'Nome científico: Matricaria tinctoria L. Herbácea anual, da família Cornpositae, originária da Europa, também conhecida corno camomila-romana e ervamadre. As folhas e flores são utilizadas como calmante, estimulante digestivo, carminativo, em casos de náuseas, inflamações das vias urinárias, além de combater febres e afecções da pele. Multiplica-se por sementes. Também é utilizada corno planta ornamental. Ã', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cana De Macaco', E'', '', E'COSTUS SP.DIURÉTICA, DIAFORÉTICA, TÔMICA E EMENAGOGO. AFECÇÕES RENAIS, COMBATE LEUCORRÉIA, TUMORESCana-de-macaco', '', E'Nome científico: Costus sp.  Espécie herbácea, perene, da família Zingiberaceae, que apresenta folhas alternas. O decocto das hastes e rizomas tem ação diurética, diaforética, tômica e emenagogo. Esta planta é muito utilizada em afecções renais (folhas e hastes). Usam-se também as hastes sumo para combater leucorréia. As folhas frescas são empregadas em forma de cataplasma no tratamento de tumores. Deve ser evitado o seu uso interno contínuo, pois apresenta muito oxalato, ocasionando o surgiment', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cantara', E'', '', E'STENORRHYNCHUS LANCEOLATUM (AUBL.) RICH. EX SPRENGEL.TRATAMENTO DE NERVOS, AFRODISÍACASCantara', '', E'Mome científico: Stenorrhynchus lanceolatum (Aubl.) Rich. ex Sprengel.  Trata-se de uma espécie terrestre, perene, nativa do Brasil, pertencente a família Orchidaceae. Na medicina popular, é utilizada para o tratamento de nervos, sendo também empregada por propriedades afrodisíacas. Sua propagação se dá por sementes e divisão de touceiras. i', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capeba', E'', '', E'POTHOMORPHE UMBELLATA (L.) MIQ., PARIPAROBA, MALVAÍSCO, CAAPEBA E CAPEVAPARA AFECÇÕES DO APARELHO DIGESTIVO, COMBATE A FEBRE, REGULA A MENSTRUAÇÃO. USADA AINDA CONTRA INSUFICIÊNCIA HEPÁTICA. É DIURÉTICO, TÕNICO, ESTORNÁQUICO E CARMINATIVO. (USO INTERNO).CAPEBA', '', E'Nome científico: Pothomorphe umbellata (L.) Miq.  Família: Piperaceae. Origem: América.  Sinonímia: pariparoba, malvaísco, caapeba e capeva.  Descrição: planta arbustiva, perene, cresce até 1,5 - 2,5 m de altura; folhas grandes, reniformes, pilosas. As inflorescëncias são umbelas axilares.  Constituintes químicos principais: pouco conhecidos. Contém óleo essencial, compostos fenólicos, esteróides e mucilagens.  Indicações: para afecções do aparelho digestivo, combate a febre, regula a menstruaçã', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capim Caboclo', E'', '', E'CYNBOPOGON MARTINII (ROXB) J.F.WATON, CAPIM-SÃO-JOSÉTOSSE, BRONQUITE, ROUQUIDÃO E AFECÇÕES CATARRAISCapim-caboclo', '', E'Nome científico: Cynbopogon martinii (Roxb) J.F.Waton.  Espécie bianual ou perene, da família Gramineae, originária da índia, também conhecido como capim-são-josé. As folhas, na forma de infusão, são indicadas para tosse, bronquite, rouquidão e afecções catarrais. É popularmente usado, em banhos e defumaçoes. Propaga-se por sementes e divisão de touceiras adultas. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capim Citronela', E'', '', E'CYMBOPOGON NARDUS RE RENDL.ANTIMICROBIANA, FABRICAÇÃO DE PERFUMES E COSMÉTICOS, SENDO TAMBÉM REPELENTE DE INSETOSCapim-citronela', '', E'Nome científico: Cymbopogon nardus Re rendl.  Espécie perene, da família Gramineae, originária do Sri Lanka e da índia, semelhante ao capim-santo, mas com aroma que lembra o Eucalvptus citriodora em razão do alto teor de geraniol (65/0) e citronelal (35%) em seu óleo essencial. Estes princípios ativos conferem-lhe atividade antimicrobiana. É utilizado, na fabricação de perfumes e cosméticos, sendo também repelente de insetos. Multiplica-se por divisão de touceiras. Prefere climas úmidos e exige', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capim Gordura', E'', '', E'MELINIS MINUTIFLORA BEAUV., CATINGUEIRODISENTERIACapim-gordura', '', E'Nome científico: Melinis minutiflora Beauv.  Espécie herbácea, anual, da família Gramineae, originária da África, também conhecida como catingueiro. Suas folhas apresentam numerosas glândulas, o que lhe confere característica gordurosa. O decocto das folhas é usado popularmente para combater a disenteria. É urna planta forrageira. Multiplica-se por sementes. Ø', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capim Limao', E'', '', E'CVMBONOGON CITRATUS (D.C.) STAPF, CAPIM-CIDREIRA, CAPIM-CIDRÓ, CAPIM-LIMÃO, ERVA-CIDREIRA, CAPIM-DE-CHEIRO E CHÁ-DE-ESTRADABACTERICIDÁ,ANTIESPASMÓDICO, ANTITÉRMICO, CALMANTE, ANALGÉSICO SUAVE, CARMINATIVO, ESTOMÁQUICO, DIURÉTICO, SUDORÍFERO, HIPOTENSOR, ANTI=REUMÁTICO. MAIS UTILIZADO ERM DIARRÉIAS, DORES ESTOMACAIS E PROBLEMAS RENAIS. INSÔNIA, ANSIEDADE, TÔNICO DEPURATIVO NOSCAPIM LIMÃO', '', E'Nome científico: Cvmbonogon citratus (D.C.) Stapf.  Família: Gramineae. Origem: Índia. Sinonímia: capim-cidreira, capim-cidró, capim-limão, erva-cidreira, capim-decheiro e chá-de-estrada.  Descrição: erva perene, cespitosa, formando touceiras compactas e robustas de até 1,2 m de altura, com rizoma semisubterrâneo. As flores são raras e estéreis.  Constituintes químicos principais: óleo essencial contendo geraniol, citral (antiespesmódico, antimicrobiano, inseticida e repeÍente), mirceno (analgés', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capim Pé De Galinha', E'', '', E'ELEUSINE INDICA GAERTN., CAPIM-DE-POMARPNEUMONIA, GRIPE E FEBRESCapim-pé-de-galinha', '', E'Nome científico: Eleusine indica Gaertn.  Espécie anual ou perene, da família Gramineae, originária da índia, também conhecida com capim-de-pomar. As folhas, na forma de infusáo, são usadas em pneumonia, gripe e febres. Multiplica-se por sementes. É considerada uma planta daninha. *', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Capuchinha', E'', '', E'TROPAEOLUM MÁIUS L., CAPUCHINHA-GRANDE, MASTRUÇODO-PERU, FLOR-DE-SANGUE, AGRIÃO-DO-MÉXICO, CHAGAS E NASTÚRCIO.PURGATIVA (FRUTOS SECOS), APERIENTE, TÔNICO, DEPURATIVA, E ANTIBIÓTICO NATURAL, ANTIESCORBÚTICA, ESTIMULANTE. DIGESTIVA, EXPECTORANTE E PARA ÚLCERAS. USADA AINDA PARA ESCROFULOSE E DEMAIS AFECÇÕES DA PELE (USO EXTERNO).CAPUCHINHA', '', E'Nome científico: Tropaeolum máius L. Família: Tropaeolaceae. Origem: América do Sul.  Sinonímia:capuchinha-grande, mastruçodo-peru, flor-de-sangue, agrião-do-méxico, chagas e nastúrcio.  Descrição: trepadeira anual, herbácea; caules carnosos e cilíndricos verde-claros; folhas redondas; flores solitárias, que variam do branco ao vermelho-escuro. Sabor picante.  Constituintes químicos principais: mirosina (enzima), glucotropaeolina, que origina compostos sulfurados antibjótices por hidrólise, resi', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Carapiá', E'', '', E'DORSTENIA SP. , CAIAPÁ,  CHUPÃO, LIGA-OSSO, LIGA-LIGA, TIÚ, FIGUEIRA-TERRESTRE E CAAPIÁEMENAGOGA, FEBRÍFUGA, SUDORÍFERO E TÔNICO. SOLIDIFICADOR DE OSSOS FRATURADOS E ANTIOFÍDICACarapiá', '', E'Nome científico: Dorstenia sp.  Planta perene, da família Moraceae, nativa do Brasil, também conhecida como caiapá, chupão, liga-osso, liga-liga, tiú, figueira-terrestre e caapiá. Utiliza-se toda a planta como emenagoga, febrífuga, sudorífero e tônico. É ainda empregada pela população rural corno solidificador de ossos fraturados e antiofídica, além de servir para aromatizar o fumo. Apresenta furocumarinas, substâncias fotossensibilizantes, com potencial carcinogênico. Dose acima do normal pode', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cardo De Santa Maria', E'', '', E'SILYBUM MARIANUM L.AFECCÕES DA VESÍCULA BILIAR; SÃO COLAGOGOS E REGENERADORES DO TECIDO HEPÁTICO.FEBRÍFUGACARDO DE SANTA MARIA', '', E'SiLyBUM MARIANUM L. Asteraceae (compositae)  Planta anual ou bienal caracterizada por um caule alto e ramoso, apresentando folhas sesseis, alternas. manchadas e com espinhos. Na extremidade dos ramos, encontram-se capítulos solitários de flores violáceas e lubulosas. Os frutos são aquênios com coroa. A espécie è originária das regiões mediterrânicas e frequentemente semeada nos jardins campestres, a titulo ornamental ou medicinal. Naturalizam-se muitas vezes nos arredores. Os seus efeitos medici', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cardo Santo', E'', '', E'CNICUS BENEDICTUS L., CARDO-BENTODIGESTIVO, DEPURATIVO, COLERÉTICO, ANTIBIÓTICO, APERIENTE, ESTORNÁQUICO, CICATRIZANTE, ANTIOFTÁLMICO (LOÇÃO), ALÉM DE CURAR FERIDAS E CHAGASCARDO SANTO', '', E'Nome científico: Cnicus benedictus L. Família: Compositae. Origem: Índia (aclimatada na Europa). Sinonímia:cardo-bento.  Descrição: planta herbácea, anual; haste ramosa e pilosa; folhas grandes, lobadas, espinhosas, cor verde-clara, nervuras salientes; flores amarelas, tubulosas, em capítulos solitários, rodeados de folhas e brácteas, terminadas em espinhos avermelhados; frutos aquênios.  Constituintes químicos principais: óleo essencial, cnicina, tanino, mucilagem, sais minerais, resinas e flav', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cardos Medicinais', E'', '', E'REUNIÃO DE DIVERSOS CARDOSDEPENDE DA ESPÉCIE CONSIDERADACardos Medicinais', '', E'(Sob ponto de vista antroposofico) O tipo compostas assume um aspecto particular na sub-família dos cardos. Eles são geralmente plantas imponentes, que crescem sobretudo nas estepes pobres e secas da região mediterrânea e do Oriente próximo, na Rússia meridional e Ásia central. Poderíamos denominar esses vegetais como "Os cactos do leste".  Na verdade, quando a América é representada através de seus cactos, a África através de suas Euforbiáceas e a Ásia através de seus cardos, algo das forças fo', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Carqueja', E'', '', E'BACCHARIS TRIMERA (LESS), CARQUEJA, CARQUEJA AMARGOSA. B. ARTICULATA: CARQUEJA DOCEANEMIA, DIÁBETE, OBESIDADE. DIGESTIVO, TÔNICO ESTOMACAL, APERIENTE, DIURÉTICO, REUMATISMO, GOTA E ESTIMULANTE DO FÍGADO; FERIDAS E ÚLCERAS (USO EXTERNO)CARQUEJA', '', E'Nome científico: Baccharis trimera (Less) D.C.  Família: Compositae. Origem: Brasil. SinoLia: vassoura, quina-decondomine, cerque, carqueja-amarga, tiririca-de-babado, bacante e cacaia amarga.  Descrição: arbusto perene de pequeno porte (1 a 2 m); com ramos trifoliados e inflorescêncías em capítulos.  Constituintes químicos principais: óleo essencial com nopineno, carquejol, acetato de carquejilo, sesquiterpenos e taninos.  Indicações: anemia, diábete, obesidade. digestivo, tônico estomacal, ape', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Carqueja Doce', E'', '', E'BACCHARIS SPP.,DEPURATIVO, DIURÉTICO, CONTRA REUMATISMO, DIARRÉIAS, ENFERMIDADES DO BAÇO, DA BEXIGA, DO FÍGADO. TAMBÉM É EMPREGADA CONTRA ANEMIA, PRISÃO DE VENTRE (CARMINATIVO) E ENJÔOS.Carqueja-doce', '', E'Nome científico: Baccharis spp.  Espécie herbácea, perene, da família Compositae. O caule apresenta somente duas decorrências foliáceas. As folhas, na forma de infusão, são utilizadas como depurativo, diurético, contra reumatismo, diarréias, enfermidades do baço, da bexiga, do fígado. Também é empregada contra anemia, prisão de ventre (carminativo) e enjôos. O gênero Baccharis é muito extenso, incluindo cerca de 400 espécies com características semelhantes, que recebem o nome indistintamente de', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Carvalhinha', E'', '', E'TEUCRIUMESTIMULA OS PROCESSOS DO FÍGADO,FAVORECE O FLUXODA BÍLIS E COMBATE A FORMAÇÃO DOS CÁLCULOS.ESTIMULANTE DA SECREÇÃO BILIAR. PARALISIAS DOS MEMBROS.INFLAMAÇÕES DAS VIAS RESPIRATÓRIAS SUPERIORES.PÓLIPOS DA CAVIDADE NASAL.Carvalhinha', '', E'Teucrium Labiatae Sob ponto de vista antroposófico Teucrium marum As folhas dessa planta delicada são muito pequenas e bastante estreitas; o cacho de flores, vermelho claro, ascende a partir dos brotos. O odor das flores maceradas é queimante e picante; o gosto é extremamente apimentado. A ação desta planta, que se esgota no domínio floral ou volátil, se assemelha à do tomilho, mas está deslocada em direção ao metabolismo. Esta planta estimula os processos do fígado, favorece o fluxo da bílis e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Carvalho Comum', E'', '', E'QUERCUS ROBUR L.ADSTRINGENTE,DIARRÉIAS INTENSAS E CATARROS GASTRINTESTINAIS.FRIEIRAS, QUEIMADURAS, HEMORRÓIDAS E DOENÇAS DA PELE (INCLUINDO MICOSES).DESINFETANTES E VULNERÁRIAS.Carvalho comum', '', E'Quercus robur L. Fagaceae Árvore de grande desenvolvimento que, se dispuser de umidade, espaço e nutrientes necessários, pode tornar-se gigantesca e durar muito tempo. As folhas são verde-escuras, coriáceas, lobadas, estendendo-se até a base do pecíolo. As flores estaminadas agrupam-se em amentos caídos, as pistiladas apresentam longos pedúnculos axilares. O carvalho-comum dá-se bem em solos ricos e profundos, sobretudo na planície. Os carvalhos sempre foram cultivados e apreciados como símbolos', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Castanheiro Da Índia', E'', '', E'AESCULUS HIPPOCASTANUM L.AFECÇÕES CARDÍACAS OU CIRCULATÓRIAS.ATUAM SOBRE A RESISTÊNCIA DAS PAREDES VENOSAS, AUMENTAM A PERMEABILIDADE DAS CORONÁRIAS E AFETAM IGUALMENTE A COAGULAÇÃO SANGUÍNEA.IFLAMAÇÕES DAS VIAS RESPIRATÓRIAS SUPERIORES (EXPECLORANTES), DAS VARIZES E EDEMA ADVINDCastanheiro da índia', '', E'Aesculus hippocastanum L. Hippocastanaceae  A família das hipocastenáceas tem menos de vinte espécies. A maior parte pertencente ao género Aesculus e outras duas ao gênero Billia, nativo da America Central. O gênero Aesculus consta de 13 espécies de árvores e arbustos deciduos que ocorrem no sudeste da Europa, Asia oriental e América do Norte; Aesculus hippocastanum é nativo nos Bálcans e Himalaias. Introduzido na Europa no século XVI, o castanheiro da Índia têm unta bonita folhagem que fica de', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Catinga De Mulata', E'', '', E'TANACETUM VULGARE L., TANACETO, ATANÁSIA-DASBOTICAS, TASNEIRA, PALMA, ERVA-CONTRAVERMES, ERVA-DOS-VERMES E ERVA-LOMBRIGUEIRA', '', E'', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cavalinha', E'', '', E'EQUISETUM SPP.,MILHO-DE-COBRA, COLA-DE-CAVALO, RABO-DE-CAVALO E ERVA-CANUDOPROBLEMAS RENAIS E OBESIDADE. É TAMBÉM HEMOSTÁTICA.CAVALINHA', '', E'Nome científico: Equisetum spp. Família: Equisetaceae. Origem: América do Sul. Sinonímia: milho-de-cobra, cola-de-cavalo, rabo-de-cavalo e erva-canudo.  Descrição: o nome cavalinha é dado, indistintamente, a todas as espécies dessa família. A seguinte descrição se refere a E. pyramidale: caule fistuloso, ereto, sulcado, articulado, áspero, verde-escuro, rígido, bainha cilíndrica, com folhas reduzidas a escamas, ramos densamente verticilados e parte reprodutiva (estróbilo) em espiga apiculada.  C', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cebolinha', E'', '', E'ALIUM FISTULOSUM L., CEBOLINHA FRANCESAESTIMULANTE, DIURÉTICA E ANTI-SÉPTICA. AFECÇÕES RESPIRATÓRIASCebolinha', '', E'Nome científico: Alium fistulosum L. Espécie anual, da família Liliaceae, originária da Europa, sendo bastante conhecida como cebolinha francesa. Apresentam propriedades estimulante, diurética e anti-séptica. Os bulbos são utilizados nas afecções respiratórias. Na culinária, é empregada como condimento, sendo rica em vitaminas A e C. Multiplica-se por sementes e bulbilhos, que são plantados em local definitivo.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cenoura', E'', '', E'DAUCUS CAROTA L.VITALIZAÇÃO DOS ÓRGÃOS SENSORIAISCenoura', '', E'Daucus carota L. Umbelliferae (Apiaceae) Sob ponto de vista antroposófico O gênero Daucus possui um grande número de espécies, e devido á essa plasticidade, os botânicos tem grandes dificuldades com a classificação das espécies deste género. A cenoura é originária da região mediterrânea. Ela cresce preferencialmente nos campos secos, se bem que um pouco úmidos, sobretudo nos solos arenosospantanosos. Luz, sílica, água, húmus, calor: A mistura harmoniosa desses elementos confere às plantas deste', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Centela', E'', '', E'CENTELLA ERECTA (L.F.) FERNALD.CICATRIZANTE, COMBATE A CELULITE. ANTIDEPRESSIVACentela', '', E'Nome científico: Centella erecta (L.F.) fernald.  Planta herbácea, perene, da família Umbelliferae, originária da América Tropical. As folhas, cicatrizantes, combatem a celulite e estimulam o metabolismo das gorduras. A planta é antidepressiva ,e potencializa a capacidade de memorização em animais de laboratório. Esta espécie apresenta os mesmos princípios ativos da Centella asiatica, tendo alguns componentes em concentração superior. Loção para celulite: colocar duas xícaras da erva picada era', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cerefólio', E'', '', E'ANTHRISCUS CEREFOLIUM HOFFMANNDIGESTIVA, DEPURATIVA E ESTIMULANTE. PROBLEMAS DE ESTÔMAGO, BEXIGA E GOTA. ENFERMIDADES NERVOSAS. NFLAMAÇÕES DOS OLHOS E PARA AUMENTAR A SECREÇÃO LÁCTEACerefólio', '', E'Nome científico: Anthriscus cerefolium Hoffmann  Espécie herbácea, anual, da família urnbelliferae, originária da Ásia. Apresenta propriedades digestiva, depurativa e estimulante. As folhas são indicadas no tratamento de problemas de estômago, bexiga e gota. As sementes são empregadas em enfermidades nervosas. É também utilizada para inflamações dos olhos e para aumentar a secreção láctea em mulheres em período de lactação. Na culinária, é considerada um condimento de valor pelo seu aroma agradá', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cereus', E'', '', E'CEREUS GRANDIFLORUS MILL.MALES DO CORAÇÃO, RESFRIADO, BRONQUITE CRÔNICA, FEBRES COM CATARRO, CORIZA, OLHOS. PALPITAÇÕES DO CORAÇÃOCereus', '', E'Nome científico: Cereus grandiflorus Mill.  É uma espécie tropical perene, da família Cactaceae, com caule trepador, de seção transversal com três vértices. Suas flores exalam aroma suavíssimo, lembrando a baunilha. Indicada para males do coração, resfriado, bronquite crônica, febres com catarro, coriza, olhos salientes e menstruação dolorosa. A cactina é um princípio ativo extraído das flores e dos gomos desta planta e tem sido empregada contra as palpitações do coração; ela aumenta a força das', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Chambá', E'', '', E'JUSTICIA PECTORALIS VAR. STENOPHYLLA LEONARDBRONQUITE E TOSSEChambá', '', E'Nome científico: Justicia pectoralis var. stenophylla Leonard  Trata-se de urna espécie perene, da família Acantaceae com caule reptante e ascendente, folhas lanceoladas e com flores em espigas terminais. Originária da América Tropical. Utilizada n combate de bronquite e tosse. As folhas são empregadas ern infusão, na dosagem de 20 g em 1 litro d''água, tornando-se 3 xícaras (chá) ao dia, ou, ainda, sob a forma de xarope, usando-se 100 g de folhas por litro de caldo xaroposo. Tomar 3 colheres (so', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Chamomila', E'', '', E'CHAMORNILLA RECUTITA (L.) RAUSCHERT, CAMOMILA-DA-ALEMANHA, MANÇANILHA E MATRICÁRIA.TEM SUAVE AÇÃO CALMANTE. É ANTIINFLAMATÓRIO, ANALGÉSICA,ANTIESPASMÓDICA, CARMINATIVA. CIATRIZANTE E EMEMAGOGA.CHAMOMILA', '', E'Nume científico: Chamornilla recutita (L.) Rauschert  Família: Compositae. Origem: Europa. Sinonímia: camomila-da-alemanha, mançanilha e matricária.  Descrição: erva anual, com até 0,40 m de altura; folhas muito divididas; inflorescëncias em capítulos terminais, com centro amarelo constituído por flores tubuladas e periferia formada por flores liguladas brancas, que ficam pendentes quando a inflorescéncia amadurece; frutos aquénios; caule glabro, verde, ereto, ramificado e delicado.  Constituint', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Chapeu De Couro', E'', '', E'ECHINODORUS MACROPHYLLUS (KUNTH.) MICH.,CHÁ-DE-CAMPANHA, ERVA-DEBUGRE, ERVA-DO-PÃNTANO,CHÁ-DE-MINEIRO, CONGONHA-DO-BREJO, ERVA-DO-BREJO E CHÁ-DE-POBREDIURÉTICO, ANTIOFÍDIEE, DEPURATIVO, E ANTIREUMÁTICO.. CONTRA DOENÇAS RENAIS, DAS VIAS URINÁRIAS E INDICADO AINDA NO TRATAMENTO DE ERUPÇÕES DE PELE (USO INTERNO).CHAPEU DE COURO', '', E'Nome científico: Echinodorus macrophyllus (Kunth.) Mich. Família: Alismataceae. Origem: Nativa do Brasil. Sinonímia: chá-de-campanha, erva-debugre, erva-do-pãntano,chá-de-mineiro, congonha-do-brejo, erva-do-brejo e chá-de-pobre.  Descrição: planta herbácea, folhas simples, grandes, ovais a cordiformes e inteiras, verdes, nervuras principais curvas, salientes na face inferior, pecíolo longo, sulcado longitudinalmente, flores reunidas em inflorescências eretas.  Constituintes químicos principais:', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Chelidonia', E'', '', E'CHELIDONIUM MAJUS L.,QUELIDÔNIA, ERVA-DAS-VERRUGAS, ERVA-DOS-CALOS, FIGATIL, GRANDE QUELIDÕNIA E CELIDÔNIA-MAIOR.ELIMINA VERRUGAS DA PELE E CALOS, AJUDA TAMBÉRN NO TRATAMENTO DE ÚLCERAS ESCROFULOSAS OU ESCORBÚTICAS E DE FERIDAS VELHAS. APRESENTA AINDA AÇÃO SEDATIVA LOCAL.CHELIDONIA', '', E'Nome científico: Chelidonium majus L. Família: Papaveraceae. Origem: Europa. Sinonímia: quelidônia, erva-das-verrugas, erva-dos-calos, figatil, grande quelidõnia e celidônia-maior.  Descrição: planta herbácea, ereta, com 15 a 30 cm de altura; folhas alternas pinatissectas; inflorescências em umbelas simples, flores amarelas com 2 a 3 sépalas, 4 pétalas e muitos estames; frutos tipo cápsula linear, de 3 a 6 cm de comprimento.  Constituintes químicos principais: quelidonina, queleritrina, sanguina', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Choupo Negro', E'', '', E'POPULUS NIGRA L.DESINFETANTES E DIURÉTICAS.CATARROS DAS VIAS RESPIRATÓRIAS SUPERIORES.DORES ARTICULARES DE ORIGEM REUMATISMAL.DERMATITES. AS HEMORRÓIDAS, AS DORES DA GOTACHOUPO NEGRO', '', E'Populus nigra L. Salicaceae  Árvore de grande desenvolvimento, com ramos inicialmente castanhos e depois cinzento-esverdeados, casca enrugada e cinzento-escura. As folhas pecioladas são cordifonnes, cuneiformes na base, e nas suas axilas originam-se gemas viscosas. O choupo é uma planta com flores dióicas; flores masculinas e femininas estão agrupadas em amemtos que desabrocham na Primavera. Os frutos são cápsulas cobertas de penugem. É uma espécie nativa em meios úmidos, ao longo de cursos de á', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cicuta Aquática', E'', '', E'CICUTA VIROSA L.ANTIESPASMÓDICA, ANTIEPILÉPTICA, NAS CÃIBRAS TETANIFORMES DO MAXILAR,ANGINA DO PEITO, E ALGUMAS VEZES TAMBÉM NA COQUELUCHE.DISMENORRÉIA.DORES DA GOTA OU DO REUMATISMO E ATÉ MESMO DO CÂNCER.Cicuta aquática', '', E'Cicuta virosa L. Umbelliferae (Apiaceae) Sob ponto de vista antroposófico  Na Cicuta aquática, o elemento aéreo penetra de maneira muito intensa no elemento aquoso, dominando este último. O elemento aéreo torna as folhas da Cicuta muinto finas, fazendo destas, instrumentos importantes para o ar e a luz, criando um espaço próprio á explosão do processo floral. Este elemento escava tanto no caule, como no rizoma, que submerge na terra, lacunas ceríferas. Na cicuta o elemento aéreo domina o aquoso,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cicuta Maior', E'', '', E'CONIUM MACULATUM L.DORES MUSCULARES,ASMA.SUPOSITÓRIOS ANALGÉSICOS EFICAZES CONTRA AS DORES DA PRÓSTATA,DOS TUMORES OU DAS AFECÇÕES NERVOSAS.Cicuta maior', '', E'Conium maculatum L. Umbelliferae (Apiaceae)  Planta herbácea bienal com caule alto, canelado e ramificado, maculado de violeta na base e apresentando folhas alternas, bipenatissectas a tripenatissectas. Os pecíolos foliares formam uma bainha membranosa. As ramificações têm umbelas compostas terminais, formadas por diminutas flores brancas. Os frutos são diaquênios. Toda a planta é extremamente venenosa e, quando se machucam as folhas ou a planta murcha, liberta-se um odor de rato. A cicuta cresc', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cidreira De Arbusto', E'', '', E'LIPPIA ALBA (MILL) N.E. BROWN., ERVA -CIDREIRA-DE-ARBUSTO, ERVA-CIDREIRA-DO-CAMPO, ALECRIM-DO-CAMPO, ALECRIM-SELVAGEM, CIDREIRA-BRAVA E FALSA-MELISSA.ANTIESPASMÓDICO, ESTOMÁQUICO, CARMINATIVO, CALMANTE, DIGESTIVO. COMBATE, AINDA, A INSÔNIA E A ASMA.CIDREIRA DE ARBUSTO', '', E'Nome científico: Lippia alba (Mill) N.E. Brown.  Família: verbenaceae. Origem: América do Sul. Sinonímia: erva -cidreira-de-arbusto, erva-cidreira-do-campo, alecrim-do-campo, alecrim-selvagem, cidreira-brava e falsa-melissa.  Descrição: arbusto perene, muito ramificado dicotomicamente; folhas oblongo-agudas, opostas; flores róseovioláceas, reunidas em capítulo axial. Os ramos novos são pubescentes e os velhos, glabros. Atinge até 3 m de altura. Cheiro semelhante ao da erva-cidreira e do capim-sa', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cila', E'', '', E'SCILLA MARITIMADIURÉTICA. TOSSE ESPASMÓDICA.FAVORECE A SECREÇÃO BRONQUIAL E AUMENTA A SUDORESE.CARDIOTÔNICA.Cila', '', E'Scilla maritima , Urginea maritima Liliaceae Sob ponto de vista antroposófico  A cila tem como habitat o solo árido, arenoso e salgado das praias quentes e ensolaradas. Vive, portanto, em um ambiente mineral salino. Como Liliácea, guarda em si processos cósmicos de natureza etérica: um vegetal com enorme vitalidade que cresce em um solo salino arenoso castigado pelo calor do sol: O processo etérico-vital da cila vence a tendência salino-mineralizante.  O bulbo da cila é verde, suas folhas bulbar', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cimicífuga', E'', '', E'CIMICÍFUGA RACEMOSA, ACTAEA RACEMOSAAMENORRÉIAS,DISMENORRÉIAS,DEVOLVER AO ÚTERO, APÓS O PARTO, A SUA ATIVIDADE RÍTMICA.Cimicífuga', '', E'Cimicífuga racemosa , Actaea racemosa Ranunculáceae  Esta pequena e alta planta, com suas inflorescências bastante longas em forma de velas, cresce nas florestas montanhosas da Europa, Ásia e América do Norte, em locais sombreados, úmidos, mas que recebem uma quantidade suficiente de luz.  Esta planta exprime a transição das forças da Primavera para o Verão. Ela atinge 2 metros de altura, e possui folhas 2 vezes penadas e longamente pecioladas. Seu cacho de flores é bastante alongado, nascida da', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Cabeludo', E'', '', E'MIKANIA HIRSUTISSIMA D.C.DIURÉTICO, ANTIALBUMINÚRICO, AFECÇÕES RENAIS E NAS VIAS URINÁRIAS.Cipó cabeludo', '', E'Nome científico: Mikania hirsutissima D.C.  Espécie trepadeira, perene, da família Compositae, nativa da Mata Atlãntica. Contém óleos essenciais, onde se destaca o alfa curcumeno e espatulenol, flavonóides com propriedades diuréticas. Com a planta inteira preparara-se tinturas ou infusões que são usadas como diurético, antialbuminúrico, nas afecções renais e nas vias urinárias. Multiplica-se por sementes e estacas. Ç', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Carijó', E'', '', E'DAVILLA RUGOSA POIR., CIPÓ-CABOCLOLAMATÓRIO, ANIÚCERA E ESTIMULANTE DO SISTEMA NERVOSO.ADSTRIGENTE, DIURÉTICA, COLAGOGO, USADA NAS ORQUITES, EDEMAS, LINFITE E NAS ICTERÍCIAS.TRATAMENTO DE FERIMENTOS, E, AINDA, EMPREGADA EM BANHOS CONTRA A INCHAÇÃO DAS PERNAS E DO ESCROTO.Cipó carijó', '', E'Nome científico: Davilla rugosa Poir.  Espécie trepadeira, perene, da família Dilleniaceae, que ocorre espontaneamente no Brasil. Também conhecida como cipó-caboclo. os caules são usados na medicina popular como antiinflamatório, aniúcera e estimulante do sistema nervoso. As folhas tem sabor adstringente e levemente amargo, em decocçao (30 g da erva em 1/2  litro de água). É adstrigente, diurética, colagogo, usada nas orquites, edemas, linfite e nas icterícias. Pode ser usada no tratamento de fe', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Chumbo', E'', '', E'CUSCUTA CORNICULATA ENGELM, FIOS-DE-OUROTOSSE E PROBLEMAS RESPIRATÓRIOS.ANTICATARRAL.AFECÇÕES DA GARGANTA, AFECÇÕES DA GARGANTA,r', '', E'Cipó chumbo  Nome científico: Cuscuta corniculata Engelm  Planta parasita do Brasil, pertencente à família Convolvulaceae, também conhecida corno fios-de-ouro. Caules filiformes, volúveis, de cor amarelo-alaranjada, de sabor amargo. Toda a planta é usada contra tosse e problemas respiratórios. O suco é considerado anticatarral. A infusao para uso interno é feita com 1 colher (sopa) de erva fresca para 1 xícara (chá) de água. Nas afecções da garganta, fazem-se gargarejos com o decocto da planta.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Cravo', E'', '', E'TYNANTHUS SP.ESTIMULANTE GERAL.CARMINATIVO, ANTIDIARRÉICO, ESTOMÁQUICO.AFRODISÍACO Cipó cravo', '', E'Nome científico: Tynanthus sp.  Planta trepadeira, perene, da família Bignoniaceae, que cresce espontaneamente no Brasil. Entre os princípios ativos, encontram-se óleos essenciais, glicosídeos e alcalóides. O caule, de cor avermelhada e muito aromático, apresenta ação estimulante geral. A tintura é feita, utilizando-se 10 g do caule picado em 1 litro de álcool de cereais. Tornar 10 gotas (diluídas em água), 3 vezes ao dia, durante 10 dias. É carminativo, antidiarréico, estomáquico (de cocçáo do', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Curatombo', E'', '', E'CHINOLAENA SP.SEDATIVO  PARA CONTUSÕES , TRAUMATISMOS E REUMATISMOCipó curatombo', '', E'Nome científico: Chinolaena sp. Espécie nativa da Mata Atlântica, perene, pertencente à família Compositae. Sedativo eficaz utilizado internamente para dores em qualquer região do corpo, tanto as provocadas por contusões e traumatismos quanto as de origem reumática. Multiplica-se por sementes. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó Mil Homens', E'', '', E'ARISTOLOCHIA SP.,JARRINHA, PAPO-DE-PERU, SAPATINHO=DE-JUDEU, ANGELICÓ E CIPÓ-MILONGUEDEPURATIVO, SEDATIVO E ESTIMULANTE DOS RINS, DO FÍGADO E CORAÇÃO. CLOROSE, ANOREXIA, COMO ESTOMACAL, PARA CISTITE, CONVULSÕES, AMENORRÉIA, CORNO CARMINATIVO E NAS FEBRES INTERMITENTES DA MALÁRIA.Cipó mil homens', '', E'Nome científico: Aristolochia sp. Planta perene, da família Aristolochiaceae, nativa do Brasil, com tronco subterrãneo bem desenvolvido, amarga e aromática. As flores exalam odor fétido para atrair moscas varejeiras que a polinizam. Há muitas espécies do gênero, conhecidas também como jarrinha, papo-de-peru, sapatinho=de-judeu, angelicó e cipó-milongue. Era empregada pelos índios contra veneno de cobras. o decocto das raízes é usado como depurativo, sedativo e estimulante dos rins, do fígado e c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cipó São João', E'', '', E'PYROSTEGIA VENUSTA MIERS.,FLOR DE SÃO JOÃOTÔNICA E ANTIDIARRÉICA.Cipó são João', '', E'Nome científico: Pyrostegia venusta Miers.  Espécie trepadeira, da família Bignoniaceae, nativa do Brasil, semilenhosa, perene, com flores alaranjadas. Também conhecida como flor de são joão. As folhas, na forma de infusão, são utilizadas como tônica e antidiarréica. Floresce normalmente nos meses de junho e julho. Multiplica-se por sementes e por estacas, que enraizam melhor se cortadas após o florescimento. É considerada tóxica para bovinos. y', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Clematis', E'', '', E'CLEMATIS RECTA L.AFECÇÕES GENITAIS MASCULINAS, TAIS COMO ORQUITE, EPIDIDIMITE, INCHAÇÃO DOS TESTÍCULOS E ENDURECIMENTO DOS MESMOS.Clematis', '', E'Clematis recta L. Ranunculaceae sob ponto de vista antroposófico  É uma planta não trepadeira que atinge a altura de cerca de um metro. É um "vegetal do verão". A Clematis recta segue o curso dos grandes rios "Elba, Vístula, Danúbio" e isso está de acordo com a afinidade geral das Ranunculáceas para com a água. Nestas regiões onde a planta nasce, ela escolhe os terrenos calcários, declives dos bosques e locais rochosos. Surgindo a partir de um rizoma nodoso, ela oscila entre a consistência herbá', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Coca', E'', '', E'ERYTHROXYLUM COCAANESTESIA LOCAL,ESTIMULA O SISTEMA NERVOSO CENTRAL.ALIVIAR FADIGA E FOME.Erythroxylum coca Erythroxylaceae', '', E'O gênero Erythroxylum tem cerca de 250 espécies de árvores tropicais e arbustos, encontrados principalmente nas Americas e Madagáscar. Erythroxylum coca é nativa nas altas altitudes dos Andes oriental. Extratos de Coca proveram a base da bebida Coca-Cola até o ano 1902, quando a cocaína foi proibida nos E.U.A. e passaram a ser usados extratos isentos de cocaina. O nome Erythroxylum deriva do grego "erylhros", vermelho, e ..xylon, madeira. frequentemente, embora incorretamente, o nome é pronuncia', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Coentro', E'', '', E'CORIANDRUM SATIVUM L.CARMINATIVO. ESTIMULANTE. ESTOMÁQUICO E DEPURATIVO, COMBATE INFLAMAÇÕES INTESTINAIS, EXERCENDO AÇÃO DESINFETANTE SOBRE OS INTESTINOSCOENTRO', '', E'Nome científico: Coriandrum sativum L. Família: Umbelliferae.  Origem: Europa Meridional. Sinonímia: sem referências.  Descrição: planta glabra (sem pêlo), até 60 cm de altura; folhas inferiores diferentes das superiores; flores brancas ou róseas, pequenas. As folhas e flores têm forte odor.  Constituintes químicos principais: óleo essencial contendo coriandrol, pineno, borneol, geraniol, cimeno, d-linalol, limoneno, terpinol; apresenta também ácidos acético e oxálico.  Indicações: carminativo.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Colônia', E'', '', E'ALPINIA SPECIOSA SCHUM.DIURÉTICA E ANTIHIPERTENSIVA.Colônia', '', E'Nome científico: Alpinia speciosa Schum.  Espécie herbácea, perene, da família Zingiberaceae, de grande porte (2-3m de altura). Apresenta inflorescëncia grande, com flores branca-rosada, muito aromática. As folhas, na forma de infusão (1 folha média por 1 litro de água) tem ação diurética e antihipertensiva. Este chá, mantido na geladeira e renovado a cada dia, deve ser tornado pelo hipertenso como se fosse água. Multiplica-se por divisão de rizomas. Õ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cominho', E'', '', E'CARUM CARVI L.ANTIESPASMÓDICO E SUA ATIVIDADE NOS GASES DO TRATO DIGESTIVO,EMENAGOGA.COMBATE OS ESPASMOS UTERINOS, A HIPOCONDRIA E A HISTERIA.AEROFAGIA.Cominho', '', E'Carum carvi L. Umbelliferae (Apiaceae) Sob ponto de vista antroposófico Nesta planta, assim como no anis e no funcho, são os frutos que constituem a parte utilizada conto condimento ou como medicamento. O gênero Carum compreende 22 espécies, que crescem no norte das regiões temperadas do velho mundo, assim como na Califórnia e no Chile. AS espécies americanas possuem raizes nodosas e tuberosas. O Carum Carvi, cominho, se encontra em toda a Europa ao norte dos Alpes até o norte da Noruega. Encont', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Compostas', E'', '', E'COMPOSTAS - COMPOSITAE (ASTERACEAE)DEPENDE DA ESPÉCIECompostas - Compositae (Asteraceae)', '', E'Motivo Formador e Forças Terapêuticas (Sob ponto de vista antroposófico) "Durante uma excursão na montanha, depois que as sinuosidades do caminho nos permitiram observar as diferentes partes da paisagem, atingimos finalmente o cume, e um olhar nos permitiu condensar numa vista única as nossas visões parciais e provisórias É o que acontece com o botânico, após ter estudado numerosas familias de plantas, quando chega na família mais evoluída e melhor organizada, a das compostas. Essa família recap', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Confrei', E'', '', E'SVMPHYTUM SP., CONSÓLIDA-DO-CÁUCASO , ORELHAS-DE-ASNO, ERVA- DO-CARDEAL, LÍNGUA-DE-VACA E LEITE-VEGETAL-DA-RÚSSIA.HEMOSTÁTICO, ANTIINFLAMATÓRIO, CICATRIZANTE. UTILIZADO PARA FAVORECER O CRESCIMENTO DE TECIDOS NOVOS EM ULCERAÇÕES, FERIDAS E CORTES, FRATURAS E AFECÇÕES ÓSSEAS. ATUA, AINDA, COMO INDUTOR DA PRODUÇÃO CALCÁRIA.CONFREI', '', E'Nome científico: Svmphytum sp. Família: Boraginaceae. Origem: Ásia. Sinonímia: consólida-do-cáucaso , orelhas-de-asno, erva- do-cardeal, língua-de-vaca e leite-vegetal-da-rússia.  Descrição: planta vivaz, rizomatosa, com parte aérea áspera e pilosa; flores brancacentas, amarelas ou violáceas; folhas basais; caule oco.  Constituintes químicos principais: alantoína (cicatrizante e hidratante) e alcalóides pirrolizidínicos (sinfitina e equimidina), taninos, mucilagens, colina, vitaminas, minerais e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Congonhas De Bugre', E'', '', E'CASEARIA SYLVESTRIS SWARTZ.,CAFEZINHO DO MATO E GUAÇATONGACICATRIZANTE, EMAGRECEDORA, DEPURATIVA, PICADAS DE INSETOS, AFECÇÕES CARDÍACAS,COMBATE DO COLESTEROLCongonhas de bugre', '', E'Nome científico: Casearia sylvestris Swartz.  Espécie arbórea de pequeno porte, da família Flacourtiaceae, nativa da Mata Atlântica. Também conhecida corno cafezinho do mato e guaçatonga. Na forma de decocção ou tintura, as folhas são usadas como cicatrizante, emagrecedora, depurativa, picadas de insetos, afecções cardíacas e, ainda, ajuda no combate do colesterol. Contém óleo essencial, tanino, resina, antocianosídeo e saponina. Multiplica-se por semente ou mudas coletadas na mata, desenvolvend', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Conizina Do Canadá', E'', '', E'CONYZA CANADENSIS (L.)ADSTRINGENTE.DIARRÉIA, HEMORRAGIA, MENSTRUAÇÃO EXCESSIVA, HEMORRÓIDAS, DESORDENS RENAIS,ECZEMA E OUTROS PROBLEMAS DE PELE.Conizina do canadá', '', E'Conyza canadensis (L.) CRONQ. syn.: Erigeron canadensis L. Asteraceae (Compositae) Cerca de cinqüenta espécies anuais e perenais compõem o gênero Conyza, nativo na América do Norte e amplamente naturalizado na Europa, Ásia, Austrália e várias ilhas do Pacífico. Conyza canadensis é uma erva daninha comum, encontrada em partes meridionais do Canadá, ao longo dos E.U.A. e na América tropical. Em 1653 foi registrado no Jardim Botânico de Blois (França do norte) e em aproximadamente 30 anos se esparr', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Consólida Real', E'', '', E'DELPHINIUM CONSOLIDA L.PARASITICIDA PARA PIOLHOS DA CABEÇA.DIURÉTICAS, VERMÍFUGAS E CATÁRTICAS.Consólida real', '', E'Delphinium consolida L. syn.: Consolida regalis S. F. GRAY Ranunculaceae O gênero Delphinium consta de umas 250 espécies bienais e perenais, encontradas nas regiões temperadas do norte e montanhas africanas centrais; Delphiniums são de perto relacionados aos acônitos (Aconitum). Ambos são venenosos, mas extensamente cultivados por suas belas flores azuis. O nome Delphinium vem do grego "delphis", golfinho, devido que as flores de algumas espécies se assemelham a esse animal. Delphinium consolida', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Copaíba', E'', '', E'COPAIFERA LANGSDORFFII DESF.,PAU D''ÓLEOANTIINFLAMATÓRIO,DISENTERIAS, BRONQUITE E SINUSITE, INFLAMAÇÕES DA GARGANTA, RIOS E BEXIGA (CISTITE),DERMATOSES. ANTI-SÉPTICO DAS VIAS RESPIRATÓRIAS E URINÁRIAS.CICATRIZASTECopaíba', '', E'Nome científico: Copaifera langsdorffii Desf. Espécie da família Leguminosas, também chamada de pau d''óleo, é uma árvore brasileira com até 13 m de altura. o óleo extraído do caule da copaíba, em uso interno, é antiinflamatório. É também usado contra disenterias, bronquite e sinusite, inflamações da garganta, rios e bexiga (cistite) e para todas as dermatoses. É poderoso anti-séptico das vias respiratórias e urinárias. Externamente é cicatrizaste e pode ser passado 2 vezes ao dia sobre feridas e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cordao De Frade', E'', '', E'LEONOTIS NEPETAEFOLIA R. BR., CORDÃO-DE-SÃO-FRANCISCO E CATINGA-DE-MULATA.CONTRA A ASMA E DISÚRIA, ANTIESPASMÁDICO. É ANTI-HEMORRÁGICO UTERINO, DIURÉTIÇO, FEBRÍFUGO, ESTOMÁQUICO, BÉQUICO, PEITORAL; AJUDA NA ELIMINAÇÃO DO ÁCIDO ÚRICO, ALÉM DE SER TÔNICO E SUDORÍFERO (USO INTERNO). É AINDA ANTIREUMÁTICO, PARA ARTRITES E COMO VULNCordão-de-frade', '', E'Nome científico: Leonotis nepetaefolia R. Br.  Família: Labiatae. Origem: África Tropical e Meridional e índias orientais.  Sinonímia: cordão-de-são-francisco e catinga-de-mulata.  Descrição: erva de até 1,5 m de altura, anual, aromática; caule quadrangular, folhas opostas oval lanceoladas;flores alaranjadas dispostas em glomérulos nas axilas das folhas; os frutos são quatro grãos pretos trapezóides.  Constituintes químicos principais: heterosídíos cianogênicos e saponínicos, gomas, mucilagens,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Coridália Oca', E'', '', E'CORYDALIS CAVA L.ANALGÉSICA QUE ESTIMULA A CIRCULAÇÃO, CONTROLA ESPASMOS E NÁUSEA, E TEM PROPRIEDADES SEDATIVAS E ANTI-BACTERIANAS.PERTURBAÇÕES NERVOSASCoridália oca', '', E'Corydalis cava (L. emend. MILL.) SCHWEIGG. et KOERTE Papaveraceae  Aproximadamente 300 espécies anuais e perenais, geralmente tuberosas, compõem o gênero Corydalis, amplamente distribuído pela zona temperada do norte e regiões tropicais montanhosas. Corydalis solida é encontrada em bosques na Europa e Ásia ocidental. Embora relacionada com as papoulas, as Corydalis são bastante diferentes na aparência, com folhas parecidas com as de samambaia e flores tubulares, por vezes lembrando as das labiat', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cravagem Do Centeio', E'', '', E'CLAVICEPS PURPUREA (FR.) TUL.CONTRAÇÃO DOS MÚSCULOS LISOS DO ÚTERO,ATUAM COMO DEPRESSORES DO SISTEMA SIMPÁTICO, CAUSAM VASOCONSTRIÇÃO DO SISTEMA VENOSO PERIFÉRICO E AUMENTAM A TENSÃO ARTERIAL.Cravagem do Centeio', '', E'Claviceps purpurea (Fr.) Tul. Clavicipitaceae Cogumelo parasita ascomicete que vive geralmente nas espigas do centeio. Na altura da floração do centeio as curtas fibras micelianas da cravagem atravessam e enchem completamente os ovários do cereal. No exterior, essas fibras produzem, por estrangulamentos sucessivos, pequenos conídios, ao mesmo tempo que um líquido claro e açucarado é segregado na superfície. Este líquido atrai os insetos que transportam depois o cogumelo para vegetais sadios. Os', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cravo De Defunto', E'', '', E'TAGETES ERECTA L.SUDORÍFERO, ANTI-REUMÁTICO, AFECÇÕES UTERINAS, RESFRIADOS, BRONQUITE E TOSSE.VERMÍFUGO.LAXATIVO.Cravo de defunto', '', E'Nome científico: Tagetes erecta L.  Planta herbácea, anual, da família Compositae, originária da América do Sul. A infusão das folhas e flores são empregadas como sudorífero, anti-reumático, afecções uterinas, resfriados, bronquite e tosse. O óleo dele extraído é vermífugo. Suas raízes e sementes possuem efeito laxativo. Multiplica-se por sementes que podem ser semeadas o ano todo, principalmente na primavera e verão. Em consórcio com outras culturas, evita o ataque de nematóides. É utilizada ta', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cumaru', E'', '', E'TORRESEA CEARENSIS FR. ALL.BRONCODILATADORA, RESFRIADOS, TOSSE, BRONQUITE, ASMA E AFECÇÕES PULMONARES.PERTURBAÇÕES DIGESTIVAS, CÓLICAS INTESTINAIS E UTERINAS.ANTIINFLAMATÓRIACumaru', '', E'Nome científico: Torresea cearensis Fr. All.  Árvore da família Leguminosas, nativa do Brasil, também conhecida por imburana ou amburana. As cascas e sementes, na forma de tintura, constituem ótimo peitoral (atividade broncodilatadora), usado contra resfriados, tosse, bronquite, asma e afecções pulmonares de modo geral. O decocto das sementes é popularmente indicado para as perturbações digestivas, cólicas intestinais e uterinas. Sua atividade antiinflamatória, dada pela presença de cumarinas, t', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Cúrcuma', E'', '', E'CURCUMA AROMATICAICTERÍCIA, HEMORRAGIA NASAL, HEMORRAGIA INTERNA, MENSTRUAÇÃO DOLOROSA, CHOQUES, DORES DE TÓRAX ASSOCIADAS COM BAIXA ENERGIA DO FÍGADO, E ANGINA.ADSTRINGENTE,PROBLEMAS DIGESTIVOS E DE PELE, CIRCULAÇÃO DEFICIENTE, TUMORES UTERINOS, ICTERÍCIA, DOENÇAS DO FÍGCúrcuma', '', E'Curcuma aromatica Zingiberaceae Cerca de quarenta espécies de plantas perenes pertencem ao gênero Curcuma, encontradas na Ásia tropical e Austrália. O nome vem de "kurkum", o nome árabe para estas plantas. Muitas espécies têm rizomas grandes ou tubérculos e são usados como especiarias, fontes de amido e corantes. Curcuma longa é um aromatizante e corante comumente usado na culinária Asiática. Também existem muitos registros de usos medicinais destas plantas, especialmente na China, Índia e Indon', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Dedaleira', E'', '', E'DIGITALIS PURPUREA L.FALHAS CARDÍACAS, PARA DIMINUIR A PULSAÇÃO, REGULARIZAR UMA ATIVIDADE CARDÍACA ARRÍTMICA OU INSUFICIENTE, ASSIM COMO EM CASOS DE HIPERTROFIA CARDÍACA.DIURÉTICAS.Dedaleira', '', E'Digitalis purpurea L. Scrophulariaceae Planta herbácea bienal com caule alto, ereto e terminado por um belo cacho de flores violetas. No primeiro ano apenas se forma uma roseta de folhas; no segundo, a haste que suporta a inflorescência. As flores são grandes, campanuladas, violeta ou brancas, maculadas de violeta no interior. O fruto é uma cápsula. É uma espécie dos prados florestais europeus, também das clareiras, sobretudo em regiões montanhosas. É também uma planta ornamental muito apreciada', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Dente De Leão', E'', '', E'TARAXACUM OFFICINALE WEBER., TARAXACO,ALFACE-DE-CÃO, SALADA-DE-TOUPEIRA E AMARGOSA.TÔNICO, HIPOGLICEMIANTE, APERIENTE. COMBATE O EOLESTERO.1 E O ÁCIDO, ÚRICO. É FEBRIFUGO, DEPURATIVO, LAXANTE, SUAVE, DIURÉTICA E AUXILIA NOS PROBLEMAS DO FÍGADO. USADO AINDA CONTRA DIARRÉIA CRÔNICA, ALÉM DE ESTIMULAR A SECREÇÃO DE SUCO GÁSTRICO.DENTE DE LEÃO', '', E'Nome científico: Taraxacum officinale Weber.  Família: Compositae. Origem: Europa, principalmente Portugal.  Sinonímia:taraxaco,alface-de-cão, salada-de-toupeira e amargosa.  Descrição: planta perene, lactescente. Da parte superior da raiz tuberosa brotam as folhas; caule curto; folhas variáveis em tamanho e forma; flores amarelas reunidas em capítulos terminais; frutos aquênios, com aspecto de pára-quedas, que se deslocam mesmo com uma leve brisa. Sabor amargo.   Constituintes químicos principa', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Dictamo Branco', E'', '', E'DICTAMNUS ALBUS L.PRODUZEM CONTRAÇÕES DA MUSCULATURA UTERINA LISA,AFECÇÕES DO TUBO DIGESTIVO, CONTRA OS GASES, PARA REGULARIZAR A EVACUAÇÃO E CONTRA OS PARASITAS INTESTINAIS.DOENÇAS DE PELE, ESPECIALMENTE SARNA E ECZEMA.Dictamo branco', '', E'Dictamnus albus L. syn.: Consolida regalis S. F. GRAY Rutaceae  Seis espécies perenais compunham antigamente o gênero Dictamnus que atualmente é composto apenas por uma espécie. Dictamnus foi denominado por ter aroma semelhante ao de Origanum dictamnus que, por sua vez, provavelmente, foi denominado por sua origem ou dispersão no Monte Dikte, em Creta. Dictamnus albus é uma planta perene com rizoma esbranquiçado e ramificado, caule ereto terminado por um cacho de grandes flores rosadas. As folha', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Digital Lanosa', E'', '', E'DIGITALIS LANATA EHRHPODEROSA AÇÃO CARDIOTÔNICA DE EFEITO RÁPIDO, NOS CASOS AGUDOS DE FALHA CARDÍACA, NA TAQUICARDIA OU NA IRREGULARIDADE DA ATIVIDADE CARDÍACA (POR EXEMPLO, ESTADOS ASMÁTICOS GRAVES).Digital lanosa', '', E'Digitalis lanata Ehrh Scrophulariaceae  Planta herbácea bienal, formando, no decurso do primeiro ano, uma roseta terrestre; no decurso do segundo, um caule alto e ereto com folhas sésseis e lanceoladas. Na axila das folhas superiores formam-se flores campanuladas castanhas e brancas, constituindo uma espiga terminal. O fruto é uma cápsula. A espécie, originária dos países balcânicos, é cultivada em grande e pequena escala para fins medicinais, de preferência às outras espécies, em virtude da sua', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Doce Amarga', E'', '', E'SOLANUM DULCAMARA L.ADSTRINGENTE, REFRESCANTE,ABAIXA A FEBRE E TEM EFEITOS DIURÉTICO, EXPECTORANTE, SEDATIVO E ANTI-REUMÁTICO.FEBRÍFUGO E PARA DOENÇAS DE PELE, CONGESTÃO BRONQUIAL, BRONQUITE CRÔNICA,REUMATISMO, ICTERÍCIA, COLITE ULCERATIVA, PNEUMONIA E DOENÇAS VENÉREAS.Doce amarga', '', E'Solanum dulcamara L. Solanaceae  O gênero Solanum é cosmopolita e consiste de cerca de 1.500 espécies de árvores, arbustos e trepadoras perenes, sendo um dos mais numerosos do mundo. A maioria das plantas do gênero Solanum contém alcalóides tóxicos. Em algumas espécies de Solanum, certas partes são comestíveis enquanto outras partes da mesma planta são muito venenosas, O melhor exemplo conhecido é a batata (Solanum tuberosum) que tem folhagem e frutos venenosos e tem tubérculos comestíveis (embo', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Dorema Ammoniacum', E'', '', E'DOREMA AMMONIACUMANTI-ESPASMÓDICO, ESTIMULANTE, EXPECTORANTE, EMENAGOGO,BRONQUITES CRÔNICAS,ARREBENTAR OS ABCESSOS.Dorema ammoniacum', '', E'Esta planta vive no mesmo habitat que a Ferula assafoetida. Tal como a Assofétida, a Dorema vive em colônias numerosas, formando pequenos bosques, ela cresce até o deserto de Kirghiz. Sua raiz também necessita de pelo menos 5 anos para crescer, é espessa, longa, com grossas ramificações horizontais. A planta é mais alta que um ser humano. O caule que surge possui um diâmetro de mais ou menos 5 cm e se apressa em florir. Um látex muito abundante escorre da raiz. Brotos secundários em forma de can', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Dormideira', E'', '', E'PAPAVER SOMNIFERUM L.SEDATIVO DO SISTEMA NERVOSO CENTRAL,ATENUA AS DORES,ACALMA A TOSSE E REDUZ O PERISTALTISMO INTESTINAL.ANTIESPASMÓDICO DOS MÚSCULOS LISOS,DIARRÉIA,CÓLICAS BILIARESDormideira', '', E'Papaver somniferum L. Papaveraceae  Planta herbácea anual cultivada em pequena e grande escala pelas suas virtudes alimentares, oleaginosas e medicinais. Possui um caule alto e ramificado, com folhas sésseis e ovaladas, terminado por grandes flores brancas e vermelhas. O fruto é uma cápsula. Toda a planta é percorrida por uma rede de laticíferos onde circula látex branco; é venenosa, excetuando as sementes maduras. A indústria farmacêutica usa o suco fresco retirado após incisão das cápsulas ima', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Douradinha Do Campo', E'', '', E'TEM VÁRIAS ESPÉCIES DA FAMÍLIA MALPIGHIACEAE.DIURÉTICA, CONTRA GOTA E CISTITE, EMAGRECEDORA,ESTIMULANTE E DEPURATIVA.Douradinha do campo', '', E'Nome científico: Tem várias espécies da família Malpighiaceae. Planta nativa, perene, de porte arbustivo ou trepador, da família Malpighiaceae. Existem outras espécies, da família Malvaceae, Rubiaceae, Sterculiaceae e Scrophulariaceae que também recebem o nome popular de douradinha-docampo. A infusào das folhas é utilizada como diurética, contra gota e cistite, emagrecedora,estimulante e depurativa. Segundo a medicina popular, esta planta modera os batimentos do coração. Multiplica-se por sement', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Embaúba Branca', E'', '', E'CECROPIA GLAZIOVII SNETH.,ÁRVORE DE PREGUIÇA, UMBAÚBA E EMBAÚBATOSSE, BRONQUITE, COQUELUCHE, PARA ABAIXAR A PRESSÃO ARTERIAL E ENFRAQUECIMENTO DO CORAÇÃO.Embaúba branca', '', E'Nome científico: Cecropia glaziovii Sneth.  Espécie da família Moraceae, também conhecida como árvore de preguiça, umbaúba e embaúba. Árvore de tronco reto, oco, esgalhado, aspecto semelhante a um mamoeiro. Usam-se as raízes e folhas para tosse, bronquite, coqueluche, para abaixar a pressão arterial e enfraquecimento do coração. Pode-se utilizar o suco da raiz diluído em água ou preparara infusão com as folhas (1 colher (sopa) em 1 litro de água fervente). Na medicina popular, o extrato de plant', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Endro', E'', '', E'ANETHUM GRAVEOLENS L.CARMINATIVA, LIMITA A ACUMULAÇÃO DE GASES,CALMANTE PARA OS NERVOS.AÇÃO FAVORÁVEL SOBRE A SECREÇÃO LÁCTEA.Endro', '', E'Anethum graveolens L. Umbelliferae (Apiaceae)  Planta anual com caule ramificado, coberto por uma pruina glauca e terminado por umbelas de flores flavescentes. As folhas lineares, várias vezes penatissectas, são alternas sobre o caule. Os frutos são diaquênios. O endro ou aneto é originário das regiões orientais da bacia mediterrânea e da Ásia ocidental. No passado, era já considerado como uma importante planta medicinal, usada contra tosse, dores de cabeça e no preparo de ungüentos. Atualmente,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Equinácea', E'', '', E'ECHINACEA PURPUREADOENÇAS DE PELE, INFECÇÕES POR FUNGOS, SEPTICEMIA, GANGRENA, FURÚNCULOS,ABSCESSOS, FERIDAS DE DIFÍCIL CURA, INFECÇÕES DA ÁREA RESPIRATÓRIAS SUPERIOR,DOENÇAS VENÉREAS.Equinácea', '', E'Echinacea purpurea Asteraceae (Compositae)  Nove espécies perenes, robustas, rizomatosas, compõem o gênero Echinacea que é nativo dos E.U.A. oriental. Echinacea purpurea é uma de várias espécies, que inclui Echinacea pallida e Echinacea angustifolia, usadas por nativos norte-americanos, principalmente para tratar feridas. Em particular, as tribos das planícies consideraram a Echinacea angustifolia como uma verdadeira panacéia. Esta planta fez parte do repertório Nacional norte-americano (1916- 5', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva Benta', E'', '', E'GEUM URBANUM L.ADSTRINGENTE.CATARRO GASTRINTESTINAL, PARA DETER AS DIARRÉIAS VIOLENTAS,CÓLICAS INTESTINAIS E AS HEMORRAGIAS INTERNAS,VINHOS FORTIFICANTES.GARGAREJOS CONTRA AS INFLAMAÇÕES DA CAVIDADE BUCAL,HEMORRAGIAS DAS GENGIVAS, A DESCARNADURA DOS DENTES E O MAU HÁLITErva Benta', '', E'Geum urbanum L. Rosaceae  Planta herbácea perene, possuindo um rizoma grosso (desenho em baixo à direita) e um caule ramificado com folhas e estípulas alternas e trímeras. As flores amarelas e solitárias encontramse na extremidade dos caules. Os frutos são aquênios cobertos de excrescências recurvadas (figura pormenorizada). Toda a planta é vilosa. É vulgar nos silvados, ao longo dos muros e das sebes. Desde a Antiguidade é colhida devido às suas virtudes peitorais. Colhe-se o rizoma. Depois de', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva Botão', E'', '', E'ECLIPTA ALHA HAASK.IMUNOESTIMULANTE, HEPATOPROTETORA E ANTIOFÍDICA. Erva botão', '', E'Nome científico: Eclipta alha Haask.  Planta herbácea, anual, da família Compositae. É uma espécie silvestre, de ramos, finos, lenhosos, com flores em capítulos cônicos brancacentos. Apresenta a wedelolactona, cumarinas que lhe conferem atividade imunoestimulante, hepatoprotetora e antiofídica. Estimula a síntese do interferon, que neutraliza in vitro o veneno de jararaca. Tem grande utilidade no tratamento de pacientes com a queda das defesas orgãnicas. Auxilia no tratamento de doenças infeccio', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva Cidreira', E'', '', E'MELISSA OFFICINALIS L., MELISSA, CIDRILHA E MELITÉIACALMANTE, DIGESTIVO, CARRNINATIVA, ANTIESPASMÓDICA, ANTINEVRÁLGICA. USADA, AINDA, CONTRA INSÔNIA, PARA PROBLEMAS NERVOSOS E NO TRATAMENTO DE FERIDAS. ATUA COMO HIPOTENSOR.ERVA CIDREIRA', '', E'Nome científico: Melissa officinalis L. Família: Labiatae.  Origem: Sul da Europa.  Sinonímia: melissa, cidrilha e melitéia.  Descrição: erva perene; caule de secção quadrangular; folhas opostas ovais, verdeclaras e brilhantes, denteadas; flores esbranquiçadas, reunidas em glomérulos, axilares. Odor semelhante ao do limão.  Constituintes químicos principais: óleo essencial contendo citral, citronelal, citronelol, pineno, limoneno, linalol e geraniol; taninos, ácido cafêico e clorogênico.  Indica', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De Bicho', E'', '', E'POLYGONUM SPP., CAPETIÇOBA, CATÁRIA, PIMENTADO-BREJO, PIMENTA-DA-ÁGUA, PERSICÁRIA, CAPIÇOBA E PERSICÁRIA-DO-BRASIL.É URNA PLANTA ANTITÉRMICA, ESTIMULANTE, DIURÉTICA, VERMICIDA, CONTRA ÚLCERAS, DIARRÉIAS SÁNGÜÍNEAS, E CONGESTÕES CEREBRAIS. ADSTRINGENTE, CICATRISANTE, ANTI-HEMORROIDAL. USADA AINDA PARA REUMATISMO, ERISIPELA E ARTRITE (USO EXTERNO).Erva-de-bicho', '', E'Nome científico: Polygonum spp. Família: Polygonaceae. Origem: Ásia.  Sinonímia: capetiçoba, catária, pimentado-brejo, pimenta-da-água, persicária, capiçoba e persicária-do-brasil.  Descrição: erva perene ou anual, tamanho variado, 1 m ou mais de altura; caule enraizando-se na base, nodoso e com internódios avermelhados ou esverdeados;folhas alternas, verde-escuras, amargas; inflorescência terminal em forma de espigas; flores hemafroditas, pequenas, brancas ou róseas; fruto tipo aquênio triangul', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De Passarinho', E'', '', E'STRUTHANTHUS CONCINNUS MORT.AFECÇÕES RESPIRATÓRIAS,BRONQUITE, TOSSE,PNEUMONIA E COQUELUCHE.Erva de passarinho', '', E'Nome científico: Struthanthus concinnus Mort.  Epífita semiparasita, da família Loranthaceae, originária do Brasil. Cresce tanto em plantas silvestres corno em plantas cultivadas, especialmente nas laranjeiras, absorvendo-lhes a seiva. Recomenda-se o suco das folhas frescas em afecções respiratórias, como bronquite, tosse,pneumonia e coqueluche. Multiplica-se por sementes. ;', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De Santa Luzia', E'', '', E'EUPHORBIA HIRTA L.CARCINOGÊNICOS,FORTES PURGATIVOS.DIURÉTICO E ANTI-BACTERIANO.ASMA, BRONQUITE, ENFISEMA, TOSSE NERVOSA, CATARRO, FEBRE DO FENO E DISENTERIA AMÉBICA.QUEIMADURAS E VERRUGASErva de santa luzia', '', E'Euphorbia hirta L. Syn: Chamaesyce hirta Millsp. Euphorbiaceae  Entre as dicotiledôneas, a família Euphorbiaceae é uma das maiores, contando com cerca de 5.000 espécies distribuídas por uns 300 gêneros; só o gênero Euphorbia apresenta mais de 700 espécies, muitas das quais são suculentas. Entre as euforbiáceas encontram-se árvores, arbustos, sub-arbustos e ervas. Um grande número de espécies é latescente e algumas espécies contêm substâncias tóxicas. Considerando-se a grandeza da família, é surp', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De Santa Maria', E'', '', E'CHENOPODIUM AMBROSIOIDES L., AMBRISINA, MENTRUZ, ERVA FORMIGUEIRA, MASTRUÇO, MASTRUZ, MATA COBRA, CANUDO, ERVA-POMBA-ROTA, ERVA SANTA, AMBRÓSIA E QUENOPÓDIO.ESTOMÁQUICA, DIURÉTICA, VERMÍFUGA, SUDÓRÍFERA, PARA ANGINA, E INFECÇÕES PULMONARES. USADA AINDA COMO EIEATRIZANTE E PARA CONTUSÕES (USO EXTERNO).ERVA DE SANTA MARIA', '', E'Nome científico: Chenopodium ambrosioides L.  Família: Chenopodiaceae. Origem: América Tropical.  Sinonímia: ambrisina, mentruz, erva formigueira, mastruço, mastruz, mata cobra, canudo, erva-pomba-rota, erva santa, ambrósia e quenopódio.  Descrição: planta herbácea, com até 1 m de altura; caule ereto e muito ramificado; folhas alternas lanceoladas, denteadas; flores pequenas e verde-amareladas; fruto seco, pequeno, com numerosas sementes escuras.  Constituintes químicos principais: óleo essencia', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De São João', E'', '', E'HYPERICUM PERFORATUM L.FERIDAS.SEDATIVO E NITIDAMENTE COLAGOGO.ANTI-INFLAMATÓRIO.INFLAMAÇÕES CRÔNICAS DO ESTÔMAGO, DO FÍGADO, DA VESÍCULA, DOS RINS;AFECÇÕES GINECOLÓGICAS.ENURESE.ANSIEDADE, TENSÃO NERVOSA, PERTURBAÇÕES NA MENOPAUSA, SÍNDROME PRÉ-MENSTRUAL,COBREIRO, CIÁTICA, E FErva de São João', '', E'Hypericum perforatum L. Guttiferae (Hypericaceae)  O gênero Hypericum conta aproximadamente com 370 espécies anuais, arbustivas e semi-arbustivas perenes e semi-perenes, encontradas principalmente nas regiões temperadas. Uma grande variedade de grupos provê muitas plantas finas de jardinagem para a maioria das aplicações. Hypericum pode derivar do grego hyper, "acima", e eikon, "pintura". de vez que as flores eram colocadas sobre imagens religiosas para afastar o mal no Dia de Solstício de verão', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva De São Roberto', E'', '', E'GERANIUM ROBERTIANUM L.ADSTRINGENTE.DIURÉTICO.HEMOSTÁTICO.DIARRÉIAS REBELDES.CÁLCULOS URINÁRIOS E RENAIS.DIURÉTICO.DOENÇAS DA PELE,DERMATITES, ECZEMAS SUPURANTES, ÚLCERAS E INFLAMAÇÕES DIVERSAS.Erva de são roberto', '', E'Geranium robertianum L. Geraniaceae  O gênero Geranium consta de cerca de 300 espécies perenais, algumas anuais e subarbustos, amplamente distribuídos pelas regiões temperadas. Os gerânios são populares plantas de jardinagem, com folhas atraentes e pequenas e delicadas flores venosas, que crescem por um longo período de tempo. Os pelargônios, plantas próximas relacionadas, também são popularmente conhecidos como "gerânios", mas têm usos diferentes. Geranium robertianum é uma planta herbácea anua', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva Doce', E'', '', E'PIMPINELLA ANISUM L.ESTIMULANTES, DIGESTIVOS, CARMINATIVOS E ANTIESPASRNÓDICOS.COMBATER FEBRE E AUMENTAR A SECREÇÃO DO LEITE NAS LACTANTESErva doce', '', E'Nome científico: Pimpinella anisum L.  Espécie herbácea, anual, da família Umbeliferae, originária da África. Por suas características botânicas e aromáticas, confunde-se com o Funcho. Contém óleo essencial que lhe confere propriedades estimulantes, digestivos, carminativos e antiespasrnódicos, além de combater febre e aumentar a secreção do leite nas lactantes. A infusão é feita, utilizando-se 10 g de frutos em 1 litro d''água fervente, deixa-se em repouso por 1/2 hora e côe. É muito usada corno', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Erva Dos Gatos', E'', '', E'NEPETA CATARIA L.ANTIESPASMÓDICA, SEDANTE, BÉQUICA, ESTOMÁQUICA, CARMINATIVA E EMENAGOGA.Erva dos gatos', '', E'Nome científico: Nepeta cataria L.  Espécie herbácea, perene, da família Labiatae, originária do Mediterrâneo oriental. O perfume desta planta é considerado afrodisíaco para os gatos, daí deriva seu nome. Possuem flores de coloração pálida ou branca; as sementes são pequenas, escuras, com dois pontos brilhantes, semelhantes aos olhos. As flores e folhas, na fornia de infusão, xarope ou tintura, possuem as propriedades antiespasmódica, sedante, béquica, estomáquica, carminativa e emenagoga. O sab', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Espinheira Santa', E'', '', E'MAYTENUS ILICIFOLIA MART., SALVA-VIDAS, COROMILHO-DO-CAMPO, ESPINHO-DE-DEUS, MAITENO, ESPINHEIRA-DIVINA E CANCEROSA.ANTIÁCIDO, ANTI-SÉPTICO, ANTINFLAMATÓRIO E CICATRIZANTE. PLANTA EMPREGADA COM SUCESSO EM ULCERAS PÉPTICAS E GASTRITE CRÔNICA. FRACA AÇÃO LAXATIVA E DIURÉTICA. EXTERNAMENTE UTILIZADA COM SUCESSO EM ACNES E ALGUNS TIPOS DE ECZEMAS, FERIDAS E ULCERAÇÕES. ESPINHEIRA SANTA', '', E'Nome científico: Maytenus ilicifolia Mart. Família: Celastraceae. Origem: América do Sul. Sinonímia: salva-vidas, coromilho-do-campo, espinho-de-deus, maiteno, espinheira-divina e cancerosa.  Descrição: planta arbustiva, de caule bem ramificado, apresentando estrias longitudinais que a diferenciam das outras espécies do mesmo gênero; folhas inteiras, lanceoladas, alternas, coriáceas e denteadas; flores hermafroditas, reunidas em inflorescências axilares; fruto capsular (em forma de vagens arredo', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Estévia', E'', '', E'STEVIA REBAUDIANA (BERT.) HEMSLEY.COADJUVANTE NO TRATAMENTO DE DIABETES E OBESIDADE; É TAMBÉM ANTICÁRIE. POPULARMENTE, SÃO ATRIBUÍDAS A ESTA PLANTA PROPRIEDADES CORNO: TÔNICO ESTIMULANTE DAS FUNÇÕES CEREBRAIS, CONTRA FADIGA E DEPRESSÃO, REGULADOR DA PRESSÃO ARTERIAL DOS HIPERTENSOS, CONTRESTÉVIA', '', E'Nome científico: Stevia rebaudiana (Bert.) Hemsley.  Família: Compositae. Origem: Brasil. Sinonímia: sem referências.  Descrição: arbusto de pequeno porte; caule ereto, bem ramificado; folhas opostas, oblongas a ovaladas, 2 a 4 cm de comprimento; flores dispostas em cachos.  Constituintes químicos principais: óleo essencial e glicosídios diterpênicos (esteviosídio, dulcosídio e esteviobiosídio).  Indicações: coadjuvante no tratamento de diabetes e obesidade; é também anticárie. Popularmente, são', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Eucalipto', E'', '', E'EUCALYPTUS SP.ANTISSÉPTICA.AROMÁTICA, ESTIMULANTE, DESCONGESTIONANTE E EXPECTORANTE, RELAXA ESPASMOS E ABAIXA FEBRE.CATARRO, BRONQUITE, SINUSITE, RESFRIADOS, E GRIPE;FERIDAS E ABSCESSOS.Eucalipto', '', E'Eucalyptus sp. Myrtaceae  Mais de 500 espécies de árvores e arbustos aromáticos perenes pertencem ao gênero Eucalyptus que é nativo na Austrália. O eucalipto foi introduzido, com muito sucesso, na Europa, Argélia, Índia, México, E.U.A., América Central e do Sul. Os eucaliptos estão entre as plantas de mais rápido crescimento e as árvores mais altas do mundo. Os ramos crescem com rapidez e podem atingir mais de quatro metros em um ano. Existem espécies cujas árvores registram alturas superiores a', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Eufrásia', E'', '', E'EUPHRASIA OFFICINALIS L.ADSTRINGENTE.REDUZ INFLAMAÇÃO.LOÇÕES OCULARES,SENSIBILIDADE EXCESSIVA À LUZ E FADIGA OCULAR.CATARRO, SINUSITE, RINITE ALÉRGICA, FEBRE DO FENO E INFECÇÕES DAS VIAS RESPIRATÓRIAS SUPERIORES.ABRIR O APETITE, ESTIMULAR A DIGESTÃO.DORES DE CABEÇA, A HISTERIA, Eufrásia', '', E'Euphrasia officinalis L. Scrophulariaceae  O gênero Euphrasia é cosmopolita e inclui cerca de 450 espécies de plantas semiparasitas, sendo geralmente considerado como um grande grupo de espécies semelhantes com pouquíssimas delas que se destacam tais como Euphrasia rostkoviana e Euphrasia montana. De modo geral as Euphrasias são difíceis de cultivar por causa do ambiente de crescimento que requerem. O nome genérico deriva do termo grego euphrasia que se traduz por alegria e representa a alegria', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Eupatório', E'', '', E'EUPATORIUM CANNABINUMGRIPE,PLEURISIA,PNEUMONIA,FEBRE FORTE, DE ABATIMENTO E DE DORES TORÁXICAS.Eupatório', '', E'Eupatorium cannabinum Asteraceae (Compositae)  Sob ponto de vista antroposófico É uma planta vivaz que medra as beiras de lagos, de rios, de riachos, as florestas úmidas, canais de irrigação, na Europa central e meridional bem como na Ásia ocidental. Ela cresce no verão até um metro e meio de altura, com folhas quase sésseis Em forma de mão, divididas em 3 a 5 lobos opostos; ela termina no alto por uma abundante panícula de flores, com uma delicada cor rosa-violeta; as floretas, filiformes, são', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Falso Boldo', E'', '', E'COLEUS BARBATUS BENTH., BALDO, BALDO-DO-REINO, ALUMÃ,MALVA-SANTA, BALDO-NACIONAL E SETE-DORESTÔNICO, DIGESTIVO,HIPOSSECRETOR GÁSTRICO (PARA AZIA E DISPEPSIA), CÁRMINATIVO, PARA AFECÇÕES DO FÍGADO E RESSACA  ALCOÓLICA.FALSO BOLDO', '', E'Falso baldo Nome científico: Coleus barbatus Benth. Família: Labiatae. Origem: Ásia. Sinonímia: baldo, baldo-do-reino, alumã,malva-santa, baldo-nacional e sete-dores.  Descrição: subarbusto perene de 1,5 a 2,0 m de altura; ramos de secção quadrangular; folhas opostas, ovadooblongas, pilosas; flores pentâmeras, azuis a violáceas, reunidas em racimos. Sabor amargo e odor característico.  Constituintes químicos principais: óleo essencial rico em guaieno e fenchona; contém ainda barbatol, barbatesin', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Fel Da Terra', E'', '', E'CENTAURIUM ERYTHRAEA RAMTÔNICO PARA O SISTEMA DIGESTIVO E ABAIXA A FEBRE.ESTIMULAM O FÍGADO E A VESÍCULA BILIAR, AUMENTAM O FLUXO BILIAR, MELHORANDO O APETITE E A DIGESTÃO.HEPATITE, ICTERÍCIA, ANOREXIA, SÍNDROME PÓS-VIRAL.ENFERMIDADES FEBRIS.Fel da terra, Centáurea-menor', '', E'Centaurium erythraea RAM Syn.:Centaurium minus MOENCH, Erythraea centauríum (L.) PERS, Gentianaceae O género Centaurium consta de cerca de 40 espécies anuais e bienais, ocasionalmente perenais, encontradas ao longo de regiões temperadas. Centaurium erythraea é nativa em dunas e prados secos da Europa e sudoeste da Ásia e naturalizada na América do Norte. Como muitos membros da família das gencianas, é extremamente amarga, o que levou Nicholas Culpeper a comentar em The English Physitian Enlarged', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Feno Grego', E'', '', E'TRIGONELLA FOENUM-GRAECUM L.HIPOGLICÊMICA.FORTIFICANTE PARA OS CONVALESCENTES, DIGESTIVA,ANTITÚSSICA E ESTIMULANTE DA PRODUÇÃO DE LEITE MATERNO.EQUIMOSES, INCHAÇOS E ÚLCERAS.Feno grego', '', E'Trigonella foenum-graecum L. Leguminosae (Fabaceae)  Planta herbácea anual, cultivada nos campos pelas suas qualidades alimentares e medicinais. Originário da região mediterrânea, o feno-grego prospera mesmo nas latitudes mais setentrionais, desde que seja semeado em locais minimamente abrigados e solos suficientemente ricos em calcário. Semeado na Primavera, forma um caule ereto com folhas trifolioladas e flores amarelas a violáceas. O fruto é uma vagem fina que encerra sementes amarelas (à esq', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Feto Macho', E'', '', E'DRYOPTERIS FILIX-MAS (L.) SCHOTT.PARASITAS INTESTINAIS, PONTADAS NO FÍGADO, HEMORRAGIA INTERNA,HEMORRAGIA UTERINA, CAXUMBA E ENFERMIDADES FEBRIS,RESFRIADOS, GRIPE, SARAMPO, PNEUMONIA, E MENINGITE.TENÍFUGO.FERIDAS QUE SARAM DIFICILMENTE, ABSCESSOS, FURÚNCULOS, CARBÚNCULOS, CHAGAS,DORES REFeto macho', '', E'Dryopteris filix-mas (L.) SCHOTT. Aspidiaceae  Dryopteris é um gênero cosmopolita de samambaias decíduas rizomosas que contêm cerca de 150 espécies. Muitas espécies são cultivadas como ornamentais pela sua bela folhagem em formato de vaso. Algumas espécies exigem condições especiais, mas várias outras, inclusive Dryopteris filix-mas, são facilmente cultivadas como plantas ornamentais, sendo robustas e muito resistentes à seca. Várias espécies contêm derivados de floroglucinol ("filicina"), que p', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Fidalguinhos', E'', '', E'CENTAUREA CYANUS L.TRATAR FERIDAS E AFECÇÕES ULCEROSAS, CONJUNTIVITES, FERIDAS SECUNDÁRIAS,ÚLCERAS DE BOCA,LOÇÕES CAPILARES.DIURÉTICO E ESTIMULANTE DO METABOLISMO.PERTURBAÇÕES GÁSTRICAS.Fidalguinhos', '', E'Centaurea cyanus L. Syn.:Cyanuci segetum HILL. Asteraceae (Compositae)  Cerca de 450 espécies anuais, bianuais, perenais e sub-arbustos compõem o gênero Centaurea que ocorre nas regiões mediterrâneas, Eurásia, América do Norte e Austrália; Várias espécies são cultivadas como ornamentais por suas flores parecidas com cardos que são coloridas e brilhantes. O nome Centaurea foi atribuído porque o legendário centauro, Chiron, conhecido pelo seu conhecimento de ervas, foi o primeiro que revelou suas', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Figueira', E'', '', E'FICUS CARIS L.INFLAMAÇÕES DA BOCA E GARGANTA.HIDROPISIA.ELIMINAR VERRUGAS.Figueira', '', E'Nome científico: Ficus caris L.  Espécie arbórea, de porte médio, da família da Moraceae, provavelmente originária do Oriente Médio. Os frutos secos em decocção (2 figos em 400 ml de água) são utilizados contra inflamações da boca e garganta. A casca seca ou a rama, na forma de decocção (20 g em 1 litro de água, 4 xícaras ao dia) atua contra a hidropisia. O látex ajuda a eliminar verrugas. As folhas contém uma substância fotossensibilizante (bergapterio) que pode ser perigosa em contato com a pe', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Filipêndula', E'', '', E'FILIPENDULA ULMARIADIAFORÉTICOS PARA BAIXAR A FEBRE E CONTRA AS DORES REUMATISMAIS.DORES DA BEXIGA E DOS RINS.SUDORÍFICA, DIURÉTICA, DEPURATIVA, ANTIREUMÁTICA.Filipêndula', '', E'Filipendula ulmaria Rosaceae Sob ponto de vista antroposófico  A rainha dos prados medra em toda a Europa e no norte da Ásia. Ela se deixa notar em grande número à beira dos riachos tranqüilos, nos juncais e em locais onde crescem algumas canáceas, nas margens pantanosas dos lagos e das poças ao longo dos rios e dos canais de irrigação. O rizoma rastejante no solo palustre, impregnado de água, cresce de ano em ano, produzindo novas raízes a partir de seus nós. No fim deste rizoma surge um broto', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Folha Da Fortuna', E'', '', E'BRYOPHYLLUM PINNATUM KURTZ.,COIRAMA, FOLHA-DA-COSTA, FORTUNA, FOLHA-DE-PIRARUCU, RODA-DAFORTUNA E FOLHA-GROSSA.EMOLIENTE, (PARA FURÚNCULOS), CICÁTRIZANTE (QUEIMADURAS) E ANTIINFLAMATÓRIO LOCAL (USO EXTERNO). REFRESCANTE INTESTINAL, PARA COQUELUCHE E DEMAIS INFECÇÕE DO APARELHO RESPIRATÓRIO. PLANTA USADA TAMBÉM PARA ÚLCERAS E GASTRITES.FOLHA DA FORTUNA', '', E'Nome científico: Bryophyllum pinnatum Kurtz. Família: Crassulaceae. Origem: África. Sinonímia: coirama, folha-da-costa, fortuna, folha-de-pirarucu, roda-da-fortuna e folha-grossa.  Descrição: planta sublenhosa, perene, carnosa, 1,5 m de altura; caule de cor mais clara (quando mais velho) e os demais avermelhados; flores hermafroditas, tubulosas, penduladas, verde-pálidas ou amarelo-avermelhadas.  Constituintes químicos principais: mucilagem, tanino, ácidos orgânicos, sais minerais e glicosídios', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Framboeseiro', E'', '', E'RUBUS IDAEUS L.EXPECTORANTES, PARA TRATAMENTO DE PERTURBAÇÕES GÁSTRICAS, PARA FACILITAR A DIURESE E A SECREÇÃO BILIAR.Framboeseiro', '', E'Rubus idaeus L. Rosaceae  Arbusto com ramos castanhos e eretos, cobertos de pequenos espinhos e apresentando folhas alternas imparifolioladas. Estas são verdes e brilhantes na página superior, brancas e tomentosas na infenor. Os cachos lassos de flores brancas formam-se na axila das folhas de ramos do ano precedente; estes morrem no fim da vegetação. O fruto, a framboesa, de cor vermelha ou amarela, é uma drupa composta que se desprende do receptáculo quando amadurece. É uma espécie bastante vul', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Freixo Europeu', E'', '', E'FRAXINUS EXCELSIOR L.LAXANTES.CONTRA OS PARASITAS INTESTINAIS.FEBRÍFUGOS.AFECÇÕES RENAIS E ESPECIALMENTE EM CASOS DE CÁLCULOS,DORES REUMATISMAIS.GOTA.Freixo europeu', '', E'Fraxinus excelsior L. Oleaceae  Aproximadamente 65 espécies de árvores decíduas, principalmente robustas, compõem o gênero Fraxinus que ocorre ao longo das partes temperadas do hemisfério do norte. Fraxinus ornus é encontradodo em bosques da Europa meridional e Ásia ocidental. A maioria dos freixos é de rápido crescimento e tolera uma grande variedade de condições ambientais. Eles têm folhas penatissectas e flores insignificantes, com a exceção dos freixos denominadas "florescentes". Estes inclu', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Fumaria', E'', '', E'FUMARIA OFFICINALIS L., FEL-DA-TERRA E ERVA-MOLEIRINHA.UTILIZADA NAS AFECÇÕES DO FÍGADO, NA ARTERIÓSCLEROSE, NAS AFECÇÕES DA PELE- É DIURÉTICA, ESTOMÁQUICA, LAXANTE, DEPURATIVA, CARDIOTÔNICA E USADA PARA ESCROFULOSE.FUMÁRIA', '', E'Nome científico: Fumaria officinalis l. Família: Papaveraceae.  Origem: Europa. Sinonímia: fel-da-terra e erva-moleirinha.  Descrição: planta herbácea anual de 0,20 a 0,80 m de altura, ramosa, haste delgada, angulosa, de ramos difusos; folhas alternas, pecioladas,profundamente recortadas em colmilhos, verde-glaucas ou acinzentadas; flores branco-avermelhadas, manchadas de púrpura no cimo, numerosas, pequenas, dispostas em cachos terminais. Sabor muito amargo e persistente.  Constituintes químico', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Funcho', E'', '', E'FOENICULUM VULGARE MIILL., ERVA-DOCE, FIOLHO, FIOLHO-DE-FLORENA E FIOLHO-DOCE.CARMINATIVO, GALACTAGOGO, DIGESTIVO, DIURÉTICO, TÔNICO GERAL E ANTIESPASMÓDICO (CÓLICAS DE CRIANÇAS).FUNCHO', '', E'Nome científico: Foeniculum vulgare miill. Família: Umbelliferae. Origem: Mediterrãneo.  Sinonímia: erva-doce, fiolho, fiolho-de-florena e fiolho-doce.  Descrição: herbácea perene ou bianual, glabra, aromática e ramosa, com até 2 m de altura; caule fistuloso estriado; pecíolo aniplexicaule, recurvado; inflorescências em umbelas compostas, com flores aromáticas verde-amareladas; fruto aquênio; folhas verde-azuladas, profundamente divididas.  Constituintes químicos principais: óleo essencial conte', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Galega', E'', '', E'GALEGA OFFICINALISTRATAMENTO COMPLEMENTAR DA DIABETES.ESTIMULAR A ATIVIDADE DAS GLÂNDULAS MAMÁRIAS.Galega', '', E'Galega officinalis Leguminosae (Fabaceae)  Apenas seis espécies perenais compõem o gênero Galega que ocorre na Europa central e meridional, Ásia ocidental (Galega officinalis) e África oriental tropical. Algumas espécies são cultivadas por sua atraente folhagem penatissecta e seus racemos coloridos. Um dos nomes populares, arruda-de-bode, deve-se ao cheiro de sujeira que surge da folhagem quando contundida. O nome Galega vem do grego "gala", leite, porque estas plantas têm reputação de aumentare', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Galeopis', E'', '', E'GALEOPIS DUBIAPERTURBAÇÕES PULMONARES.CERTAS FORMAS DE TUBERCULOSE.Galeopis', '', E'Galeopis dubia Labiatae (Lamiaceae)  Sob ponto de vista antroposófico esta planta herbácea, natural da Europa ocidental, cresce em solos arenosos e pedregosos, ou seja, solos de natureza silicosa, ou ainda, esta planta cresce no granito estéril. Tal solo é absolutamente mineral, mas ele pode ser muito aerado e impregnado de água. Para a Galeopis dubia, a sílica não é apenas um substrato, (este vegetal foge do calcário). A sílica, para esta planta, é um elemento trabalhado interiormente pelo vege', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Genciana Amarela', E'', '', E'GENTIANA LUTEA L.ESTIMULAR AS SECREÇÕES GÁSTRICAS.AÇÃO TÔNICA SOBRE O FÍGADO E A VESÍCULA BILIAR,Genciana amarela', '', E'Gentiana lutea L. Gentianaceae  Planta perene com raiz grossa, apresentando uma roseta de folhas elípticas. É somente ao fim de quatro a oito anos que aparece, no centro da roseta, um caule alto e oco com folhas sésseis e opostas. Na axila das folhas superiores estão agrupadas em feixes as grandes flores amarelas. O fruto é uma cápsula que encerra sementes aladas. É uma espécie originária dos Cárpatos que se encontra, ainda que raramente, noutras cadeias montanhosas da Europa e da Ásia. É uma es', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Gengibre', E'', '', E'ZINGIBER OFFICINALE ROSCOE., GENGIVRE, GINGIBRE, MANGARATAIA E MANGARATIÁ.ESTIMULANTE GASTRINTESTINAL, APERIENTE, COMBATE OS GASES INTESTINAIS (CARMINATIVO), VÔMITOS E ROUQUIDÃO. É TÔNICO, BACTERICIDA E EXPECTORANTE. EXTERNAMENTE, É REVULSIVO, UTILIZADO EMGENGIBRE', '', E'Nome científico: Zingiber officinale Roscoe.  Família: Zingiberaceae.  Origem: Ásia Tropical.  Sinonímia: gengivre, gingibre, mangarataia e mangaratiá.  Descrição: planta herbácea, rizomatosa perene; raízes adventícias; folhas dísticas, sendo as basilares reduzidas; brácteas florais obovadas, cada urna envolvendo uma só fiar curto pedicelada; rizoma de sabor picante.  Constituintes químicos principais: gingerol, zingibereno (bactericida), beta bisaboleno, zingerona, alfa-felanâreno, citral, canf', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Gervão', E'', '', E'STACHYTARPHETA CAYENENSIS (RICH) VALH.TÔNICA, ANTIHEMORROIDAL, LAXATIVO, ANTITÉRMICO, SUDORÍFUGA, DIURÉTICO, CONTRA A ROUQUIDÃO, TOSSES, HEPATITE E AMEBÍASES. Gervão', '', E'Nome científico: Stachytarpheta cayenensis (Rich) Valh.  Espécie subarbustiva, bianual ou perene, da família Verbenaceae, nativa do Brasil. Como princípios ativos contém estarquitafina, vitral, geraniol, verbenalina, dextrina e ácido salicílico. As raízes e folhas, na forma de decocção, são utilizadas como tônica, antihemorroidal, laxativo, antitérmico, sudorífuga, diurético, contra a rouquidão, tosses, hepatite e amebíases. O sumo das folhas, usado externamente, é cicatrizante. Multiplica-se po', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Giesta', E'', '', E'CYTISUS SCOPARIUS (L.) LINK.PERTURBAÇÕES DA ATIVIDADE CARDÍACA E DA CIRCULAÇÃO.DILATAM AS CORONÁRIAS E AUMENTAM A TENSÃO.ESTIMULAM A ATIVIDADE DOS MÚSCULOS LISOS E DO ÚTERO,Giesta', '', E'Giesteira-das-vassouras Cytisus scoparius (L.) LINK. syn.: Sarothamnus scoparius (L.) WIMM. ex W.D.J. KOCH Leguminosae (Fabaceae) (Papilionaceae)  Mais de 30 espécies de arbustos decíduos e pequenas árvores pertencem ao gênero Cytisus que ocorrem na África do Norte, Ásia Ocidental e Europa. Cytisus scoparius é nativo em brejos, solos não cultivados e bosques na Europa; é uma planta familiar tanto no estado selvagem como em cultivos. A maioria das variantes citadas em catálogos são, de fato, híbr', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ginco', E'', '', E'GINKGO BILOBA L.ASMA,RESPOSTAS INFLAMATÓRIAS ALÉRGICAS, INSUFICIÊNCIA CEREBRAL NAS COMPLICAÇÕES CIRCULATÓRIAS DE IDOSOS,DOENÇA DE RAYNAUD E VEIAS VARICOSAS.BATIDA IRREGULAR DO CORAÇÃO.INCONTINÊNCIA URINÁRIAGinco', '', E'Ginkgo biloba L. Ginkgoaceae  Uma única espécie de árvore decídua compõe este gênero que é encontrado de forma natural nas províncias Zhejiang e Guizhou da China central, e que não tem nenhum parente próximo na família. G. biloba é raro no estado silvestre,mas há muito tempo cresce como uma árvore sagrada na China e no Japão. Flores macho e fêmeas nascem em plantas separadas; a frutificação só acontece quando árvores macho e fêmeas crescem junto e em verões quentes. O nome Ginkgo vem do japonês', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ginjeira', E'', '', E'PRUNUS CERASUS L.BRONQUITES.DIARRÉIAS.DIURÉTICOS.TISANAS PARA EMAGRECER.CARMINATIVAS E ANTIANEMICAS.PERTURBAÇÕES DIGESTIVAS,DISFUNÇÃO HEPÁTICA.ANEMIA.Ginjeira', '', E'Prunus cerasus L. Syn.: Cerasus vulgaris MILL. Rosaceae  Árvore ou arbusto com ramos castanhoavermelhados, frequentemente decumbentes, apresentando folhas alternas, brilhantes, dentadas. As flores brancas de simetria pentâmera crescem em fascículos sobre ramos curtos. Os frutos são drupas vermelho-escuras. É uma especie de origem asiática, cultivada em todo o mundo pelos seus frutos, sob a forma de numerosas variedades. Para fins medicinais, são colhidos os pedúnculos, retirados de frutos maduro', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Girassol', E'', '', E'HELIANTHUS ANNUS L.RICAS EM PROTEÍNAS.VULNERÁRIA,MALÁRIA.Girassol', '', E'Helianthus annus L. Asteraceae (Compositae) Sob ponto de vista antroposófico  Essa planta, originária do México, nasce a partir de sua semente, atinge em pouco tempo o dobro da altura de um homem e floresce. Ela cresce nos jardins, nas vinhas, nos terrenos que são nivelados (onde ela permanece pequenina). Cresce bem na Europa central e na Rússia meridional, mas ela literalmente devora o humus do solo. Além disso, ela precisa de muito sol e umidade. Todo o crescimento do forte caule ereto, acompa', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Goiabeira', E'', '', E'PSIDIURN GUAJAVA L.DIARRÉIA, ANTI-SÉPTICO BUCAL.AFECÇÕES DA GARGANTA E DORES DE DENTE.Goiabeira', '', E'Nome científico: Psidiurn guajava L.  Espécie arbórea, da família Myrtaceae, nativa do Brasil. Como princípios ativos contém: tanino, mucilagem, e eugenol. Os frutos são ricos em vitamina C. Os brotos em decocçéo (50 g de brotos em 1 litro de água, tomar 1 xícara de 2 em 2 horas) são indicados para diarréia e como anti-séptico bucal. A casca do caule também é utilizada em afecções da garganta e dores de dente. É importante conhecer bem as causas da diarréia antes de fazer o tratamento. A goiabei', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Guaco', E'', '', E'MIKANIA GLOMERATA SPRENG., UACO, CIPÓ-CATINGA, CIPÓ SUCURIJU, ERVA-COBRE, CORAÇÃO-DE-JESUS E ERVA-DE-COBRATEM EFEITO BRONCODILATADOR COMPROVADO, ALÉM DE SER ANTI-SÉPTICO DAS VIAS RESPIRATÓRIAS, EXPECTORANTE E ANTIÁSMÁTICO. É AINDA FEBRÍFUGO, SUDORÍFERO, ANTI_REUMÁTICO E CICATRIZANTE.GUACO', '', E'Nome científico: Mikania glomerata Spreng.  Família: Compositae.  Origem: América do Sul.  Sinonímia: uaco, cipó-catinga, cipó sucuriju, erva-cobre, coração-de-Jesus e erva-de-cobra.  Descrição: planta trepadeira arbustiva; ramos abundantes; folhas opostas, verdes; flores amareladas e brancas reunidas em capítulos.  Constituintes químicos principais: compostos sesquiterpênicos, diterpênicos, estigmasterol, flavonóides, cumarinas, resina, tanino, saponina e guacosídio.  Indicações: tem efeito bro', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Guiné', E'', '', E'PETIVERIA ALLIACEA L.ANTIESPASRMÓDICO E ABORTIVO , SUDORÍFERO, DIURÉTICO, ANTI-REUMÁTICO.INFLAMAÇÕES NA BOCA E GARGANTA, DOR DE DENTE E GENGIVITE.Guiné', '', E'Nome científico: Petiveria alliacea L.  Planta herbácea, perene, da família das Phytolaccaceae, originária da América tropical. Apresenta forte odor que lembra o alho. Como princípios ativos contém óleo essencial, alcalóides, saponinas, taninos e flavonóides. Tem efeito antiespasrmódico e abortivo (raízes), sudorífero, diurético, anti-reumático (massagear o local dolorido com a tintura) e antivenéreo. Ainda é utilizado contra inflamações na boca e garganta, dor de dente e gengivite. o decocto da', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Hedeoma', E'', '', E'HEDEOMA PULEGIOIDESEMENEGOGA E ABORTIVA;DISMENORRÉIA, A LEUCORRÉIA,ESTIMULA AS ATIVIDADES HEPÁTICAS, BILIARES E DO BAÇO.Hedeoma', '', E'Hedeoma pulegioides Labiatae (Lamiaceae) Sob ponto de vista antroposófico  Esta planta, cujo odor é muito parecido com o da hortelã, medra nas regiões médias da América do Norte. Ela cresce em caminhos pedregosos e em terrenos rochosos. O seu porte lembra o do Marrubium. Esta planta possui pequeníssimas flores brancas que emergem dos nós situados junto à intersecção da folha com o caule. A atividade desta planta é emenegoga e abortiva; ela combate a dismenorréia, a leucorréia, favorecendo o aque', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Heléboro', E'', '', E'HELLEBORUS NIGERELEVAÇÃO DA PRESSÃO SANGUÍNEA, UM AUMENTO DA DIURESE,SEQÜELAS DA NEFRITE ESCARLATE E OS SINTOMAS MENÍNGEOS,Heléboro', '', E'Helleborus niger Ranunculaceae  Sob ponto de vista antroposófico Esta planta é espontânea nos Alpes orientais, principalmente na vertente Sul. Ela habita as altitudes médias, os declives calcários espessos, úmidos, mas pedregosos, vivendo num solo fresco e molhado, levemente sombreado, e possui um rizoma que quase não permite o surgimento de folhas coriáceas, persistentes e de divisão digitada. O ritmo vital dessa planta se rebela contra o ritmo dinâmico do ano terrestre. Ela florece quando a vi', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Hera Terrestre', E'', '', E'GLECHOMA HEDERACEUM L.,HORTELÃ-DO-MATO, ERVA-DE-SÃO-JOÃO E ERVA-TERRESTRETÔNICO, BÉQUICO, INFLAMAÇÕES NA GARGANTA, DESOBSTRUENTE DO FÍGADO, ESTOMÁQUICO, VULNERÁRIO, VERMÍFUGA E ANTIESPASMÓDICO.Hera terrestre', '', E'Nome científico: Glechoma hederaceum L. Família: Labiatae. Origem: Europa e Ásia Boreal. Sinonímia: hortelã-do-mato, erva-de-são-joão e erva-terrestre.  Descrição: planta herbácea, perene, vivaz, com 10 a 30 cm de altura; raízes delicadas e fibrosas; caules com vários ramos, uns floridos e eretos, outros estéreis e deitados; folhas pequenas, pecioladas, cordiformes, arredondadas, obtusas, mais ou menos aveludadas, opostas; flores azul-violáceas, róseas ou esbranquiçadas. Sabor amargo.  Constitui', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Heracleum', E'', '', E'HERACLEUM SPHONDYLIUMANTIEPLÉPTICO.Heracleum', '', E'Heracleum sphondylium Umbelliferae (Apiaceae) Sob ponto de vista antroposófico Esta Umbelífera, típica dos campos, cresce nos prados úmidos-sombreados e ácidos ou em clareiras úmidas. Nesta planta, o tipo Umbelífera aparece de uma maneira menos delicada do que nas outras. O princípio aromático retirou-se quase que totalmente devido ao meio aquoso, sombreado e ácido. A variabilidade extrema da forma foliar do Heracleum exprime este conflito. A folha é ora simples, com bordos unidos, ora recortada', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Herniária', E'', '', E'HERNIARIA GLABRA L.DIURÉTICAS, ANTISÉPTICAS E LIGEIRAMENTE ESPASMOLÍTICAS.INFLAMAÇÕES DAS VIAS URINÁRIAS, DOS RINS E DA VESÍCULA BILIAR.Herniária', '', E'Herniaria glabra L. Caryophyllaceae  Planta herbácea anual, por vezes vivaz, possuindo um caule ramificado, rasteiro, formando tapetes. As pequenas folhas ovais são sésseis, dando origem, nas axilas, a cachos de pequenas flores brancas. O fruto é uma cápsula que contém sementes castanhoescuras (em baixo à direita). A espécie, originária da Europa e da Ásia, cresce em substratos pobres, arenosos, ao longo dos caminhos e dos riachos. A herniária era utilizada antigamente para tratamentos das vias', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Hissopo', E'', '', E'HYSSOPUS OFFICINALISPERTURBAÇÕES GÁSTRICAS E PEITORAIS.AFECÇÕES DO APARELHO RESPIRATÓRIO: TOSSE, TOSSE CONVULSIVA, BRONQUITE, ASMA.INFLAMAÇÃO DAS VIAS URINÁRIAS, DOS RINS E DA VESÍCULA.Hissopo', '', E'Hyssopus officinalis Labiatae (Lamiaceae) Sob ponto de vista antroposófico O Hissopo possui um caule ornado de flores finamente lanceoladas e estreitas; esta planta traz em sua extremidade uma inflorescência que se volta apenas para um lado da planta, com flores azuladas ou violetas, reunidas em falsas espigas, projetando para fora delas seus estames. A pátria do Hissopo é a Europa meridional e os locais secos da Ásia ocidental (Turquia, regiões do mar Cáspio, regiões do mar Aral). Encontramos e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Hortelã Pimenta', E'', '', E'COLEUS AMBOINICUS LOUR.,HORTELÃ GROSSA, MALVARIÇO E HORTELÃ-GRANDE.ANTI-SÉPTICO BUCAL E BALSÂMICO, ÚTIL PARA INFLAMAÇÕES NA BOCA E GARGANTA, ROUQUIDÃO, TOSSE E BRONQUITE. Hortelã pimenta', '', E'Nome científico: Coleus amboinicus Lour. Espécie herbácea, perene, da família Labíatae, originária da Ásia, também conhecida como hortelã grossa, malvariço e hortelã-grande. Tem folhas grandes e suculentas, lembrando o falso-boldo. Contém mucilagens e óleo essencial rico em timol. É um vegetal indicado como anti-séptico bucal e balsâmico, útil para inflamações na boca e garganta, rouquidão, tosse e bronquite. Pode ser preparado o xarope com 30 a 40 folhas frescas aquecidas com 150 a 200 g de açú', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Imperatória', E'', '', E'PEUCEDANUM OSTRUTHIUM W.D.J. KOCHTÔNICO ESTOMACAL,ESTIMULANTE DAS GLÂNDULAS DIGESTIVAS E SALIVARES,SUDORÍFICO, DIURÉTICO,EXPECTORANTE.ANTIESPASMÓDICA .EPILEPSIA E O DELIRIUM TREMENS.VULNERÁRIO.Imperatória', '', E'Peucedanum ostruthium W.D.J. KOCH syn.: Imperatoria ostruthium L. Umbelliferae (Apiaceae) Sob ponto de vista antroposófico  Esta planta habita os Pirineus e os Alpes. Ela cresce nos prados e nos planaltos de altitude, junto aos cursos de água que escorrem das geleiras junto às rochas, às margens dos riachos, medrando entre 1.500m e 2.700m. Esta planta estabelece um confronto entre a rocha fragmentada, esmigalhada, e penetrada de água, por um lado, e por outro lado entre o ar e a luz das alturas.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Inula', E'', '', E'INULA HELENIUM L.CATARROS BRÔNQUICOS.VÔMITOS, SOLUÇOS E FLATULÊNCIA.Inula', '', E'Inula helenium L. Asteraceae (Compositae) Sob ponto de vista antroposófico A Inula é uma composta que se destaca um pouco do tipo da família, porque ela desenvolve folhas inabitualmente grandes e numerosas. De seu rizoma ramificado ascende, atingindo cerca de um metro, um caule vigoroso, vertical, contornado por folhas longas, largas, oval-pontudas, inteiras, com bordos grosseiramente denteados. Tais folhas estão inseridas num caule que se bifurca várias vezes na parte apical produzindo na ponta', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ipê Roxo', E'', '', E'TABEBUIA IMPETIGINOSA (MART.) STANDL.,IPÊ-ROSA, IPÊ-PIONGA, IPÊ-PRETO, AIPE, PAU-D''ARCO.AFECÇÕES DA PELE (IMPIGENS, COCEIRAS E SARNAS), INFLAMACCÕES NA BOCA, ESTOMATITE, ÚLCERAS GÁSTRICAS, ARTRITE, LEUCORRÉIA, DIABETE,. ALÉM DE ANTIINFLAMATÓRIO, APRESENTA ATIVIDADES ANTIÁLÉRGICO, ANTIRNICROBIANA,ANTICANCERIGENA, ANTIMALÁRICA. E ANTIHEMORRÁGIIPÊ ROXO', '', E'Nome científico: Tabebuia impetiginosa (Mart.) Standl.  Família: Bignoniaceae. Origem: América Tropical. Sinonímia: Ipê-rosa, ipê-pionga, ipê-preto, aipe, pau-d''arco.  Descrição: árvore de 8 a 12 m de altura (20-30 metros no interior da mata), copa arredondada, de cerca de 6 m de diãmetro, formada no alto do tronco. Apresenta folhas opostas, constituídas por cinco folíolos pilosos e oblongos. Flores de cor rosa-arroxeada, dispostas em panículas quase em forma de umbelas e frutos em cápsulas comp', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ipeca', E'', '', E'CEPHAELIS IPECACUANHATOSSES, BRONQUITE, TOSSE AGUDA, COQUELUCHE E DISENTERIA E AMÉBICA.INDUZIR VÔMITO EM CRIANÇAS.Ipeca, ipecacuanha', '', E'Cephaelis ipecacuanha Rubiaceae Relacionadas ao gênero Psychotria e Palicourea, as aproximadamente 180 espécies do gênero Cephaelis são arbustos e pequenas árvores perenes que acontecem em várias partes das regiões tropicais. Muitas espécies são conhecidas por conter alcalóides. Só Cephaelis ipecacuanha, um arbusto esbelto, perene, com raiz rastejante brilhante, folhas ovaladas pontudas, que cresce expontamente sob a copa das florestas tropicais brasileiras, é amplamente cultivado em Cingapura e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Jambolão', E'', '', E'EUGENIA JAMBOLANA LAM.ANTIDIABÉTICO.MALES DOS RINS, INFECÇÕES DA BEXIGA, HEMORRAGIA E COMO DEPURATIVOJambolão', '', E'Nome científico: Eugenia jambolana Lam.  Espécie de porte arbóreo, da família Myrtaceae, nativa do Brasil. O pó das sementes é empregado como antidiabético (ingerir de 1/2 a 1 grama da semente em pó, 2 a 3 vezes ao dia; pilar alguns frutos de modo a fazer sair todo o suco, tomar 2 gotas diluídas em meio copo d''água, 3 vezes ao dia). As cascas, sob decocção, são utilizadas para males dos rins, infecções da bexiga, hemorragia e como depurativo (20 g da casca em 1 litro de água durante 15 minutos,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Jambu', E'', '', E'SPILANTHES OLERACEA L.ANEMIA, DISPEPSIA, AFECÇÕES DA BOCA E GARGANTA,SIALOGOGO E ESTOMÁQUICO.ANALGÉSICO LOCAL.Jambu', '', E'Nome científico: Spilanthes oleracea L.  Planta herbácea, anual, prostrada, com capítulos globosos de flores amarelas. Pertence à família Compositae, sendo nativa do Brasil. Contém espilantina, afinina, espilantol, filosterina e colina. As folhas e capítulos, na forma de infusáo ou tintura, são usados contra anemia, dispepsia, afecções da boca e garganta, como sialogogo e estomáquico. Os capítulos têm efeito analgésico local. Além de serem um dos ingredientes do pato no tucupi, famoso prato regi', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Jatobá', E'', '', E'HYMENAEA SPP.ADSTRINGENTE, SEDATIVA E CARMINATIVA.INFLAMAÇÕES DA BEXIGA E PRÓSTATA.HEMORRAGIA, DISENTERIA,DIARRÉIA E DISPEPSIA.Jatobá', '', E'Nome científico: Hymenaea spp.  Espécie arbórea, da família Leguminosas, nativa do Brasil. Como princípios ativos, contém óleo essencial, tanino e resina. Tem a ação adstringente, sedativa e carminativa. O decocto da casca é usado principalmente nas inflamações da bexiga e próstata. Aconselhado em casos de hemorragia, disenteria,diarréia e dispepsia. Para combater a tosse e a bronquite, mistura-se a polpa do fruto ou a resina com igual quantidade de mel. Multiplica-se por sementes.  Ô', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Jenipapo', E'', '', E'GENIPA AMERICANA L.DIARRÉIA E PROBLEMAS RENAIS, PRINCIPALMENTE CÓLICAS.DIURÉTICO, CONTRA ENTERITE, HIDROPISIA, ASMA E ANEMIA.ÚLCERAS, JÁ A RAIZ É PURGATIVA.Jenipapo', '', E'Nome científico: Genipa americana L. Espécie arbórea, da família Rubiaceae, originária da América tropical. As folhas são utilizadas popularmente para casos de diarréia e problemas renais, principalmente cólicas (3 folhas grandes em 1 litro d''água, em infusão). o suco da fruta é digestivo, diurético, contra enterite, hidropisia, asma e anemia. A casca, em banhos, é usada para tratar úlceras, já a raiz é purgativa. As folhas e frutos podem ser usados como forrageiras. Multiplica-se por sementes,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Jurubeba', E'', '', E'SOLANUM PANICULATUM L.PROBLEMAS DE FÍGADO, ESTÔMAGO E BAÇO.CICATRIZASTE.APERIENTE E DIGESTIVO.Jurubeba', '', E'Nome científico: Solanum paniculatum L. Espécie arbustiva, perene, da família Solanaceae, nativa do Brasil. Toda a planta é rica em substãncias amargas e mucilaginosas. Indicam-se os frutos para problemas de fígado, estômago e baço (tomar 1 colher (sopa) do suco dos frutos, de 2 em 2 horas). As folhas frescas, na forma de cataplasma, são utilizadas como cicatrizaste. O decocto da raiz, folhas e frutos é indicado como aperiente e digestivo. Recomenda-se evitar o uso prolongado dessa planta, pode', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Labiatas', E'', '', E'LABIATAEDEPENDE DA ESPÉCIELabiatas - Labiatae (Lamiaceae)', '', E'Plantas do Calor (Sob ponto de vista antroposófico) As Labiatas, com suas 3.000 espécies, constituem uma autêntica família de plantas medicinais. Via de regra, uma família botânica possui um certo número de espécies medicinais; aqui, entre as Labiatas, acontece um fenômeno raro e singular: todas as espécies de Labiatas possuem tais virtudes. Uma planta medicinal nos chama a atenção por ser uma variante unilateral do tipo de sua família (NT: por exemplo, o Girassol e a Margarida são exemplos típi', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Lágrima De Nossa Senhora', E'', '', E'COIX LACRYMA JOBI L.REUMATISMO.ASMA,LOMBALGIA, INCHAÇO E MALES DOS RINS,DIURÉTICA.Lágrima de nossa senhora', '', E'Nome científico: Coix lacryma Jobi L. Espécie herbácea, anual, da família Gramineae, originária da índia. Seus frutos são duros, globosos e de coloração cinza, na forma de tintura são usados no tratamento de reumatismo. As folhas, internamente, são indicadas contra asma, no tratamento de lombalgia, inchaço e males dos rins, apresentam também atividade diurética. Os frutos, reduzidos a pó, produzem farinha comestível, esta é indicada para crianças e convalescentes por ser nutritiva e fortificante', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Lambari', E'', '', E'STACHYS BYZANTINA C. KOCK.,LAMBARIZINHO, PEIXE-DE-POBRE, ORELHA-DE-LEBRE, SÁLVIA-PELUDACALMANTE.Lambari', '', E'Nome científico: Stachys byzantina C. Kock. Planta perene, rasteira, com folhas muito pilosas, verdeprateadas. Pertence à família Labiatae, sendo também conhecida como lambarizinho, peixe-de-pobre, orelha-de-lebre, sálvia-peluda etc. Originária do Cáucaso (Turquia) As folhas são utilizadas com calmante. Apresenta uso popular semelhante ao da sálvia. As folhas são empregadas na alimentação, fritas à milanesa. Multiplica-se pelas inúmeras brotaçóes laterais produzidas, que, separadas, são mudas já', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Laranjeira Da Terra', E'', '', E'CITRUS AURANTIUM L.CALMANTE,FEBRÍFUGO E SUDORÍFERO,TAQUICARDIA.PROBLEMAS DIGESTIVOS.FRAGILIDADE DOS VASOS CAPILARES,Laranjeira da terra', '', E'Nome científico: Citrus aurantium L. Árvore de pequeno ou médio porte, da família Rutaceae, originária do sudoeste asiático. As folhas atuam como calmante, febrífugo e sudorífero e são também usadas contra taquicardia. O chá (infusão) da casca do fruto é indicado para problemas digestivos. Quando a laranja começa a amarelecer, retira-se a casca, deixando-a secar; depois de desidratada, reduz-se a pó. É um excelente remédio para o tratamento da fragilidade dos vasos capilares, sendo a hesperidina', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Lauroceraso', E'', '', E'PRUNUS LAUROCERASUS L.ATUA NA RESPIRAÇÃO E NO CORAÇÃO.Lauroceraso', '', E'Prunus laurocerasus L. Rosaceae Sob ponto de vista antroposófico Esta pequena árvore, proveniente da Ásia Ocidental e do Sul da Europa, se destaca sobretudo em seu processo de formação de grandes folhas esbeltas e desenvolvidas, duras, brilhantes e persistentes. Seus pequenos cachos florais elevados, branco-esverdeados, condensados, produzem pequenas cerejas negras que não chamam muito a atenção. As florestas montanhosas úmidas são seu habitat preferido. O processo cianeto, contido nas sementes', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Leonurus', E'', '', E'LEONURUS CARDIACAAMENORRÉIA, A DISMENORRÉIA,ESTERILIDADE,TRANSTORNOS DA MENOPAUSA;PALPITAÇÕES CARDÍACAS,ANGÚSTIA CARDÍACA,DISPNÉIA, NA DEBILIDADE CARDÍACA COM DIMINUIÇÃO DO PULSO,ANGINA DO PEITO,Leonurus', '', E'Leonurus cardiaca Labiatae (Lamiaceae) Sob ponto de vista antroposófico Leonurus cardiaca é uma planta asiática que medra nos escombros. Na Europa, ela cresce ao longo das cercas e vegeta nos prados secos. Esta planta se abstém de separar a gênese floral da gênese foliar, tal como acontece no marrubiun, fazendo com que a gênese floral desça até o domínio rítmico, típico do elemento foliar. Os falsos verticilos das flores vermelhas, em forma de bocas abertas, brotam junto à insersão das folhas co', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Levante', E'', '', E'MENTHA VIRIDIS L., ALEVANTE, ELEVANTE E HORTELÃ SILVESTREANTI-HELMÍNTICO. ANTIESPPAMÓDIEO, VERMÍFUGO E CALMANTE.LEVANTE', '', E'Nome científico: Mentha viridis L. Família: Labiatae. Origem: Europa, Ásia e África. Sinonímia: alevante, elevante e hortelã silvestre.  Descrição: planta herbácea rizomatosa (caules subterrâneos) que emite haste quadrangular de coloração verde ou arroxeada; folhas de aroma característico; flores com corola pequena e violácea.  Constituintes químicos principais: óleo essencial contendo mentol, pulegona e fenóis.  Indicaçoes: anti-helmíntico. Antiesppamódieo, vermífugo e calmante.  Parte usada: t', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Levístico', E'', '', E'LEVISTICUM OFFICINALE W.D.J. KOCHMALES DO ESTÔMAGO,DISPEPSIA E PERTURBAÇÕES CARDÍACAS LIGADAS A PROBLEMAS GÁSTRICOS E INTESTINAIS.DIURÉTICO.HIDROPSIA DO CORAÇÃO E NAS INCHAÇÕES EDEMATOSAS,CISTITE, NA ALBUMINURIA,NEFROPATIAS E DORES DE CABEÇA .COMBATE OS SUORES MAL CHEIROSOSLevístico', '', E'Levisticum officinale W.D.J. KOCH Umbelliferae (Apiaceae) Sob ponto de vista antroposófico  Sua forma selvagem parece provir das montanhas da Pérsia. O Levisticum medra nos declives montanhosos do Sul da Europa, onde vive até a altitude de 2.700m. Sua raiz principal é curta e ramificada em raízes secundárias longas e espessas que se enterram numa profundidade de cerca de meio metro. Este órgão fundamental resulta de uma longa e intensa fase de aspiração do ar, da luz e da astralidade cósmica que', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Licopódio', E'', '', E'LYCOPODIUM CLAVATUM L.PROBLEMAS DO FÍGADO.DORES, E ESPASMOS NOS BRAÇOS OU PERNAS.BENEFICIA A DIGESTÃO,ESTIMULA O ÚTERO.DESORDENS URINÁRIAS E DO RIM, CISTITE,GASTRITE,ARTRITE REUMATÓIDELicopódio', '', E'Lycopodium clavatum L. Lycopodiaceae Este grande gênero cosmopolita consiste de cerca de 450 espécies de musgos sempre verdes, perenes que podem ser de hábito terrestre ou epífito; Lycopodium é encontrado em todas zonas temperadas. São plantas primitivas, com folhas pequenas em formato de escamas ou agulhas, reproduzindo-se através de esporos. Esporos de licopódio são usados em experiências de som pois são tão finos que vibram nos padrões das ondas de som, e também para efeitos em cenas e fogos', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Licopus', E'', '', E'LYCOPUS VIRGINICUSTÔNICO CARDÍACO,ANGÚSTIAS CARDÍACAS,DILATAÇÃO DO CORAÇÃO,TAQUICARDIA LIGADA À SÍNDROME DE BASEDOW.ICTERÍCIA,Licopus', '', E'Lycopus virginicus Labiatae (Lamiaceae) Sob ponto de vista antroposófico Esta pequena e estirada planta aperfeiçoou seu ritmo foliar superpondo nós cujas folhas escondem, junto à intersecção da folha com o caule, minúsculas coroas de pequenas flores brancas. A iNflorescência está totalmente colocada dentro da arquitetura foliar. Como na espécie anteriormente estudada (Leonorus cardiaca), as folhas estão profundamente divididas, penadas. O Lycopus virginicus cresce na América do Norte, na beira d', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Limão Bravo', E'', '', E'PODOPHYLLUM PELTATUMPURGATIVO, EMÉTICO,VERMÍFUGO E TÔNICO DO FÍGADO,VERRUGAS.Limão bravo', '', E'Podophyllum peltatum Berberidaceae O gênero Podophyllum conta com cerca de 10 espécies perenes, distribuídas ao longo da América do Norte e Himalaia. Podophyllum Peltatum, encontrada na América do Norte oriental, é uma planta das regiões de bosque, perene, com um rizoma vermelho-marrom, talos longos de até 2m, folhas entrecortadas como as da anêmona. Na primavera as flores brancas são seguidas de frutos amarelos parecidos com ameixas. Os frutos têm sabor de limão e são comestíveis, mas todas as', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Língua De Vaca', E'', '', E'CHAPTALIA NUTANS POLAR.BLENORRAGIA, CATARRO PULMONAR, DERMATOSES, TOSSE, DORES DE CABEÇA.TUMOR, INFLAMAÇÃO, REUMATISMO.Língua de vaca', '', E'Nome científico: Chaptalia nutans Polar.  Espécie nativa do Brasil, herbácea, perene, da família compositae. As raízes e folhas possuem gosto amargo, sendo utilizadas em blenorragia, catarro pulmonar, dermatoses, tosse, dores de cabeça (popularmente as folhas são colocadas sobre a testa). Indicada pelos índios do sul do Brasil contra tumor, inflamação, cólica abdominal, disenteria, ferimentos expostos (suco das  folhas) e reumatismo. Multiplica-se por sementes.  Língua-de-vaca Rumex ssp Polygona', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Líquen Da Isl', E'', '', E'ÂNDIACETRARIA ISLANDICA (L.) ACH.GASTROENTERITE,INTOXICAÇÃO GASTRINTESTINAL,TUBERCULOSE E BRONQUITE. LAVAGEM VAGINAL,FURÚNCULOS E IMPETIGO. Líquen da islândia, Musgo-da-islândia', '', E'Cetraria islandica (L.) ACH. Parmeliaceae O gênero Cetraria consta de 40 espécies de líquens encontrados no mundo inteiro, especialmente nas regiões Árticas. Várias espécies são ecologicamente importantes como alimento para as renas. Desde tempos antigos os líquens foram usados para medicamentos, tinturas e perfumes. Eles não são cultivados e agora são raros no estado selvagem devido à poluição moderna; muitos herbolários atualmente só usam tratamentos a base de líquens em casos especiais. Cetra', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Lírio Dos Vales', E'', '', E'CONVALLARIA MAJALIS L.TRATAMENTO DE DOENÇAS CARDÍACAS,ESTIMULAM O RITMO DO CORAÇÃO E A RESPIRAÇÃO (CARDIOTÔNICOS).Lírio dos vales', '', E'Convallaria majalis L. Liliaceae (Convallariaceae) Há três espécies de plantas perenes rizomosas no gênero Convallaria, que ocorrem nas regiões temperadas do norte. A origem do nome vem do latim "convallis", vale, e se refere ao hábitat natural da planta, enquanto majalis significa o tempo de florescimento que ocorre no mês de maio. Convallaria majalis, Lírio-dos-vales ou Lírio-demaio, é uma planta herbácea perene dotada de uma rede subterrânea de rizomas emaranhados que produzem, na Primavera,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Losna', E'', '', E'ARTEMÍSIA ABSINTHIUM L.,LOSMA, ABSINTO, ACINTO, ERVASANTA, ALVINA, ALUÍNA, FLOR-DE-DIGNA, GOTAS AMARGAS E ERVA-DOS-VERMESTONICA, ESTIMULANTE. APERIENTE, VERRMÍFUGA (LOMBRIGÁS), ANTIPIRÉTICA, EMENAGOGA A E COLAGOGA. AUXILIA NO TRATAMENTO DE DIABETES E DISTÚRBIOS DIGESTIVOS CAUSADOS PELO MAU FUNCIONAMENTO DO FÍGADO.LOSNA', '', E'Nome científico: Artemísia absinthium L. Família: Compositae. Origem: Ásia, Europa e Norte da África. Sinonímia: losma, absinto, acinto, ervasanta, alvina, aluína, flor-de-digna, gotas amargas e erva-dos-vermes. Descrição: planta herbácea, perene, de 0,40 a 1 m de altura; folhas pinatissectas, de cor esverdeada na parte superior e branco-prateada na parte inferior, flores amareladas eni cachos. Sabor amargo e odor característico. Constituintes químicos principais: óleo essencial contendo absinti', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Louro', E'', '', E'LAURUS NOBILIS L.NEVRALGIAS, GASES, BRONQUITE,REUMATISMO, DIGESTIVO, ARTICULAÇÕES INFLAMADAS.Louro', '', E'Nome ciêntifico: Laurus nobilis L.  Espécie arbórea, da família Lauraceae, originária do Mediterrâneo. Planta indicada em nevralgias, gases, bronquite, reumatismo e como digestivo. Infuso estomacal: 1 folha de louro picada, 1 xícara (chá) de água fervente, abafar por 10 minutos, após amornar, coa-se e adicionamse gotas de limão. Tornar 1 xícara (chá) em jejum e outra 1/2 antes das refeições. Decocção: 10 folhas de louro fatiada, 1/2 litro de água, ferver por 10 minutos e coar, colocar em urna ba', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Macae', E'', '', E'LEONURUS SIBIRICUS L., ERVA-MACAÉ, JOÃO-MAGRO, MARROIO, QUININO-DOS-POBRES, MANÉMAGRO, LAVANTINA, MARÉ-TURÉ, RUBIM E PAU-PRA-TUDO.ESTOMÁQUICO, FEBRÍFUGO, ANTIREUMÁTICO, EUPÉPTICO, VÕMITOS E GASTRINTERITE. AS FLORES SÃO USADAS PARA BRONQUITE E COQUELUCHE.MACAÉ', '', E'Nome científico: Leonurus sibiricus L. Família: Labiatae. Origem: Ásia (Sibéria).  Sinonímia: erva-macaé, joão-magro, marroio, quinino-dos-pobres, manémagro, lavantina, maré-turé, rubim e pau-pra-tudo.  Descrição: erva de 0,40 a 1,20 m de altura; ramos e caules quadrangulares; folhas opostas; flores pequenas em glomérulos róseos ou avermelhados com lobos espiniformes no caule.  Constituintes químicos principais: leonurina, taninos e óleo essência.  Indicações: estomáquico, febrífugo, antireumáti', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Macela', E'', '', E'ACHYROCLINE SATUREIOIDES D.C., MACELA-DO-CAMPO, MACELINHA, MACELA-AMARELA, CAMOMILA-NACIONAL, CARRAPICHINHO-DE-AGULHA E MARCELAANTIESPASMÓDICA, ANTI-INFLAMATÓRIA, ANTISSÉPTICA, CALMANTE E PARA PROBLEMAS DIGESTIVOSMacela', '', E'Nome científico: Achyrocline satureioides D.C.  Família: Compositae. Origem: Brasil. Sinonímia: macela-do-campo, macelinha, macela-amarela, camomila-nacional, carrapichinho-de-agulha e marcela.  Descrição: planta herbácea, ereta, ramificada; caule cilíndrico e piloso, com até 1,5 m de altura; folhas sésseis, lineares ou lanceoladas; flores em capítulos amarelos.  Constituintes químicos principais: quercitina, luteolina, galangina, ésteres de colerianina, isognafalina e monoterpenos.  Indicações:', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Macela Dourada', E'', '', E'CHAMAEMELUM NOBILE (L.) ALL.ANTI-INFLAMATÓRIAS,DESINFETANTES E DIAFORÉTICAS.ACALMAR O SISTEMA NERVOSO,REDUZIR AS CONTRAÇÕES MUSCULARES,AFECÇÕES GINECOLÓGICAS.Macela dourada', '', E'Chamaemelum nobile (L.) ALL. syn.: Anthemis nobilis L. Asteraceae (Compositae) Planta herbácea perene com caule rasteiro e ramificado, sustentando folhas alternas muito segmentadas. O caule termina num capítulo formado por flores liguladas periféricas e tubulosas centrais ou, nas variedades melhoradas e mais procuradas, unicamente por flores liguladas. São colhidos os capítulos desabrochados, quando o tempo está quente e seco, à mão ou com um instrumento simples que permita cortar a flor sem o p', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Macelinha', E'', '', E'ANTHEMIS COTULA L.VÔMITOS, ANTI-HISTÉRICA, PARASITICIDA, SUDORÍFERA, FEBRÍFUGA,ANTIESPASMÓDICA, VULNERÁRIA E ANTIARTRÍTICA.Macelinha', '', E'Nome ciêntico: (Anthemis cotula L.)  Erva rasteira, perene, da família Compositae. Originária da Europa. Tem ação contra vômitos, anti-histérica, parasiticida, sudorífera, febrífuga (febres intermitentes) e antiespasmódica. Externamente, é vulnerária e antiartrítica. As folhas são usadas em infusão ou maceração. os capítulos (flores), reduzidos a pó, exterminam a pulga dos cães. Multiplica-se por sementes ou divisão de touceiras. Planta que exige regas freqüentes.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Malva Cheirosa', E'', '', E'PELARGONIUM GRAVEOLENS AIT.EXPECTORANTE, CALMANTE, EMOLIENTE,Malva cheirosa', '', E'Nome ciêntifico:(Pelargonium graveolens Ait.)  Planta perene, da família Geraniaceae, semelhante ao gerânio, originária da Europa. As folhas apresentam forte aroma. É expectorante, calmante, emoliente, usada em infecções de garganta e brôquios. Empregada na forma de xarope e infusão. Normalmente, é utilizada em ornamentação, desenvolvendo-se melhor em terra rica em matéria orgânica. Multiplica-se por estaquia.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Malva Da Índia', E'', '', E'ALCEA ROSEA L.INFLAMAÇÕES CRÔNICAS DO ESTÔMAGO E DOS INTESTINOS,OBSTIPAÇÃO.TRATAMENTO DE DOENÇAS DA PELE.Malva da índia', '', E'Alcea rosea L. Syn.: Althaea rosea (L.) CAV. Malvaceae O gênero Alcea consta de 60 espécies de plantas bienais ou perenes de curta duração e ocorrem desde o mediterrâneo até a Ásia Central. Várias espécies são cultivadas devido suas flores vistosas. Alcea rosea chegou à Europa no 16º século oriunda da China ou do Oriente Médio, talvez da Turquia, e se tornou uma popular planta ornamental e também erva medicinal. O nome Alcea deriva do grego alkaria, significando malva. Alcea rosea, malvaísco ou', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mandrágora', E'', '', E'MANDRAGORA OFFICINARUMESTERILIDADE.SEDATIVA, ANALGÉSICA,TRATAMENTO DE DESORDENS NERVOSAS.Mandrágora', '', E'Mandragora officinarum Solanaceae Este gênero é composto por seis espécies de ervas perenes, sem caules, em formato de pequenas rosetas de folhas ovaladas, com grandes raízes bifurcadas que lembram formas humanas, distribuídas desde regiões mediterrâneas até o Himalaia. Mandragora é o antigo nome grego para a planta e pode ser uma corrupção de nam tar ira "droga masculina de Namtar" (Assíria), uma vez que a planta era reputada por curar esterilidade. Mandragora officinarum medra em encostas roch', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Manjericao', E'', '', E'OCIMUM SPP., ALFAVACA, BASILICÃO, MANJERICÃO-DA-FOLHA-LARGA, ERVA-REAL E ALFAVACÃOESTIMULANTE, DIGESTIVA, ANTIESPASMÓDICA GÁSTRICA, GALACTAGOGA, BÉQUICA, ANTI-REUMÁTICA, ANTI-SÉPTICA, CARMINATIVA, TÔNICA E RELAXANTE MUSCULARMANJERICÃO', '', E'Nome científico: Ocimum spp. Família: Labiatae. Origem: Ásia (Índia) e África (Egito).  Sinonímia: alfavaca, basilicão, manjericão-da-folha-larga, erva-real e alfavacão.  Descrição: planta herbácea, ramificada, atinge cerca de 0,60 m de altura; folhas simples, opostas, ovais; flores brancas a levemente rosadas, labiadas, em cachos terminais espiciformes; fruto do tipo aquênio.  Constituintes químicos principais: timol, estragol, metilchavicol, linalol, cânfora e taninos.  Indicações: é uma plant', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Manjerona', E'', '', E'ORIGANUM MAJORANAREGULARIZAR O RITMO MENSTRUAL.FORTIFICA O ESTÔMAGO E O INTESTINO, CURA AS CÓLICAS, AS DIARRÉIAS, FAVORECE A CONCEPÇÃO E A MENSTRUAÇÃO.ANTI-ESPASMÓDICAS NA ASMA,Manjerona', '', E'Origanum majorana Labiatae (Lamiaceae) Sob ponto de vista antroposófico A Manjerona é originária do sul da Europa, mas ela também cresce em locais mais altos e rochosos tão bem quanto nos solos quentes e leves dos jardins tratados pela mão aplicada do homem. A semente que germina exige sombra. A planta se apresenta de uma forma equilibrada e delicadamente cinzelada. Ela possui, desde baixo, um aroma docemente apimentado. A inflorescência se assemelha a uma pequena colméia; ela esconde por bastan', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Maracujá', E'', '', E'PASSIFLORA EDULIS SIMS.INQUIETAÇÃO NERVOSA, IRRITAÇÃO FREQÜENTE E INSÔNIA.Maracujá', '', E'Nome ciêntifico: (Passiflora edulis Sims.)  Trepadeira de caule cilíndrico, semi-perene da família Passifloraceae, originária da América tropical. As folhas são utilizadas sob a forma de infusão na dose de 4 a 6 g por xícara (chá). Torna-se 1 a 2 xícaras (chá) à noite. É usada contra inquietação nervosa, irritação freqüente e contra insônia. O uso das folhas deve ser controlado por causa de riscos de intoxicação cianídrica, devidos a doses altas. A multiplicação é feita por sementes e deve-se te', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Maravilha', E'', '', E'MIRABILIS JALAPA L., BONINAPURGATIVA, DIURÉTICA, ANALGÉSICA.MANCHAS DE PELE (SARDAS) E HERPES.DORES DE OUVIDOMaravilha', '', E'Npme científico: Mirabilis jalapa L. Planta ornamental herbácea,perene, da família Nyctaginaceae, originária da América tropical, também conhecida como bonina. Possui flores brancas, avermelhadas ou róseas; o fruto é semelhante à pimenta-do-reino; as sementes são extremamente venenosas, por isso nunca devem ser usadas. As flores e raízes têm propriedades: purgativa, diurética, analgésica.O suco das folhas é usado contra manchas de pele (sardas) e herpes. No caso de dores de ouvido, colocar 2 a 3', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Margarida Comum', E'', '', E'BELLIS PERENNIS L.ADSTRINGENTE E EMOLIENTE.CATARROS DAS VIAS RESPIRATÓRIAS.EXPECTORANTE.CATARROS DO ESTÔMAGO.VEIAS VARICOSAS, FERIDAS SECUNDÁRIAS,EQUIMOSES,Margarida comum', '', E'Bellis perennis L. Asteraceae (Compositae) O gênero Bellis consiste de sete espécies de arbustos anuais ou perenes, nativos na Europa e mediterrâneo. Plantas deste gênero são muito cultivadas e algumas delas podem mesmo ser consideradas como bianuais. Elas são facilmente cultivadas e têm uma estação prolongada de florescimento. O nome Bellis vem do latim "bellus", bonito. Bellis perennis é uma planta herbácea perene que faz parte da componente adventícia dos solos com ervas em abundância. A sua', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Maria Gorda', E'', '', E'TALINUM PATENS WILLD., ORA-PRO-NÓBIS MIÚDO, CARIRU, LÍNGUA-DE-VACA, BELDROEGA-MIÚDA, LABROBRÓ, BÊNÇÃO-DE-DEUS, MAJOR-GOMES, BREDO, CARURU, ERVA-GORDA, JOÃO-GOMES, MARFA-GOMES E LABROBRÓ-DE-JARDIM.BÉQUICA. CICATRIZANTE, DIURÉTICA E DEPURATIVA,. USADA, AINDA, PARA PROBLEMAS GASTRINTESTINAIS. AS RAÍZES SÃO  ANTIESCORBÚTICAS.Maria-gorda', '', E'Nome científico: Talinum patens Willd. Família: Portulacaceae. Origem: Américas.  Sinonímia: ora-pro-nóbis miúdo, cariru, língua-de-vaca, beldroega-miúda, labrobró, bênção-de-deus, major-gomes, bredo, caruru, erva-gorda, joão-gomes, marfa-gomes e labrobró-de-jardim.  Descrição: erva ereta; folhas alternas, elípticas, carnosas e glabras; flores amarelas ou róseas, anteras amarelas, dispostas em panículas; fruto cápsula deiscente; raiz tuberosa.  Constituintes químicos principais: mucilagens e sai', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Maria Pretinha', E'', '', E'SOLANUM AMERICANUM MILL.NARCÓTICO, SEDATIVO E ANALGÉSICO,Maria pretinha', '', E'Solanum americanum Mill. Solanum nodiflorum Jacq. Solanum caribaeum Dun. Solanaceae Planta herbácea anual, reproduzida por semente. Folhas alternas, pecioladas, ovaladas ou rômbicas, com até 7cm de comprimento de coloração verde. Inflorescência axilar, com um pedúnculo de cujo ápice sai uma umbela ostentando até 6 pequenas flores. Flores com cálices de coloração verde com 5 lobos agudos; o cálice persiste até a maturação dos frutos. Corola com 5 lobos lanceolados, brancos ou com leve tonalidade', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Marmelinho', E'', '', E'TOURNEFORTÌA PANICULATA CHAM.DIURÉTICA,ELIMINAR CÁLCULOS RENAISMarmelinho', '', E'Nome científico: Tournefortìa paniculata Cham. Espécie nativa da Mata Atlãntica, de porte arbustivo, perene, pertecente à família Boraginaceae. De ação diurética, o decocto de suas folhas é recomendado para eliminar cálculos renais e pedras de qualquer origem. Multiplica-se por sementes e estacas. ê', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Marroio Branco', E'', '', E'MARRUBIUM VULGAREESTIMULA A FUNÇÃO HEPÁTICA E FAVORECE A MENSTRUAÇÃO,BRONQUITE CRÔNICA,COQUELUCHE E NA ASMA SENILMarroio branco', '', E'Marrubium vulgare Labiatae (Lamiaceae) Sob ponto de vista antroposófico Nesta planta, de maneira muito mais intensa ainda do que na melissa, o sistema de folhas, constituído pela superposição dos nós, numa disposição totalmente rítmica, é a característica que mais chama a atenção nessa planta. A partir das intersecções das folhas que emergem em cada nó, surgem pequenos agregados de florzinhas brancas e minúsculas, formando bolinhas como mostra o desenho. Esta planta se encontra em toda a Europa', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Marroio Negro', E'', '', E'BALLOTA NIGRA ROTH.CALMANTE.DEPRESSÃO, ENXAQUECA,NEURASTENIA, ESTADOS ANSIOSOS E OUTRAS AFECÇÕES NERVOSAS.NÁUSEAS DE MOVIMENTO,NÁUSEA MATUTINA EM GRAVIDEZ,DESORDENS MENSTRUAIS,RECLAMAÇÕES BRONQUIAIS.DIAFORÉTICO.Marroio negro', '', E'Ballota nigra Roth. Labiatae (Lamiaceae) Nativo na Europa, região mediterrânea e Ásia ocidental, o gênero Ballota contém 35 espécies de arbustos e sub-arbustos perenes robustos. A maioria das espécies são consideradas ervas daninhas, mas algumas têm folhagens aveludadas e são cultivadas como plantas ornamentais. Aparentemente o nome Ballota vem do grego "ballote", rejeitar, porque o gado evita estas plantas. Ballota nigra é uma planta adventícia perene, herbácea, com caules angulosos, ascendente', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Marupari', E'', '', E'ELEUTHERINE PLICATA HERB., QUEBRAPEDRAANTIDIARRÉICA E DIURÉTICA.AMEBÍASE.CÓLICAS E CÁLCULOS RENAISMarupari', '', E'Nome científico: Eleutherine plicata Herb. Planta herbácea, perene, da família Iridaceae, originária da América do Sul, apresenta bulbos avermelhados. Apresenta sapogenina esteroidal em sua constituição química. Tem ação antidiarréica e diurética. Indicada também contra amebíase. Em algumas regiões é utilizada contra cólicas e cálculos renais, sendo conhecida como quebrapedra. os bulbos são utilizados em decocção, na dosagem de 15 g de bulbos frescos em 1 litro d''água. Toma-se uma colher (sopa)', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Meimendro Negro', E'', '', E'HYOSCYAMUS NIGER L.EXTREMAMENTE TÓXICAS.ANTIASMÁTICOS, ESPASMOLÍTICOS.Meimendro negro', '', E'Hyoscyamus niger L. Solanaceae Planta anual ou bienal, possuindo um caule ereto com folhas alternas, dentadas, viscosas. Na axila das folhas formam-se flores cinzentoamareladas com veios violeta. O fruto é uma cápsula que contém abundantes sementes castanhas (em baixo à esquerda). Toda a planta é vilosa - penugenta e muito venenosa. É provavelmente originária das regiões mediterrâneas, mas cresce atualmente em toda a Europa e na Ásia. Encontra-se nos escombros, nos baldios, como adventícia das c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Melao De Sao Caetano', E'', '', E'MOMORDICA CHARANTIA L., FRUTO-DE-COBRA, FRUTO-DE-NEGRO, ERVA-DE-SÃO-CAETANO,ERVA-SÃO-VICENTE, MELÃOZINHO E ERVA-DE-LAVADEIRAPURGATIVO, FEBRÍFUGO, ANTILEUCORRÊICO, ANTICATARRAL, ANTI-REUMÁTICO. USADA PARA INFLAMAÇÕES HEPÁTICAS, DIABETES, CÓLICAS ABDÓRNINAIS, E, EXTERNAMENTE, PARA PROBLEMAS DE PELE, QUEIMADURAS, FURÚNCULOS E CONTRA HEMORRÓIDAS (FRUTO MADURO).MELAO DE SAO CAETANO', '', E'Nome científico: Momordica charantia L. Família: Cucurbitaceae. Origem: África. Sinonímia:fruto-de-cobra, fruto-de-negro, erva-de-são-caetano,erva-são-vicente, melãozinho e erva-de-lavadeira.  Descrição: cipó herbáceo, cheiro desagradável; ramos quadrangulares; folhas palmatífidas; flores amarelo-pálidas ou brancas em cachos ou corimbos; e fruto abrindo-se em três válvulas espinhosas, cor-de-ouro, tendo, no interior, as sementes cobertas de arilo vermelho.  Constituintes químicos principais: as', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mentrasto', E'', '', E'AAERATUM CONYZOIDES L.,CATINGA DE BODE, ERVA DE SÃO JOÃO E CATINGA DE BARRÃOANTI-REUMÁTICO (USO EXTERNO), ANTIDIARRÉICO, FEBRÍFUGO, ANTI-INFAMATÓRIO, CARMINATIVO, ERNENAGOGO, TÔNICO, ÚTIL CONTRA RESFRIADOS E CÓLICAS MENSTRUAIS. POPULARMENTE USADA EM BANHOS PELAS PARTURIENTES, PARA FACILITAR O TRABALHO DE PARTO.Mentrasto', '', E'Nome científico: Aaeratum conyzoides L. Família: Compositae. Origem: América do Sul. Sinonímia:catinga-de-bode, erva-de-sãojoão e catinga-de-barrão.  Descrição: erva anual, pilosa, ramosa; caule cilíndrico, até 1 m de altura; folhas ovadas, crenadas; flores esbranquiçadas ou lilases, dispostas em capítulos e estes em panículas; fruto tipo aquénio.  Constituintes químicos principais: resinas, cumarinas, mucilagens, alcalóides, óleos essenciais e ácido hidrocianídrico.  Indicações: anti-reumático', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mezereão', E'', '', E'DAPHNE MEZEREUM L.GERMICIDA, DIURÉTICO,EXPECTORANTE E LAXATIVO.Mezereão', '', E'Daphne mezereum L. Thymeleaceae Cerca de cinqüenta espécies de arbustos decíduos e perenes pertencem ao gênero Daphne que ocorre na Europa, África do Norte e Ásia. Daphnes são arbustos escolhidos para obtenção de madeira para confecção de caixilhos, pequenos batentes e recipientes, embora certas espécies, como a chinesa Daphne genkwa, sejam de difícil crescimento. Daphne é o termo grego para loureiro, talvez assim chamado porque algumas espécies tem folhas parecidas com as dos loureiros; na mito', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mil Folhas', E'', '', E'AQUILEIA MILEFOLIUM,MIL EM RAMA,MIL FLORES, AQUILEIA,ERVA DA CORTADURA, ERVA DO CARPINTEIRO, LEVANTE, MILEFOLIUMTONICO ESTOMACALMil-folhas', '', E'Nome científico: Achillea millefolium L. Família: Compositae. Origem: Europa. Sinonímia: milefólio, atroveran, erva-decortaduras, erva-dos-carreteiros, aquiléia, novalgina, mil-em-rama, macelão e ervade-carpinteiro.  Descrição: erva de 0,30 a 0,90 m de altura, perene; apresenta folhas bem recortadas; inflorescências brancas ou róseas; caule subterrâneo (rizoma); frutos do tipo aquênio.  Constituintes químicos principais: óleo essencial com azulenos, derivados terpênicos e sesquiterpênicos, lacto', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Milho', E'', '', E'ZEA MAYS L.DIURÉTICO , PROBLEMAS RENAIS.Milho', '', E'Nome científico: Zea mays L. Planta anual, da família Gramineae, originária do México e Peru, sendo uma das culturas mais antigas do mundo, havendo provas de que é cultivado há pelo menos 4.000 anos. O cabelo (estigma) é utilizado como diurético e para problemas renais. Pode ser empregado, depois de secos, na forma de infusão, tintura e xarope. Este xarope, misturado com água, constitui uma bebida para os doentes afetados por problemas renais. Mutiplica-se por sementes. ;', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mirtilo', E'', '', E'VACCINIUM MYRTILLUS L.DIARRÉIA.INFLAMAÇÕES DA BOCA E DA LARINGE. Mirtilo', '', E'Vaccinium myrtillus L. Ericaceae Arbusto baixo com ramos rastejantes que dão origem a caules angulosos de cor verde, ricamente ramificados e cobertos de folhas alternas, ovaladas (em baixo à direita) e caducas. Em baixo à esquerda, está representada a folha de Vaccinium vitis-idaea. As flores em forma de vesículas esverdeadas a rosadas aparecem isoladas na axila das folhas. Os frutos são bagas azuis. O mirtilo forma colônias extensas nas florestas altas, em substrato ácido, humoso, rico em resíd', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Morango Silvestre', E'', '', E'FRAGARIA VESCAANEMIAS.MEDICAMENTO PARA O FÍGADO.CATARROS INTESTINAIS E GÁSTRICOS, ACOMPANHADOS DE DIARRÉIAS.AFECÇÕES DAS VIAS URINÁRIAS E DOS RINS,Morango silvestre', '', E'Fragaria vesca Rosaceae Sob ponto de vista antroposófico Esta Rosácea representa uma variante unilateral do tipo; da mesma maneira que o Geum urbanum e a Potentilla, o morangueiro possui o tronco da árvore frutífera debaixo da terra; um tronco subterrâneo denominado rizoma. O rizoma rasteiro do morangueiro, que está dentro do solo, vai emitindo para fora do solo as folhas a as pequenas hastezinbas em cuja ponta estão as flores. O morangueiro produz na primavera flores brancas com cinco pétalas c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mostarda', E'', '', E'BRASSICA CAMPESTRES L., COLZA, COUVE, FALSO-NABO, NABEIRA, NABO-BRANCO E RUIBARBO.AS RAÍZES SÃO FORTIFICANTES E COMBATEM TUBERCULOSE E MOLÉSTIAS DO APARELHO URINÁRIO, INCLUSIVE CÁLCULOS RENAIS. AS SEMENTES MISTURADAS COM FARINHA DE MANDIOCA REDUZEM FURÚNCULOS E SERVEM PARA O TRATAMENTO DE FERIDAS. ANTICANCERÍGENA, REVULSIVA E VESICATÓRMOSTARDA', '', E'Nome científico: Brassica campestres L. Família: Cruciferae.  Origem: Europa.  Sinonímia: colza, couve, falso-nabo, nabeira, nabo-branco e ruibarbo.  Descrição: planta anual, ereta, atingindo cerca de 1 a 2 rn de altura; caule ramificado; folhas de formas variadas; flores amarelas, dispostas em cachos terminais; sementes castanho-escuras.  Constituintes químicos principais: indo) e isotiocinato de alila ou serevol (vesicante).  Indicações: as raízes são fortificantes e combatem tuberculose e mol', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mostarda Branca', E'', '', E'SINAPIS ALBA L.DORES REUMATISMAIS.Mostarda branca', '', E'Sinapis alba L. Cruciferae (Brassicaceae) Planta herbácea anual dotada de um caule ereto, simples, com folhas alternas, alongadas, liriformes e penatipartidas. O caule apresenta um cacho terminal de flores amarelas. O fruto é uma silíqua não deiscente na maturidade, contendo sementes amarelas e lisas. Toda a planta está coberta de pêlos ásperos. A espécie, originária das regiões mediterrâneas, é cultivada nos campos pelas suas preciosas qualidades forrageiras e oleaginosas. Antigamente, a mostar', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Mussambê', E'', '', E'CLEOME SPINOSA L.,BEIJO-FEDORENTO.BÉQUICA,RUBEFACIENTES,ASMA E BRONQUITE.Mussambê', '', E'Nome científico: Cleome spinosa L. Arbusto bianual ou perene da família Capparidaceae, originário do Brasil, espinhento, com flores de coloração rósea em racimos. Apresenta cheiro desagradável, daí o nome beijo-fedorento. As flores têm ação béquica, as folhas são rubefacientes, e as raízes são úteis contra asma e bronquite. Normalmente, é encontrada nas margens de rios e considerada planta ornamental. Multiplica-se por sementes. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Nogueira', E'', '', E'JUGLANS REGIA L.ADSTRIGENTES,PERTURBAÇÕES GÁSTRICAS E INTESTINAIS.PERTURBAÇÕES GÁSTRICAS E INTESTINAIS.HEMOSTÁTICO.FRIEIRASNogueira', '', E'Juglans regia L. Juglandaceae Árvore com casca de coloração inicialmente castanha, adquirindo, com a idade, um tom cinzento e uma superfície rugosa; as folhas imparifolioladas libertam um odor aromático. As flores estaminadas estão agrupadas em amentos,as flores pistiladas formam botões terminais. A nogueira floresce na Primavera, antes do aparecimento das folhas. Os frutos, drupas, são as nozes de todos conhecidas. É uma espécie originária do sudeste europeu e da Ásia ocidental. É plantada nas', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Oenanthe Aquática', E'', '', E'OENANTHE AQUATICAANTI CONVULSIVANTE.CATARRO PULMONAR, TOSSE CRÔNICA, BRONQUITE FÉTIDA, BRONQUIOECTASIA,TUBERCULOSE PULMONAR.ASMA.Oenanthe aquática', '', E'Oenanthe aquatica Umbelliferae (Apiaceae) Sob ponto de vista antroposófico Esta planta da Europa e da Ásia ocidental cresce nas águas rasas, barrentas, quentes e pouco aeradas; como por exemplo lagoas, poças e várzeas de rios. Sua forma é muito sensível às ações da água e do ar; a folha e mesmo toda a planta sofrem uma enorme alteração da forma. Debaixo da água este vegetal vive por muito tempo e seu caule, que pode atingir até 8 m de comprimento, se torna tão espesso como um braço, é esponjoso,', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Onopordon', E'', '', E'ONOPORDON ACANTHIUMMOLÉSTIAS DO CORAÇÃOOnopordon', '', E'Onopordon acanthium Asteraceae (Compositae) Sob ponto de vista antroposófico Ele é o mais imponente, um verdadeiro "Eu dos cardos"! Provavelmente originário dos mesmos locais que os outros cardos já estudados, ele passou pela Inglaterra e Escócia para se difundir por toda Europa central, Rússia meridional, até a Ásia ocidental, se bem que no Oeste da Europa, ela só apareça raramente. As dunas arenosas ao bordo do mar, a planície húngara, a Ucrânia, todos os países com breves chuvas de primavera', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Orégano', E'', '', E'ORIGANUM SPP., OREGÃO, MANJERONA-BAIANA E MANJERONA-SELVAGEM.APERIENTE, EXPECTORANTE, DIURÉTICO, CARMINATIVO E TÔNICO.NINFOMANIA, MASTURBAÇÃO.ORÉGANO', '', E'Nome científico: Origanum spp. Família: Labiatae.  Origem: Europa, sul da ex-URSS, México e algumas regiões da América do Sul  Sinonímia: oregão, manjerona-baiana e manjerona-selvagem.  Descrição: planta perene, caule ereto e quadrangular;folhas ovais pontiagudas (verde-escuras ou acinzentadas); pêlos finos e curtos na face inferior; flores em grupos nas extremidades.  Constituintes químicos principais: taninos, timol, fenóis, origaneno e caneacol.  Indicações: aperiente, expectorante, diurético', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ortosifão', E'', '', E'ORTHOSIPHON STAMINEUSDIÁTESE DO ÁCIDO ÚRICO.CÁLCULOS BILIARES E RENAIS, AO REUMATISMO ARTICULAR.CALCIFICAÇÃO DAS ARTÉRIAS.DORES HEPATO-BILIARES;DORES DA BEXIGA E DO RIM,ALBUMINÚRIA.Ortosifão', '', E'Orthosiphon stamineus Labiatae (Lamiaceae) Sob ponto de vista antroposófico Esta planta, que fornece a "infusão nefrítica indiana", medra na Índia, no arquipélago Malásio e na Austrália. Os ramos foliares terminam em uma falsa espiga de flores. Tais flores são de tonalidade azul pálido e se prolongam em longos tubos horizontais e seus estames, ainda mais longos, vão na mesma direção. A infusão feita com esta planta contém óleos etéricos, taninos, um glicosídeo e uma grande quantidade de sais de', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Panacéia', E'', '', E'SOLANUM CERNUUM VELL., BRAÇO-DE-PREGUIÇA, BOLSA-DE-PASTOR, VELAME-DO-MATO E PANACÉA.HEMOSTÁTICA (RAIZ), DESOBSTRUENTE DO FÍGADO (FOLHAS E FLORES), SUDORÍFERA, DIURÉTICA E DEPURATIVA,. USADA PARA MOLÉSTIAS DE PELE E REUMÁTISMOS.PANACÉIA', '', E'Nome científico: solanum cernuum Vell. Família: solanaceae. Origem: América do Sul.  Sinonímia: braço-de-preguiça, bolsa-de-pastor, velame-do-mato e panacéa.  Descrição: arbusto grande, perene, ramos com pêlos pardacentos e compridos; folhas alternas, oblongas e coriáceas; fruto baga globosa e amarela.  Constituintes químicos principais: sem referências.  Indicações: hemostática (raiz), desobstruente do fígado (folhas e flores), sudorífera, diurética e depurativa,. Usada para moléstias de pele e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Papoula Mexicana', E'', '', E'ARGERNONE MEXICANA L.ASMA,TOSSE SECA,ANTIOFTÁLMICO,DOENÇAS CUTÂNEAS, FURÚNCULOS E ABSCESSOS.Papoula mexicana', '', E'Nome científico: Argernone mexicana L.  Herbácea anual, da família Papaveraceae, originária do México. Utilizada contra asma (infusão de folhas e hastes) e tosse. Neste caso, seu uso deve ser reservado para casos de tosse seca, causada por irritação da faringe, laringe e traquéia. O suco que a planta desprende, em maceração, é diurético e de ação positiva em várias afecções dos olhos (antioftálmico), assim como em doenças cutâneas, furúnculos e abscessos. Dada a toxicidade de todas as partes des', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Parietária', E'', '', E'PARIETARIA OFFICINALIS L.DIURÉTICA,NEFRITE E CÁLCULOS RENAIS.AFECÇÕES PULMONARES E QUEIMADURAS.FEBRÍFUGO E ANTI-SÉPTICO.Parietária', '', E'Nome científico: Parietaria officinalis L. Planta herbácea, perene, da família Urticaceae, originária da Europa. Toda a planta goza de propriedades diuréticas, decorrentes do sal de nitro que contém. Atua contra nefrite e cálculos renais. Usada também contra afecções pulmonares e queimaduras, além do efeito febrífugo e anti-séptico. Infusão das folhas é feita, utilizando-se 10 g da erva em 1 litro de água. Multiplica-se por sementes e estacas. C', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pata De Vaca', E'', '', E'BAUHINIA FORFICATA LINK, UNHA-DE-VACA, UNHA-DE-BOI, UNHA-DE-ANTA, MIRIRÁ E MORORÓ.HIPOGLICEMIANTE (ANTIDIABETICA), PURGATIVA E DIURÉTICA. PARA PROBLEMAS DO APARELHO URINÁRIO, MALES DOS RINS, DO ESTOMAGO, DEPURATIVAPATA DE VACA', '', E'Nome científico: Bauhinia forficata Link. Família: Leguminosas. Origem: Ásia. Sinonímia: unha-de-vaca, unha-de-boi, unha-de-anta, mirirá e mororó.  Descrição: planta arbórea com porte médio, pode atingir de 5 a 9 m de altura; folha composta por 2 folíolos unidos pela base (com formato de pata de vaca), apresenta 2 espinhos na base; flores brancas a vermelhas; fruto do tipo vagem, de coloração pardo-escura.  Constituintes químicos principais: flavonóides (campferol, rutina e quercitina), ácidos o', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pau D''Alho', E'', '', E'GALLESIA INTEGRIFOFA (SPRENG.) HARMS.VERMÍFUGA, ANTI-HERNORROIDAL,ABSCESSOS E ALIVIAR DORES REUMÁTICAS.HIPOTENSORES E DIMINUIDORES DA TAXA DE COLESTEROL.Pau d''alho', '', E'Nome científico: Gallesia integrifofa (Spreng.) Harms. Espécie arbórea de grande porte, da família Phytolaccaceae. É encontrada na floresta tropical atlântica. A planta toda desprende odor característico de alho. As folhas em decocção (2o g em 1 litro d''água) ou cataplasmas têm ação vermífuga, anti-hernorroidal, sendo ainda empregada para resolver abscessos e aliviar dores reumáticas. Folhas e caule são também indicados corno hipotensores e diminuidores da taxa de colesterol. Multíplica-se por s', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pau Santo', E'', '', E'GUAIACUM OFFICINALEDORES ARTICULARES COM RIGIDEZ,DEFORMAÇÕES E RETRAÇÕES DOS TENDÕES.DIARRÉIAS COM CÓLICAS.PLEURITE PRODUZIDA PELO FRIO ÚMIDO COM TOSSE E DORES.DEFORMAÇÕES,ARTROSES, REUMATISMOS E TENDINITES,VERMELHIDÄO DAS AMÍDALASPau santo', '', E'Guaiacum officinale Zygophyllaceae Sob ponto de vista antroposófico As plantas da família Zygophyllaceae crescem nos terrenos secos e salgados das regiões subdesérticas. São plantas amargas, ricas em resinas. Essa família se relaciona com o calor externo, crescendo em ambiente semi-desértico e com o calor interno produzindo resinas. O Guaiacum officinale L. habita a América equatorial, principalmento nas ilhas da América Central como Cuba e São Domingos. Apresenta um porte arbóreo chegando a med', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Peônia', E'', '', E'PAEONIA OFFICINALISEPILEPSIA,EDEMA E ASCITE.Peônia', '', E'Paeonia officinalis Ranunculaceae Sob ponto de vista antroposófico Nesta planta, as forças terrestres dominam de maneira muito mais intensa. A flor se torna vermelha e surgem perfumes nas espécies asiáticas de folhas delgadas. Tais flores lembram os odores da Convallaria e os da Rosa, mas são mais aéreos. O início do verão se manifesta na família das Ranunculáceas sob a forma de "Peônia". Esta planta tem como habitat o Sul dos Alpes; ela habita os declives claros e os pequenos bosques. Não se po', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Perpétua', E'', '', E'GOMPHRENA GLOBOSA L.EXPECTORANTE E EM AFECÇÕES DO APARELHO RESPIRATÓRIO.Perpétua', '', E'Nome científico: Gomphrena globosa L. Herbácea anual, da família Amaranthaceae, originária da índia. Apresenta inflorescéncias globosa, pequenas, roxas ou creme. usam-se as flores em infusão (20 g em 1 litro d''água) como expectorante e em afecções do aparelho respiratório. Multiplica-se por sementes que são produzidas em grande quantidade e que podem ser semeadas em qualquer época do ano, principalmente no verão. É também considerada uma planta ornamental. V', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Petasites', E'', '', E'PETASITES OFFICINALISDORES DE GARGANTA E DE CABEÇA.BRONQUITES,DIAFORÉTICO.Petasites', '', E'Petasites officinalis Asteraceae (Compositae) Essa planta possui folhas gigantes; arredondadas, reniformes. Pertence ao domínio do elemento aquoso: bordos de riachos e ribeirões; ela recobre esses lugares, com seus galhos de tipo trepadeira, que crescem rente ao chão. No inverno, todas as partes aéreas desaparecem, mas em março, vemos sair da terra flores encorpadas, cor de carne, que se aprumam rapidamente, umas femininas e outras masculinas, logo elas se desagregam, enquanto que seus aquênios', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Picão', E'', '', E'BIDENS PILOSA L., ERVA-PICÃO, PIOLHO-DE-PADRE, PICÃO-DO-CAMPO, MACELA-DO-CAMPO, CARRAPICHO-PICÃO, PICÃO-PRETO, GUAMBU, CUAMBU, CARRAPICHO-DE-DUAS-PONTAS, COAMBI E CARRAPICHO-AGULHA, AMOR DE MULHERPROBLEMAS HEPÁTICOS (ICTERICIA E HEPATITE) E DAS VIÁS_URINÁRIÁS. TEM PROPRIEDADES DIURÉTICAS E DEPURATIVAS. USADA AINDA CONTRA DIABETES, DISENTERIA E, EXTERNAMENTE, CONTRA MICOSES, COMO VULNERÁRIO E ANT', '', E'A Nome científico: Bidens pilosa L. Família: Compositae. Origem: México, hoje em dia é considerada planta cosmopolita tropical.  Sinonímia: erva-picão, piolho-de-padre, picão-do-campo, macela-do-campo, carrapicho-picão, picão-preto, guambu, cuambu, carrapicho-de-duas-pontas, coambi e carrapicho-agulha.  Descrição: planta herbácea, anual, de ramos dicotômicos; folhas opostas; flores amareladas em capítulos terminais; fruto preto, cujo ápice é coroado por 2 a 4 saliências que dão capacidade de ade', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pimenta', E'', '', E'CAPSICUM ANNUUM L.DORES REUMATISMAIS,CIÁTICA,PLEURESIA.ESTIMULA O PERISTALTISMO GASTRINTESTINAL.FAVORECE A SECREÇÃO DOS SUCOS GÁSTRICOS.Pimenta', '', E'Capsicum annuum L. Solanaceae Planta anual com caule ereto e ramificado, folhas ovais e brilhantes, em cujas axilas nascem flores brancas suportadas por um pedúnculo curto. Imediatamente após a floração, aparece, conforme a espécie, uma baga encarnada, amarela ou verde. A pimenta é originária das regiões tropicais e subtropicais da América, tendo sido introduzida na Europa pelos Espanhóis no século XV. São as variedades com compridas bagas vermelhas, de gosto fortemente picante, que apresentam i', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pimpinela Escarlate', E'', '', E'ANAGALLIS ARVENSIS L.,ANAGALLIS PHOENICEABAIXA A FEBRE E TEM EFEITOS DIURÉTICO E EXPECTORANTE.Pimpinela escarlate', '', E'Anagallis arvensis L. Syn: Anagallis phoenicea Scop. Primulaceae Umi gênero de 20 espécies anuais, bienais e perenes, encontrado no mundo inteiro; Anagallis arvensis é nativa na Europa é uma erva daninha comum no solo cultivado. Originária da Europa, especialmente da área do Mediterrâneo, acompanhou os colonizadores europeus, provavelmente na forma de sementes misturadas com as de culturas, para muitas regiões, sendo hoje encontrada na maioria das regiões subtropicais e temperadas do mundo. No B', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pimpinela Oficinal', E'', '', E'SANGUISORBA OFFICINALIS L.HEMOSTÁTICA.SANGRAMENTO DO ESTÔMAGO, DO INTESTINO, DO PULMÃO,MENORRAGIA, OS SANGRAMENTOS DOS MIOMAS, AS VARIZES,HEMORRÓIDAS.DIARRÉIA.Pimpinela oficinal', '', E'Sanguisorba officinalis L. Rosasceae Sob ponto de vista antroposófico Esta bela planta dos prados se encontra nos pastos úmidos ou moderadamente secos desde os Alpes até a Noruega. Esta planta, apesar de ser uma rosácea, desempenha o papel de uma gramínea. A partir de uma vigorosa raiz marrom nasce um breve rizoma que emite uma roseta de folhas longamente pecioladas e penadas, com uma bela forma rítmica. A inflorescência ascende, com uma haste nua e rígida, portadora apenas de algumas folhas red', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pinhão Do Paraguai', E'', '', E'THEVETIA PERUVIANA (PERS.) K. SCHUM.,PINHÃO-DE-PURGA E FIGO-DO-INFERNO.HEMOSTÁTICO.PURGATIVA.HIDROPSIA.Pinhão do Paraguai', '', E'Nome científico: Thevetia peruviana (Pers.) K. Schum. Espécie nativa do Brasil, perene, da família Apocynaceae, que apresenta, ainda, os seguintes nomes: pinhão-de-purga e figo-do-inferno. É um arbusto de 2 a 3 m de altura, plantado junto às cercas das moradias rurais. O látex incolor é recomendado como hemostático. A amêndoa (1 a 3), levemente torrada e moída, tomada com água, é fortemente purgativa. Já o óleo extraído da amêndoa tem efeito drástico e é empregado contra a hidropsia. Usar sob or', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pinhão Roxo', E'', '', E'JATROPHA GOSSYPIIFOLIA L.,BATATA-DE-TEÚ,JALAPAO.HIDROPISIA E ICTERÍCIA.PURGATIVAS E RESOLUTIVAS.REUMATISMO,CONTUSÕES.ANTIHIPERTENSIVA.Pinhão roxo', '', E'Nome científico: Jatropha gossypiifolia L. É um arbusto da família Euphorbiaceae, originária do Brasil, também conhecida como batata-de-teú e jalapao. Tem suas raízes utilizadas contra hidropisia e icterícia; as sementes são purgativas e resolutivas; as folhas tém sido empregadas em banhos no combate ao reumatismo, em casos de contusões e como antihipertensiva. Esta planta é altamente tóxica. Diz-se que um pedaço de folha é o suficiente para matar uma criança. Multíplice-se por sementes. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Podagraria', E'', '', E'AEGOPODIUM PODAGRARIA L.ANTIESPASMÓDICAS, ANALGÉSICAS E GLANDULARESPodagraria', '', E'Aegopodium podagraria L. Umbelliferae (Apiaceae) Sob ponto de vista antroposófico O gênero Aegopodium é constituído por sete espécies de pequenas plantas perenes. A origem do nome vem do grego "Aigos", gota, e "podos", pé. "Podagraria" deriva do termo latino "podagra", gota, e refere-se ao uso medicinal da planta. Aegopodium podagraria é uma planta da sombra úmida e dos solos fofos. Ela cresce sob as árvores dos bosques e, a partir dai, se espalha pelas margens dos bosques, pelas clareiras, pela', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Poejo', E'', '', E'MENTHA PULEGIUM L., ERVA- DE-SÃO-LOURENÇO,POEJO-DAS-HORTAS E POEJO-REALCARMINATIVO, DIGESTIVO, VERMÍFUGO, EXPECTORANTE, ANTI-SÉPTICO, ANTIESPASMÓDICO, EMENAGOGO E PARA HIDROPISIA.POEJO', '', E'Nome científico: Mentha pulegium L. Família: Labiatae. Origem: sem referências. Sinonímia: erva- de-são-lourenço,poejo-das-hortas e poejo-real.  Descrição: planta herbácea e vivaz; caule estolonífero; folhas opostas, lanceoladas e denteadas; flores pequenas, brancolilases, em inflorescências axilares. Exala odor característico.  Constituintes químicos principais: pulegona, mentona, piperitona, borneol, carvona e acetato de mentila.  Indicações: carminativo, digestivo, vermífugo, expectorante, an', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Potentilla Erecta', E'', '', E'POTENTILLA TORMENTILLA L.SANGRAMENTOS INTERNOS,DIARRÉIAS PERSEVERANTES, INFLAMAÇÕES E CATARROS DO TRATO DIGESTIVOPotentilla erecta', '', E'Sin. Potentilla tormentilla L. Rosaceae Sob ponto de vista antroposófico Esta pequena planta rizomática está ainda mais concentrada sobre ela própria e, de uma maneira intensa, enterrada no solo. Sobre os prados úmidos, às vezes pantanosos, onde ela gosta muito de crescer, percebemos apenas suas pequenas flores graciosas de um amarelo solar, composta de quatro pétalas. Este vegetal, com suas forças luminosas e formativas, parece enviar um impulso terapêutico aos prados molhados e ácidos, tão com', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Primavera', E'', '', E'PRIMULA VERIS L.SEDATIVO E CALMANTE.RUGAS DA PELE, SARDAS E MANCHAS.Primavera, Prímula', '', E'Primula veris L. Syn.: Primula officinalis (L.) HILL. Primulaceae O gênero Primula inclui aproximadamente 400 espécies de plantas perenes que ocorrem principalmente em áreas temperadas e montanhosas do hemisfério do norte. Primula veris é encontrada na Europa e Ásia ocidental e Primula vulgaris na Europa, Ásia do norte e no Cáucaso. Elas medram nas margens dos caminhos e também se adaptam bem em gramados. Devem ser cultivadas separadamente para evitar hibridação. Muitas prímulas são cultivadas c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Proeza Japonesa', E'', '', E'CISSUS SICYOIDES L.,CIPÓ-DA-CHINA,UVA-DO-MATO, INSULINA-VEGETAL.DIABETE,REUMATISMO,ABSCESSOS.Proeza japonesa', '', E'Nome científico: Cissus sicyoides L. Planta trepadeira, perene, da família Vitaceae que apresenta gavinhas, originária do Brasil. Também conhecida corno cipó-da-china,uva-do-mato, insulina-vegetal. As folhas são usadas em casos de diabete, na forma de infusao. Externamente, são empregadas contra reumatismo e na cura de abscessos. É também utilizada na ornarnentaçao de paredes. Multiplica-se por estacas e sementes. ', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pruneira', E'', '', E'PRUNUS SPINOSA L.FORTIFICANTE NA FADIGA.Pruneira', '', E'Prunus spinosa L. Rosaceae Sob ponto de vista antroposófico A pruneira medra na beira dos bosques rochosos, beirando os caminhos situados em regiões secas, sobretudo em montanhas calcárias. Esta planta passou todo o inverno tão seca quanto um esqueleleto e, tão logo tenha terminado esta estação do ano, ela começa a brilhar por cima dos seus espinhos, brilho esse devido às suas inúmeras florzinbas brancas que nos revelam que a época da ressurreição, da Páscoa não está longe (na Europa, o inverno', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pulmonária Oficinal', E'', '', E'PULMONARIA OFFICINALIS L.SUDORÍFICA, ANTI-INFLAMATÓRIA E DIURÉTICA.BRONQUITES, TOSSE, TOSSE CONVULSIVA ,EXPECTORANTE.Pulmonária oficinal', '', E'Pulmonaria officinalis L. Boraginaceae O gênero Pulmonaria consta de 14 espécies de plantas perenes robustas, rizomatosas, de lento crescimento, nativas em bosques da Europa, Ásia e oeste da América do Norte. A origem do nome vem do latim "pulmo", pulmão, devido ao uso que se faz das plantas de várias espécies. Pulmonaria officinalis é uma planta herbácea perene com rizoma subterrâneo e um tufo de caules angulosos, apresentando folhas alternas e rugosas ao tato. Na extremidade de cada caule form', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Pulsatila', E'', '', E'ANEMONE PULSATILLAMELANCÓLICA, GERALMENTE FEMININAS, COM FORTE TENDÊNCIA A CHORARPulsatila', '', E'Pulsatilla vulgaris, Pulsatilla vernalis, Pulsatilla pratensis (Anemone pulsatilla), Ranunculaceae (Sob ponto de vista antroposófico) Já foi mencionado que a Pulsatilla está um pouco alterada em relação ao tipo geral das Anêmonas, no que se refere às suas folhas tão divididas a ponto de se tornarem filiformes, deixando notar que o elemento aéreo penetra bastante na planta. Em conseqüência disso, os locais de predileção desta planta primaveril são os prados secos, encostas pedregosas, desde que n', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Quebra Pedra', E'', '', E'PHYLLANTHUS NIRURI L., ARREBENTA-PEDRA, ERVA-POMBINHA, SAÚDE-DA-MULHER, FURA-PAREDE, SAUDADE-DA-MULHER E SAXÍFRAGA.DIURÉTICA, FORTIFICANTE DO ESTÔMAGO, APERIENTE, PARA CISTITE. ANTIINFECCIOSA DAS VIAS URINÁRIAS, PARA HIPERTENSÃO ARTERIAL (DIURÉTICO). A AÇÃO ANALGÉSICA E RELAXANTE MUSCULAR DE SEUS ALCALÓIDES AJUDA NA EXPULSÃO DOS CÁLCULOS RENAIS, POR ATUAR NO RELAXAMENQuebra-pedra', '', E'Nome científico: Phyllanthus niruri L. Família: Euphorbiaceae. Origem: Europa.  Sinonímia: arrebenta-pedra, erva-pombinha, saúde-da-mulher, fura-parede, saudade-da-mulher e saxífraga.  Descrição: erva anual de pequeno porte; ramos alternos; falhas ovais, alternas, pequenas, simulando os folíolos de uma folha imparipenada, com pequena assimetria ria base; flores amareloesverdeadas, Monóicas; fruto seco, esquizocarpo, trilocular, com duas sementes em cada lúculo.  Constituintes químicos principais', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Quiabo', E'', '', E'HIBISCUS ESCULENTUS L.ÚLCERAS E PICADAS DE ESCORPIÃO.TOSSE.Quiabo', '', E'Nome científico: Hibiscus esculentus L. Espécie anual, da família Malvaceae, originária da Etiópia (África). As sementes são utilizadas contra úlceras e picadas de escorpião. As folhas e os frutos são ricos em mucilagens. Os frutos devem ser colhidos tenros. Xarope para tosse: colocar 1 fruto fatiado, 1 folha de guaco fatiada em 1 xícara (chá) de água fervente, abafar por 15 minutos, coar e adicionar 2 colheres (sopa) de açúcar cristal e levar ao fogo para dissolver (bastam 3 minutos). Tomar 3 a', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Quinino', E'', '', E'CINCHONA PUBESCENSMALÁRIA,ESGOTAMENTO NERVOSO, ANEMIA E CONVALESCENÇA.REDUZ O BATIMENTO CARDÍACO .NEURALGIA, ESPASMOS MUSCULARES, FIBRILAÇÃO CARDÍACA;Quinino', '', E'Cinchona pubescens Rubiaceae Este gênero consta de cerca de 40 espécies de árvores e arbustos perenes, encontrados em escarpas mornas e úmidas dos Andes, principalmente nas altitudes entre 1.500 e 2.500 m. Cinchona pubescens é nativa no Equador. É difícil isolar e distinguir entre as várias espécies. As autoridades consideram que pode haver apenas pouco mais de 20 espécies realmente diferentes. O cultivo de Cinchona foi de importância capital desde o 17º século. Agora cultivada em muitas regiões', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Quitoco', E'', '', E'PLUCHEA QUITOC D.C.DIGESTIVAS E ESTIMULANTES,CARMINATIVAS, RESOLUTIVAS E DIGESTIVAS.BRONQUITE E TOSSE.ANTI-REUMÁTICO.Quitoco', '', E'Nome científico: Pluchea quitoc D.C. Espécie semi-perene, da família compositae, de porte arbustivo, muito aromático. Originária da América do Sul. As folhas e caule tem propriedades digestivas e estimulantes, sendo utilizadas na forma de infusão (20 g ern 1 litro d''água, tomar 4 a 5 xícaras (chá) ao dia). As raízes são carminativas, resolutivas e digestivas e também indicadas contra bronquite e tosse. Em banhos, age como anti-reumático (aliviar a dor) e estimulante. Multiplica-se por sementes.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Rábano', E'', '', E'RAPHANUS SATIVUS L.COLAGOGO E ADJUVANTE DO TRATAMENTO DA ICTERICIA E DAS DOENÇAS DA VESÍCULA.INFLAMAÇÕES E CÁLCULOS BILIARES.Rábano', '', E'Raphanus sativus L. Cruciferae (Brassicaceae) Planta herbácea anual ou bienal com raiz em forma de bulbo esférico a fuselado e um caule ramificado, apresentando folhas liriformes. As flores brancas ou rosadas estão agrupadas em inflorescências alongadas na extremidade dos caules. O fruto é uma silíqua contendo sementes castanhas. O rábano é uma antiga planta cultivada, já conhecida dos Egípcios. Era também cultivada outrora no Japão e na China; através da Grécia e de Roma, difundiu-se no resto d', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ranunculáceas', E'', '', E'RANUNCULÁCEASDEPENDE DA ESPÉCIERanunculáceas - Ranunculaceae', '', E'O tipo Ranunculácea (Sob ponto de vista antroposófico) As Ranunculáceas, com aproximadamente 1.200 espécies, apresentam grande plasticidade de formas e ricas possibilidades de metamorfose. Através delas, podemos estudar com muita facilidade as leis fundamentais da metamorfose das plantas. As Rununculáceas possuem algo de fluido e são pouco domésticas em relação às suas leis numéricas. A rigidez pedante lhes é totalmente estranha. A dinâmica do tipo é aquela do encontro interno entre o aquoso e o', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Rícino', E'', '', E'RICINUS COMMUNIS L.TRATAMENTO DA PELE, DAS FERIDAS,CABELO,LAXANTE.Rícino, Mamona', '', E'Ricinus communis L. Syn.: Ricinus hibridus Bess. Syn.: Ricinus leucocarpus Bert. Euphorbiaceae O rícino, provavelmente originário da África, sendo já conhecida pelos antigos egípcios e também conhecida desde a mais remota antiguidade na Índia e por isto alguns autores consideram-na de origem asiática, é uma planta herbácea anual no centro da Europa, um arbusto plurianual na Europa meridional e uma árvore perene nas regiões tropicais. No Brasil ocorre em todas as regiões habitadas, sendo mais fre', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Romã', E'', '', E'PUNICA GRANATUM L.,ROMÃZEIRA, ROMEIRA-DE-GRANADA, MILGRADA, MILGREIRA, MILIGRÃ, MILIGRANA, GRANADA E ROMEIRA.VERMÍFUGA (TÊNIA.) E ANTIBACTERIANA, ÚTIL NAS ESTOMATITES, AMIGDALITES, GENGIVITES FARINGITES E LARINGITES (INFLAMAÇÕES DA BOCA E GARGANTA).ROMÃ', '', E'Nome científico: Punica granatum L. Família: Punicaceae. Origem: Ásia Ociental. Sinonímia: romãzeira, romeira-de-granada, milgrada, milgreira, miligrã, miligrana, granada e romeira.  Descrição: arbusto de pequeno porte, perene, ereto, com altura entre 2 e 5 metros, muito ramificado; tronco com casca cinzenta e ramos opostos; folhas de forma elíptica, brilhantes e alternadas, opostas, caducas e glabras; flores solitárias e terminais, sésseis, de cor vermelho-alaranjada; fruto arredondado com casc', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Rorela', E'', '', E'DROSERA ROTUNDIFOLIA L.CALMANTE,DIURÉTICOS E EXPECTORANTES,RELAXA ESPASMOS,CONTROLA A TOSSE.ASMA,TOSSE AGUDA, BRONQUITE, GRIPE, GASTRITE E ÚLCERA GÁSTRICA.Rorela', '', E'Drosera rotundifolia L. Droseraceae Aproximadamente 100 espécies carnívoras perenes pertencem a este gênero diversificado que ocorre mundialmente; Drosera rotundifolia medra em campos úmidos ao longo da Eurasia temperada e América do Norte. Muitas rorelas são cultivadas por colecionadores de plantas carnívoras e a espécie mais comum é vendida como plantas alimentícia. O nome vem do grego drosos, "orvalho", e refere-se às gotas pegajosas de enzimas digestivas no pelos das folhas usadas para apanh', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Rosa Selvagem', E'', '', E'ROSA CANINA L.ACALMAR AS DIARRÉIAS E OS SANGRAMENTOS INTERNOS;Rosa selvagem', '', E'Rosa canina L. Rosaceae Sob ponto de vista antroposófico A roseira selvagem é uma das plantas que aparecem em grande freqüência nos países europeus. Na orla de um bosque, a roseira selvagem parece anunciar os segredos de tal bosque; crescendo junto às sebes, ela forma cercas vivas muito graciosas; ela oculta os montes de pedras e os amontoados de entulho, ela acompanha o alpinista que escala as pastagens magras das altas montanhas, e sempre está prestes a oferecer ao alpinista uma pequena rosa.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Rosáseas', E'', '', E'ROSÁCEASDEPENDE DA ESPÉCIERosáseas - Rosaceae', '', E'Os Processos do Açúcar, do Tanino e do Cianeto (Sob ponto de vista antroposófico) A intervenção intensa da esfera astral no domínio das flores estimula o organismo líquido a secretar abundantemente o néctar. As Rosáceas se fazem notar, de todas as maneiras, por um processo açúcar hipertrofiado que as torna capazes de formar abundantes sucos açucarados. Tal processo açúcar hipertrofiado produz a dilatação de suas bagas e frutos. Devido a isso, elas representam a maior família de árvores e arbusto', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Ruibarbo Palmado', E'', '', E'RHEUM PALMATUM L.ADSTRINGENTE,LAXANTERuibarbo palmado', '', E'Rheum palmatum L. var. tanguticum Maxim. Polygonaceae Planta herbácea perene, dotada de uma roseta basilar de folhas palmadas e de um caule bem desenvolvido, atingindo até 2m de altura. Este caule oco apresenta algumas folhas caulinares e uma panícula de flores terminal. Toda a planta tem cor avermelhada e gosto acidulado. O fruto é um aquênio tríquetro. O ruibarbopalmado vem da China e do Tibete. As espécies cultivadas na Europa, pelos seus pecíolos comestíveis, não são de conveniente utilizaçã', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sabina', E'', '', E'JUNIPERUS SABINAATUA NA ORGANIZAÇÃO METABÓLICO-REPRODUTORA.Sabina', '', E'Juniperus sabina Cupressaceae Sob ponto de vista antroposófico Ao observarmos a Sabina dentro do quadro Geral do grupo dos Ciprestes, iremos notar que essa planta não ocupa uma posição fixa pois apresenta formas de folhas, vários portes vegetativos indo desde o porte de pinheiro até o de uma planta que cresce rente ao chão. Os frutos, tão bem elaborados pelos Juníperos, são, nesse caso, muito pequenos e não são utilizados na terapia ou culinária, tal como no caso do Zimbro. Na Sabina podemos obs', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sabugueiro', E'', '', E'SAMBUCUS AUSTRALIS CHACO. E SCHLT., ACAPORA, SABUGO-NEGRO, SABUGUEIRINHO E SABUGUEIRO-DO-RIO-GRANDEPLANTA SUDORÍFERA, CICATRIZANTE, EMOLIENTE, DIURÉTICA, BÉQUICA, ANTIESPASMÓDICÁ. USADA CONTRA O SARAMPO (FLORES) E RESFRIADOS (CASCAS E FOLHAS), ANTITÉRMICA NATURAL. AS CASCAS PODEM SER PURGATIVAS.LAXANTES.SABUGUEIRO', '', E'Nome científico: Sambucus australis Chaco. e Schlt.  Família: Caprifoliaceae. Origem: Sul do Brasil. Sinonímia: acapora, sabugo-negro, sabugueirinho e sabugueiro-do-rio-grande.  Descrição: arbustos ramificados (2 a 4 m de altura), perenes, verrucosos, pardacentos, dotados de medula branca; folhas compostas, de 5 a 7 folíolos ovadoacuminados e denteados; flores brancas, um pouco amarelas na dessecação; fruto baga, de cor roxa, quando maduro.  Constituintes químicos principais: colina, rutina, que', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Salgueiro Branco', E'', '', E'SALIX ALBA L.ANTIPIRÉTICO, ANTINEVRÁLGICO, ANTIREUMATISMAL.DIAFORÉTICO.BANHOS, UNGUENTOS E CATAPLASMAS.Salgueiro branco', '', E'Salix alba L. Salicaceae Árvore ou arbusto com tronco castanhoesverdeado e ramos flexíveis verdeamarelados. As folhas são lanceoladas, alternas, cinzentas e tomentosas na página inferior. O desenho mostra a diferença entre as folhas de S. alba, S. fragilis, S. cinerea e S. triandra (da esquerda para a direita). É uma espécie com flores dióicas; as flores masculinas e femininas estão agrupadas em amentos. Os frutos são cápsulas. O salgueirobranco é uma planta vulgar nas associações de planícies ú', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Salsa', E'', '', E'PETROSELINUM SATIVUM HOFFM.PEITORAL,DORES DE OUVIDO.ESTIMULANTE DO APETITE.DIURÉTICO.CARMINATIVAS E REGULAM A MENSTRUAÇÃO.EMENAGOGO.Salsa', '', E'Nome científico: Petroselinum sativum Hoffm. Espécie herbácea, bianual, da família Urnbelliferae. O suco das folhas é peitoral e alivia dores de ouvido. A folha é um estimulante do apetite. A raiz e um diurético que ajuda a eliminar a uréia. As sementes são carminativas e regulam a menstruação (em casos de supressão da menstruação). As folhas e raízes devem ser secas e guardadas. Infusão da raiz: 1 raiz lavada e fatiada, seca ao sol, faz-se o pó, colocar 1 colher (chá) do pó em 1 xícara (chá) de', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Salsaparrilha', E'', '', E'HERRERIA SALSAPARILHA MART.,JAPECANGA, SALSA-CERCA-ONÇA E SALSA-JAPECANGA.DOENÇAS DE PELE, REUMATISMO, ANÚRIA, FEBRE E ENFERMIDADES VENÉREAS.Salsaparrilha', '', E'Nome científico: Herreria salsaparilha Mart. Espécie herbácea, perene, da família Liliaceae. Originária da América Tropical. Também conhecida como japecanga, salsa-cerca-onça e salsa-japecanga. É uma trepadeira com espinhos, raizes em tubérculos, que cresce perto de rios, em lugares úmidos e sombreados. No Brasil, há muitas espécies de Smilax, todas têm quase as mesmas aplicações na medicina popular. As raízes são indicadas para doenças de pele, reumatismo, anúria, febre e enfermidades venéreas.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sálvia', E'', '', E'SALVIA OFFICINALIS L., SALVA-DAS-BOTICAS, SALVA-DOS-JARDINS, SALVA E SÁBIA.CICATRIZENTE (FOLHAS E FLORES), ANTIESPASMÓDIEA, ANTISSÉPTICA, EMENAGOGA, HIPOGLICEMIANTE, DIGESTIVA, DIURÉTICA, ANTI-REUMÁTICA, CARDIOTÔNICA, CONTRA INFLAMAÇÕES DA GARGANTA, BACTERIOSTÁTICA E ADSTRINGENTE. USADA TAMBÉM PARA GENGIVITES, ALÉM DE PROPORCIONSÁLVIA', '', E'Nome científico: Salvia officinalis L. Família: Labiatae. Origem: Sul da Europa. Sinonímia: salva-das-boticas, salva-dos-jardins, salva e sábia.  Descrição: planta herbácea de 0,30 a 0,50 m de altura, aromática; folhas alongadas e arredondadas nos caules, que são recobertos por pêlos finos e macios; flores azul-violáceas, formando cachos. Sabor amargo e odor forte.  Constituintes químicos principais: óleo essencial com cineol, cânfora, borneol, tuiona e outros terpenos. Contém ainda ácido ursóli', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sanícula', E'', '', E'SANICULA EUROPAEACONTUSÕES,FERIMENTOS.ESTANCANDO AS HEMORRAGIAS.HEMORRAGIAS INTERNAS.Sanícula', '', E'Sanicula europaea Umbelliferae (Apiaceae) Sob ponto de vista antroposófico Esta planta é uma Umbelífera da floresta que medra nos solos úmidos e sombreados dos bosques da Europa, Ásia e norte da África. É uma planta perene que configura um rizoma quase horizontal, com espessas raízes filiformes que se ramificam com a idade. A partir deste rizoma nascem folhas longamente pecioladas, verde douradas, com forma de mãos. A cada ano elevase a partir do rizoma, uma haste floral e nela podese encontrar', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Saponária', E'', '', E'SAPONARIA OFFICINALIS L.EXPECTORANTE.DIURÉTICA.DIAFORÉTICA.Saponária', '', E'Saponaria officinalis L. Caryophyllaceae Planta herbácea perene com rizoma de cor alaranjada e um tufo de caules eretos, apresentando folhas opostas, sésseis, de forma lanceolada. Os caules têm uma panícula terminal de flores rosadas. O fruto é uma cápsula oval que contém sementes muito pequenas (em baixo à direita). Espontânea na Europa central e meridional, é uma espécie de lugares úmidos. Era frequentemente plantada, pois substituía, esmagada, o sabão para as lavagens. Para fins medicinais, c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Saturéia', E'', '', E'SATUREJA HORTENSISAPERITIVA, ANTIESPASMÓDICA,SUDORÍFICA E AÇÃO AQUECEDORA PARA O ÓRGÃO DIGESTIVO.EMENAGOGA E AFRODISÍACA.Saturéia', '', E'Satureja hortensis Labiatae (Lamiaceae) Sob ponto de vista antroposófico No estado selvagem, é uma planta da região mediterrânea oriental e das costas do mar Negro; ela é algo intermediário ente o Alecrim e a Sálvia, crescendo em declives rochosos e montanhas de areia; é uma planta lenhosa que tem necessidade de muito calor e suas folhas são reduzidas quase que ao estado de agulhas. Dado seu aroma rústico, algo similar a uma variação entre o tomilho e mangericão, nós não iremos nos admirar ao en', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Scila', E'', '', E'SCILLA MARITIMA,DRIMIA MARÍTIMA, URGINEA MARÍTIMA, CEBOLA, CEBOLA DO MARDIURÉTICOS, EXPECTORANTES E ESTIMULANTES DO CORAÇÃO,TÔNICO CAPILAR.BRONQUITE, BRONQUITE ASMÁTICA, TOSSE SECA, E EDEMA.EMÉTICO.CASPA E SEBORRÉIA.SCILA', '', E'Scilla maritima (Liliaceae/Hyacinthaceae) Sinonímia: Drimia marítima, urginea marítima, cebola, cebola do mar Este gênero consiste de cerca de 100 espécies de bulbosas perenes, encontradas ao longo da região medderrãnea e Portugal; Scilia maritima é nativa nas areias litorâneas e secas e no solo rochoso. Scilas são amplamente cultivadas para uso comercial, mas elas também são cultivadas corno plantas ornamentais de jardins, pela sua impressionante espiga floral em relação aquelas dos lírios "rab', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sénecio', E'', '', E'SENECIO VULGARIS L.FAVORECE A MENSTRUAÇÃO.DIMINUI OS SANGRAMENTOS DO NARIZ E HEMORRAGIAS PULMONARES.AGE NO SEXUAL.Sénecio', '', E'Senecio vulgaris L. Asteraceae (Compositae) Os Senecionídeos, que são um dos doze grupos das compostas tubulifloras, se dividem, em 40 gêneros cujo mais rico, é o dos Senecios (1300 espécies). Encontramos plantas herbáceas, pequenos arbustos, plantas trepadeiras e algumas pequenas árvores. Eles povoam os montes e as estepes, sobretudo na África. Entre eles, o Senecio vulgaris da Europa é uma erva daninha na agricultura. Esta planta não é bonita, mas é dotada de uma incrível vitalidade e de um po', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Serralha', E'', '', E'SONCHUS OLERACEUS L., SERRALHA-LISA, SERRALHA-BRAVA E CHICÓRIA-BRAVA.ESTIMULANTE DAS FUNÇÕES HEPÁTICAS, LAXANTE, DIURÉTICO, DGPURETIVO, DIGESTIVO, CICATRIZANTE E CONTRA O TERÇOL.SERRALHA', '', E'Nome científico: Sonchus oleraceus L. Família: Compositae. Origem: Europa. Sinonímia: serralha-lisa, serralha-brava e chicória-brava.  Descrição: planta herbácea lactescente, com até 1 m de altura; folhas oblongas, sésseis, azuladas na face superior, flores amarelas e brilhantes.  Constituintes químicos principais: esteróis, resinas, óleo essencial, taninos, sais minerais e açúcares.  Indicações: estimulante das funções hepáticas, laxante, diurético, dgpuretivo, digestivo, cicatrizante e contra', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sete Sangrias', E'', '', E'CUPHEA CALOPHYLLACOMBATER A FEBRE, CÓLICAS.DISENTERIAS GRAVES.DIURÉTICO.Sete sangrias', '', E'Cuphea calophylla Cham. & Schlecht. Syn.:Cuphea plumbaginea Mart. Lythraceae O gênero Cuphea apresenta cerca de 250 espécies que em sua maioria vivem em lugares úmidos, é de origem centro e sul-americana, com bastante representatividade no Brasil. Muitas espécies ocorrem como infestantes, mas são raras as situações em que a intensidade das infestações é grande. Muitas plantas do gênero Cuphea são conhecidas vulgarmente como "sete-sangrias", numa alusão de que um tratamento com as plantas equival', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sófora Do Japão', E'', '', E'SOPHORA JAPONICA L.FAVORECE A PERMEABILIDADE CAPILAR.PERTURBAÇÕES CIRCULATÓRIAS, AS DOENÇAS NERVOSAS, AS  INFLAMAÇÕES.Sófora do japão', '', E'Sophora japonica L. Leguminosae (Fabaceae) Grande árvore com densa copa esférica, ramos inicialmente verdes, depois cinzentos, folhas imparipenatissectas verdes. As flores brancoamareladas estão agrupadas em panículas terminais sobre os ramos do ano. O fruto é uma vagem comprida que contém 3-4 sementes. É uma espécie originária da Ásia oriental. Suporta muito bem o clima europeu e é frequentemente plantada como planta ornamental nos parques e nas ruas. Existem formas do tipo do chorão e formas c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Sucupira', E'', '', E'BOWDICHIA SP.INFECÇÕES BUCAIS E AMIGDALITES.ADSTRINGENTES,DIARRÉIAS CRÔNICAS E COMO DEPURATIVA.Sucupira', '', E'Nome científico: Bowdichia sp.  Espécie arbórea, da família Leguminosas. Utilizam-se as sementes em decocção nas infecções bucais e amigdalites (garganta). Suas cascas amargas tem propriedades adstringentes, sendo empregadas juntamente com sua resina, nas diarréias crônicas e como depurativa. Não se deve fazer o uso prolongado da planta na forma de chá ou xarope. Multiplica-se por sementes. *', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Tanchagem', E'', '', E'PLANTAGO SPP., PLANTAGO MAIOR , PLANTAGO TORMENTOSA , CINCO NERVOS,TRANSAGEM , TRANSAGE, TANSAGEMEXPECTORANTE, ANTIDIARRÉICA (FOLHA), CICATRIZANTE, ADSTRINGENTE,EMOLIENTE, E DEPURATIVO. USADA NO TRATAMENTO DAS INFLAMAÇÕES BUCOFARINGEANAS, DÉRMICAS,GASTRINTESTINAIS E DAS VIAS URINÁRIAS. AS SEMENTES SÃO LAXATIVAS.Tanchagem', '', E'Plantago major - Tanchagem Nome científico: Plantago spp. Família: Plantaginaceae. Origem: Europa.  Sinonímia: tansagem, transagem e transage.  Descrição: planta vivaz, de pequeno porte; folhas dispostas em roseta; pecíolo longo e alado; flores pequenas em espiga.  Constituintes químicos principais: taninos, mucilagens, ácidos orgâicos, sais de potássio, vitamina C, flavonóides, iridóides e antraquinonas nas sementes.  Indicações: expectorante, antidiarréica (folha), cicatrizante, adstringente,e', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Teixo', E'', '', E'TAXUS BACCATA L.MORDEDURAS DE SERPENTE E A RAIVA,ESTIMULAR A ATIVIDADE CARDÍACA.AUMENTAR A TENSÃO E O PERISTALTISMO INTESTINAL.Teixo', '', E'Taxus baccata L. Taxaceae Árvore ou arbusto sempre-verde, com casca castanho-avermelhada, ramos densamente cobertos de agulhas verde-escuras. Estas persistem nos ramos de seis a oito anos. O teixo é uma espécie com flores dióicas; o pólen forma-se nos cones globulosos, as flores pistiladas aparecem isoladamente sobre ramos encurtados. A semente madura está envolvida por um arilo vermelho e carnudo. O teixo era antigamente vulgar na Europa, Ásia e África. Nos nossos dias, é uma espécie protegida', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Tomilho', E'', '', E'THYMUS VULGARIS L., TIMO.ENTIESPESMÓDICO, ANTISÉPTICO, ANTI-HELMÍNTICO E ANTITÉRMICO. PARA PROBLEMAS DO APARELHO DIGESTIVO, DE ÇOQUELUCHE E REUMATISMO.Tomilho', '', E'Nome científico: Thymus vulgaris L.  Família: Labiatae. Origem: Europa.  Sinonímia: timo.  Descrição: planta perene, com haste lenhosa na base e herbácea na ponta; ramos eretos, aveludados e de cor branca; folhas verde-acinzentadas e pontilhadas na face superior; flores róseas ou brancas.  Constituintes químicos principais: óleo essencial contendo timol, carvacrol, cimol, borneol, linalol, cimeno e pineno; contém ainda taninos.  Indicações: entiespesmódico, antiséptico, anti-helmíntico e antitér', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Tomilho Doce', E'', '', E'THYMUS SERPYLLUMBOA PARA AS FUNÇÕES SEXUAIS.TOSSE, COQUELUCHE,TONIFICA OS NERVOS E É ANTI-ESPASMÓDICO;CÃIMBRAS DO ESTÔMAGO, ASMA E EPILEPSIATomilho doce', '', E'Thymus serpyllum Labiatae (Lamiaceae) Sob ponto de vista antroposófico O tomilho "adocicado" medra nos prados secos mas úmidos principalmente nas montanhas, ascendendo até o limite das neves e é espontâneo tanto ao norte como ao sul dos Alpes. Seu perfume, ao se difundir no ar, confere um aroma típico aos campos alpinos. As abelhas encontram nesta planta, uma abundante dádiva em suas pequenas inflorescências rosadas, provenientes do aparelho foliar reduzido (pequenas folhas lineares ovais). O Th', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Trevo Branco', E'', '', E'TRIFOLIUM REPENS L.CATARROS GASTRINTESTINAIS E DIARRÉIAS FORTES.PERTURBAÇÕES DAS VIAS RESPIRATÓRIAS SUPERIORES.INFLAMAÇÕES GLANDULARES, AS DORES REUMÁTICAS.Trevo branco', '', E'Trifolium repens L. Leguminosae (Fabaceae) Planta herbácea perene com caule radicante, ascendente na parte superior. Este caule radicante dá origem a folhas trifolioladas, longamente pecioladas, apresentando uma mancha esbranquiçada na página superior. As flores brancas estão agrupadas em capítulos também longamente pedunculados. Após a floração, os capítulos murcham, inclinando-se para o solo. Os frutos são vagens com sementes ocres. É uma espécie vulgar nos prados, nas pastagens, à beira dos c', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Trigo Mourisco', E'', '', E'FAGOPYRUM TATARICUM (L.)INFLUENCIA A RESISTÊNCIA E A PERMEABILIDADE DOS CAPILARES SANGUÍNEOS.PERTURBAÇÕES CIRCULATÓRIAS.Trigo mourisco', '', E'Fagopyrum tataricum (L.) Gaertn. Polygonaceae Planta herbácea anual com caule ereto, verde, apresentando folhas alternas, sésseis, sagitadas. Na extremidade do caule, surgem flores esverdeadas em cachos provenientes da axila das folhas. Os frutos são aquênios tríquetros (pormenor em baixo). O trigo-mourisco e originário da Ásia central. Era já cultivado pelas populações nômades, em virtude do seu curto período vegetativo: apenas 90 dias. Dá sementes ricas em amido, utilizadas em farinha e sêmola', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Tuia', E'', '', E'THUJA OCCIDENTALISVERRUGAS E CRESCIMENTOS ESPONJOSOS.CATARROS GÊNITO-URINÁRIOS, CATARROS CRÔNICOS.OBESIDADE,Tuia', '', E'Thuja Occidentalis Cupressaceae Sob ponto de vista antroposófico A Thuja pertence ao grande grupo das Gymnospermas que compreende os Pinheiros, Cicas, Gingkos, Efedras e outras plantas muito antigas, cujas flores ainda não apresentam envoltórios. A Thuja é um pinheiro que faz parte do grupo dos ciprestes. O desenvolvimento da Thuja ocorre da seguinte maneira: depois de 4 a 5 semanas, as sementes dessa planta germinam produzindo um broto com duas pequenas folhas em forma de agulha. Durante essa f', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Tussilagem', E'', '', E'TUSSILAGO FARFARA L.ACALMAR A TOSSE E LIQUEFAZER O MUCO DOS BRÔNQUIOS.Tussilagem', '', E'Tussilago farfara L. Asteraceae (Compositae) Planta adventícia perene, com rizoma duradouro, subterrâneo, fortemente ramificado, que emite, no início da Primavera, um caule um pouco carnudo, coberto de escamas, com pequenas flores amarelas em formato de sol (capítulos). O Tussilago trouxe dentro de si durante todo o inverno esse impulso floral e se elevou, no começo da primavera, diretamente do domínio das raízes, na luz de março. Essas flores procuram o sol e fecham-se à noite e com tempo ruim.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Umbelíferas', E'', '', E'UMBELLIFERAEDEPENDE DA ESPÉCIEUmbelíferas - Umbelliferae (Apiaceae)', '', E'Plantas do elemento Ar (Sob ponto de vista antroposófico) A grande família das Umbelíferas, que engloba cerca de 2.600 espécies, representa um aspecto importante do reino vegetal. Esta família, que se desdobra em 2.600 variantes, tem algo de arcaico e primitivo. Nós inicialmente tentaremos mostrar ao leitor o "tipo" fundamental da família, para posteriormente descrevermos algumas das suas variações particulares. Achamos entre as Umbelíferas principalmente plantas herbáceas, raramente arbustos, j', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Urtiga', E'', '', E'URTICA DIOICA L.TRATAMENTO DAS VIAS URINÁRIAS, DO APARELHO RESPIRATÓRIO, DOS CATARROS GASTRINTESTINAIS,TRATAMENTO DA DIABETES.Urtiga', '', E'Urtica dioica L. Urticaceae Planta herbácea perene, possuindo um rizoma ramificado que dá origem a caules eretos, quadrangulares, com folhas ovaladas opostas duas a duas. Na axila das folhas da parte superior do caule, surgem inflorescências em panículas. Os frutos são aquênios. Toda a planta está coberta de tricomas urticantes (pêlos compostos) que se quebram, deixando o seu conteúdo nas feridas que provocam. Estes tricomas contêm uma substância protéica desconhecida, ácido fórmico, resina, ace', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Urtiga Branca', E'', '', E'LAMIUM ALBUMESCLEROSE DO ÚTERO, ATONIA DO ÚTERO, MENSTRUAÇÃO MUITO PRECOCE;UREMIA DOS HOMENS IDOSOS E INFLAMAÇÃO DAS VIAS URINÁRIAS.Urtiga branca', '', E'Lamium album Labiatae (Lamiaceae) Sob ponto de vista antroposófico Esta Labiata, espalhada principalmente nas regiões não muito quentes da Europa, freqüentemente considerada uma erva daninha, apresenta apenas vestígios da característica calórica típica das Labiatas. Podemos comparar esta planta com a urtiga, devido à sua exuberância na parte foliar e caulinar. No Lamium album, o impulso floral se une muito mais intimamente com o ritmo foliar dos nós, que se sobrepõem no caule; sua flor é branca', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Urtiga Vermelha', E'', '', E'URERA SP.,CANSANÇÃO.DIABETE E ANEMIA.DEPURATIVO, CONTRA AFECÇÕES DE PELE, GOTA E REUMATISMO.Urtiga vermelha', '', E'Nome científico: Urera sp. Espécie herbácea, perene, da família Urticaceae, originária do Brasil. Apresenta hastes vermelhas e folhas cobertas de pêlos urticantes (que irritam a pele). Recebe também o nome de cansanção. É recomendada como coadjuvante no tratamento de diabete e anemia. Usada, ainda, na forma de infusão, como depurativo, contra afecções de pele, gota e reumatismo. As folhas e sementes são comestíveis, as características urticantes desaparecem após o cozimento. Multiplica-se por se', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Urucum', E'', '', E'BIXA ORELLANADIMINUIÇÃO DE PRESSÃO ARTERIAL.LEVE RELAXAMENTO.REPELIR INSETOS.ADSTRINGENTE, PURGATIVA.Urucum', '', E'Bixa orellana Bixaceae Sob ponto de vista antroposófico Essa planta pertencia à família Flacourtiaceae, mas devido a alguns detalhes botânicos foi retirada dessa família, pertencendo atualmente à família Bixaceae, que possui um único gênero e uma única espécie que é a Bixa orellana, o Urucum. A família Flacourtiaceae é composta por muitas plantas de enorme valor terapêutico, como o Carpatoche brasiliensis conhecido com o nome de Sapucainha, cujo óleo das sementes possui um princípio ativo contra', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Urze', E'', '', E'CALLUNA VULGARIS L. HILLANTI-INFLAMATÓRIO NAS VIAS URINÁRIAS.DIURÉTICO,SEDATIVA.DOENÇAS DOS RINS.HIPERTROFIA DA PRÓSTATA.Urze', '', E'Calluna vulgaris L. Hill Ericaceae Arbusto rasteiro, sempre-verde, com ramos radicantes que suportam uma densa cobertura de folhas aciculadas. As diminutas flores cor-de-rosa estão agrupadas em ricas espigas terminais. O fruto é uma cápsula. A espécie é abundante na zona temperada, onde se encontra mesmo em latitudes muito setentrionais; dá-se bem nos solos ácidos, pobres, nos rochedos, areais, turfeiras, onde pode formar extensas coberturas. Colhe-se, para fins medicinais, a flor ou as cimeiras', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Uva Espim', E'', '', E'BERBERIS VULGARIS L.REMÉDIO PARA O FÍGADO.CONTROLAR DIARRÉIA TROPICAL.PERTURBAÇÕES RENAIS, CONTRA OS CÁLCULOS URINÁRIOS,CATÁRTICA, COLAGOGA E DIURÉTICAUva espim', '', E'Berberis vulgaris L. Berberidaceae Cerca de 450 espécies perenes e arbustos decíduos compõem o gênero Berberis, amplamente distribuído na Eurásia, Américas e África do norte. Muitas espécies são cultivadas por suas flores aromáticas, pelos frutos de cores brilhantes e pela agradável folhagem que, no caso das espécies decíduas, dá a bela coloração do outono. O habitat denso e espinhoso faz deles os melhores arbustos para cercas de restrição ou proteção em encostas íngremes. Berberis vulgaris é um', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Uva Ursina', E'', '', E'ARCTOSTAPHYLOS UVA-URSI (L.)ANTIBACTERIANA,INFECÇÕES URINÁRIAS,DOENÇAS INFLAMATÓRIAS DAS VIAS URINÁRIAS.CÁLCULOS URINÁRIOS E DIVERSAS AFECÇÕES RENAIS,Uva ursina', '', E'Arctostaphylos uva-ursi (L.) SPRENG. Ericaceae Aproximadamente 50 espécies de arbustos robustos, decíduos ou perenes e pequenas árvores compõe o gênero Arctostaphylos, distribuído principalmente na América do Norte ocidental e norte da Europa. Várias espécies são usadas ornamentalmente. O nome vem do grego "arkton staphyle", uvas de urso, pelo fato dos frutos serem um importante alimento para os ursos. Arcrostaphylos uva-ursi é um arbusto rasteiro de crescimento rápido, com ramos densamente cobe', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Valeriana', E'', '', E'VALERIANA OFFICINALIS L.ATENUAM A IRRITABILIDADE NERVOSA,PERTURBAÇÕES CARDÍACAS,CÃIBRAS.DEPRESSÃO NERVOSA,FADIGA, ESGOTAMENTO INTELECTUAL E INSÔNIA CRÔNICA. Valeriana', '', E'Valeriana officinalis L. Valerianaceae Planta herbácea vivaz, possuindo uma enorme raiz e um curto rizoma, que dá origem a um caule anguloso com folhas opostas e penatissectas. O caule termina num corimbo de pequenas flores brancas ou avermelhadas. O fruto é um aquênio com coroa. A espécie está difundida na Europa, Ásia e América. É uma planta medicinal muito antiga, como é recordado pelo seu nome científico, derivado do latim valere, ter saúde. A valeriana é cultivada nos campos. No segundo ano', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Vara Dourada', E'', '', E'SOLIDAGO VIRGAUREA L.INFECÇÕES URINÁRIAS, CATARRO CRÔNICO, GRIPE, TOSSE SANGUINOLENTA, LESÕES INTERNAS GRAVES COM COAGULAÇÃO DE SANGUE,DISPEPSIA E FLATULÊNCIA CURAR FERIDAS, FERIDAS PURULENTAS, INFLAMAÇÕES DA BOCA E DA GARGANTA, MORDIDAS DE INSETOS,ÚLCERAS, E GARGANTA DOLORIDVara dourada', '', E'Solidago virgaurea L. Amarantaceae Há aproximadamente 10 espécies de perenes do gênero Solidago que estão difundidas ao longo de todo o hemisfério do norte, mas principalmente na América do Norte, onde eles têm uma longa história nos medicamentos nativos; Solidago virgaurea é nativa das áreas secas da Europa. Virtualmente todas as espécies e várias variantes híbridas crescem em estado selvagem nas bordas de florestas e clareiras. Suas folhas inteiras, alongadas, orientadas no sentido do crescime', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Vassourinha Doce', E'', '', E'SCOPARIA DULCIS L.CATARRO DOS PULMÕES, FEBRES ,DORES DE OUVIDO.CERTOS TIPOS DE DIABETES.Vassourinha doce', '', E'Scoparia dulcis L. Scoparia procumbens Jacq. Scoparia ternata Forsk. Salicaceae Planta nativa na América Tropical, hoje com larga distribuição no mundo. No Brasil ocorre na maior parte do território, mas raramente aparece em grandes concentrações, sendo infestante em pastagens e culturas, especialmente perenes como a do café. É uma planta herbácea anual, reproduzida por semente, de base sublenhosa, ereta com até 80cm de altura, muito ramificada com ramos ascendentes, numa estrutura que permite s', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Veratro', E'', '', E'VERATRUM ALBUM L.VASODILATADOR,HIPOTENSOR,CRISES DE ASMA, TOSSE CONVULSIVA;Veratro', '', E'Heléboro-branco Veratrum album L. Liliaceae Planta bulbosa perene, dotada de um curto rizoma, raízes poderosas e caule robusto, apresentando folhas elípticas de disposição alterna. Estas são plissadas no sentido das nervuras. O caule termina em panícula composta de flores amarelo-esverdeadas. O fruto é uma cápsula. Toda a planta é extremamente venenosa. Encontra-se nos prados úmidos das regiões de baixa e média montanha da Europa central e meridional. Colhe-se o rizoma com uma parte das raízes.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Verbasco Densifloro', E'', '', E'VERBASCUM DENSIFLORUM BERTOL.EXPECTORANTE E LIGEIRAMENTE DIURÉTICO,ESPASMOLÍTICAS.CATAPLASMAS E BANHOS PARA ÚLCERAS E HEMORRÓIDAS.DORES DE DENTES.Verbasco densifloro', '', E'Verbascum densiflorum Bertol. Syn.: Verbascum thapsiforme Schrad. non Rafin. Scrophulariaceae Planta alta, bienal, formando, durante o primeiro ano, uma roseta basilar, durante o segundo um caule que atinge até 2m de altura, terminado por uma bela espiga de flores amarelas. As folhas são alongadas, penugentas, sésseis e alternas sobre o caule, onde o limbo é decorrente até ao nascimento da folha inferior. O fruto é uma cápsula que contém sementes diminutas. É uma espécie difundida em toda a Euro', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Vinagreira', E'', '', E'HIBISCUS SABDARIFFA L.ANTIESCORBÚTICA,ESTOMÁQUICA, DIURÉTICA E EMOLIENTE.RESOLUTIVAS.DIURÉTICAS E TÔNICAS.Vinagreira', '', E'Nome científico: Hibiscus sabdariffa L. Planta de origem africana, anual, caule e folhas avermelhados, flores róseas. Pertence à família Malvaceae. É rica em ácidos orgãnicos. A infusão das folhas e raízes é antiescorbútica, estomáquica, diurética e emoliente. As folhas em cataplasmas são resolutivas. As sementes são diuréticas e tônicas. Com os frutos, preparam-se geléias, pastas, picles, licores e vinhos. Multiplica-se por sementes e estacas.', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Vinca', E'', '', E'CATHARANTHUS ROSEUS G. DON.,MARIA-SEM-VERGONHA.LEUCEMIA.Vinca', '', E'Nome científico: Catharanthus roseus G. Don. Espécie herbácea, perene,da família Apocynaceae,originária do Madagáscar,atualmente considerada como cosmopolita tropical. Planta muito comum em jardins, também conhecida como maria-sem-vergonha. Apresenta princípios ativos (virablastina e vincristina) que, se extraídos e purificados, ajudam no tratamento de alguns tipos de leucemia. Porém possui outras substãncias que são tóxicas. Multiplica-se por sementes e estacas. ±', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Violeta', E'', '', E'VIOLA ODORATA L., AMOR-PERFEITO, VIOLA, VIOLAROXA, VIOLETA-DE-CHEIRO E VIOLETA-COMUM.AS RAÍZES SÃO LIGEIRAMENTE PURGATIVAS. AS FLORES SÃO BÉQUICAS E SUDORÍFERAS. SERVE PARA TOSSE, AFECÇÕES BRONQUIAIS, COQUEQUELUCHE, SARAMPO E INFLAMAÇÕES DE GARGANTA. CICATRIZANTE (USO EXTERNO).VIOLETA', '', E'Nome científico: Viola odorata L. Família: Violaceae.  Origem: Europa e Ásia ocidental.  Sinonímia: amor-perfeito, viola, violaroxa, violeta-de-cheiro e violeta-comum.  Descrição: planta herbácea, perene, acaule, rizoma espesso, flores violáceas escuras, raramente lilás ou brancas, muito perfumadas, fruto cápsula.  Constituintes químicos principais: violina, ácido tânico e salicílico.  Indicações: as raízes são ligeiramente purgativas. As flores são béquicas e sudoríferas. Serve para tosse, afec', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Vique', E'', '', E'MENTHA ARVENSIS D.C. VAR. PIPERACENS HOLMENS.DESCONGESTIONANTE NASAL,ESTOMACAL, CARMINATIVA E ANTIEMÉTICO.IRRITAÇÃO DA PELE E DORES DE CABEÇA.Vique', '', E'Nome científico: Mentha arvensis D.C. var. piperacens Holmens. Planta herbácea, perene, rizomatosa, da família Labiatae. Originária da Ásia e Europa. Folhas alternas, obovadas, com forte odor característico de mentol. É utilizada como descongestionante nasal, basta inalar uma porção de folhas amassadas na mão. É ainda estomacal, carminativa e antiemético. Tornar 2 a 3 xícaras (chá) ao dia, com 4 a 6 folhas frescas por xícara (chá). A tintura é preparada com 60 g de folhas frescas em 100 ml de ál', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Visco Branco', E'', '', E'VISCUM ALBUM L.AUMENTAR A FECUNDIDADE.ARTERIOSCLEROSE.CITOSTÁTICOS (ANTITUMORAIS)Visco branco', '', E'Viscum album L. Loranthaceae Arbusto semiparasita, com ramos e folhas sempre verdes, vivendo sobre os ramos de espécies folhosas ou resinosas. As folhas alongadas, coriáceas, são séssies e opostas na extremidade dos ramos. As flores são dióicas, pistiladas (em baixo à esquerda) e estaminadas (em baixo à direita), formando-se em posição axilar. Os frutos são bagas monospérmicas brancas. É uma espécie difundida num vasto território euroasiático, desde sempre considerada medicinal e sagrada. Do pon', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Zimbro', E'', '', E'JUNIPERUS COMMUNISATIVIDADE TERAPÊUTICA ESTRUTURANTE NA REGIÃO URO-GENITAL.MOLÉSTIAS RENAIS.AMENORRÉIA.Zimbro', '', E'Juniperus communis Cupressaceae Sob ponto de vista antroposófico O Juniperus é um arbusto que apresenta folhas em forma de agulhas, porte de um pinheirinho e, o que mais nos chama a atenção, é o seu porte bastante diminuto e suas estruturas muito parecidas com frutos. Em relação à localização do Juniperus communis no grupo dos Ciprestes notamos que ele ocupa uma posição bem indiferenciada no que se refere ao desenvolvimento das folhas, que sempre são em forma de agulhas. De maneira oposta a Thuj', '', 'SIHORE Fitoterapia');
INSERT INTO "PhytotherapyPlant" (id, name, "scientificName", "commonNames", indications, contraindications, dosage, "relatedRemedies", source) VALUES (gen_random_uuid()::text, E'Abrunheiro Bravo', E'', '', E'PRUNUS SPINOSA L.DIURÉTICA, LAXANTE,ADSTRINGENTE,AFECCÕES DA BEXIGA E DAS VIAS URINÁRIASPrunus spinosa L. Rosaceae', '', E'Arbusto que forma matagais impenetráveis devido a uma multiplicação intensa através de rebentos radiantes. Os ramos espinhosos apresentam diminutas folhas ovaladas e pecioladas, de implantação alterna. As flores são brancas, pentámeras, e desabrocham antes do aparecimento das primeiras folhas. Os frutos são drupas azul-escuras: os abrunhos. O abrunheiro-bravo cresce sobre vertentes secas e ensolaradas, em suportes pobres e pedregosos. É conhecido desde a Antiguidade como planta medicinal e alime', '', 'SIHORE Fitoterapia');
